	('847bde54-f369-40c3-a22b-a4d045850982', 'Paulo Mauia', 'Arts Finest Tattoo Shop, owned and led by Paulo Mauia, is a respected Samoan tattoo studio known for delivering finely detailed, culturally grounded tattoo work with skill, care, and integrity.

Specialising in Samoan and Polynesian tattoo designs, Paulo brings years of experience and a deep understanding of traditional patterns, symbolism, and placement. Each piece is carefully crafted to reflect identity, story, and cultural pride — whether through bold traditional work, custom designs, or finely executed modern pieces.

Arts Finest Tattoo Shop is more than a place to get tattooed; it is a space where art, heritage, and craftsmanship come together. With a strong reputation across Samoa and New Zealand — and expanding to Australia from January 2026 — the studio continues to serve clients who value authenticity, cultural respect, and high-quality tattooing.', 'Arts Finest', 'https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logos/paulo.jpg', NULL, 'paulomauia3@gmail.com', NULL, NULL, 'New Zealand', 'Arts & Culture', 'active', 'verified', NULL, NULL, '2025-12-17 05:28:29.873448+00', '2026-03-05 02:35:18.829614+00', '2025-12-17', 'Paulo Mauia', '{English}', '{"tiktok": "https://tiktok.com/@paulomauia", "facebook": "https://facebook.com/profile.php?id=100060918442844", "instagram": "https://instagram.com/paulomauia_tattoo"}', NULL, 'Auckland', NULL, NULL, '24hrs', 'https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banners/Paulo.png', 'Samoa', false, NULL, NULL, 'paulo-mauia', false, NULL, NULL, true, 'homepage'),
	('1ceaf4d4-8a5e-4f25-b75f-43a05cd656fb', 'SaaSy Cookies', 'SaaSy Cookies is a digital product studio and infrastructure partner for founders, creators, and growing businesses.

