	('385a01f6-0b40-4abf-a15e-d2bb3bd646eb', 'Pacific Stain', 'Pacific Stain is the creative expression of a Samoan family dedicated to honouring and preserving the stories of their ancestors. Through intricate 3D mixed media, pyrography, traditional motifs, and handcrafted wooden creations, they bring Polynesian culture to life — piece by piece.

Every artwork carries the mana of Polynesian heritage, blending ancestral knowledge with modern craftsmanship. From carved bowls and decorative panels to symbolic designs inspired by tatau and natural elements, Pacific Stain celebrates identity, memory, and the deep connection between people and their roots.

Driven by a passion to share Polynesian art with the world, Pacific Stain creates pieces that are not only visually striking but spiritually meaningful — art that speaks, remembers, and continues the legacy of Polynesia.', 'Carving the Spirit of Samoa', 'https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logos/pacificstain.jpg', NULL, 'pacificstain@aol.com', NULL, NULL, 'United States', 'Arts & Culture', 'active', 'verified', NULL, NULL, '2025-12-12 08:38:00.862376+00', '2026-03-05 02:35:18.829614+00', '2026-02-26', 'Patrick Etu Ah-wong', '{English}', '{"tiktok": "https://tiktok.com/@pacificstain", "facebook": "https://facebook.com/pacific.stain", "instagram": "https://instagram.com/pacificstain_official"}', NULL, 'Orlando', 'Florida', NULL, NULL, 'https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banners/Pacific%20Stain.png', 'Samoa', false, NULL, NULL, 'pacific-stain', false, NULL, NULL, true, 'homepage'),
	('1bebde9a-bd2f-4c22-a522-228fbef28880', 'Pacificana', 'Pacificana is a proudly Papua New Guinea–owned creative studio bringing the vibrant spirit of the Pacific to life through handcrafted floral art. Every piece is inspired by the colours of our islands, the strength of our women, and the traditions passed down through generations.

Each handmade bloom is carefully shaped, painted, and detailed with love — transforming iconic Pacific flowers into stunning wearable art for everyday joy, cultural events, weddings, and island celebrations.

Pacificana is more than an accessories brand — it is a celebration of identity. A way for our people to express who we are, wherever we are in the world. Bold, colourful, authentic, and proudly PNG.

From bright hibiscus and frangipani to custom colourways, every design reflects the warmth, resilience, and creativity of our Pacific community.

Wear your culture. Celebrate your roots. Bloom boldly with Pacificana.', 'PNG Beauty, Crafted by Hand', 'https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logos/pacificana.jpg', NULL, 'pacificmarketltd@gmail.com', '+675 7344 5243', NULL, 'Papua New Guinea', 'Arts & Culture', 'active', 'verified', NULL, NULL, '2025-12-13 02:00:27.00608+00', '2026-03-05 02:35:18.829614+00', '2026-02-26', 'Pacificana', '{"Tok Pisin",English}', '{"facebook": "https://facebook.com/pacificana.pg"}', NULL, 'Port Moresby', NULL, NULL, NULL, 'https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banners/Pacificana.jpg', 'Papua New Guinea', false, NULL, NULL, 'pacificana', false, NULL, NULL, true, 'homepage'),
	('3966d793-4307-49e0-891e-5fc34c3a0cd8', 'SILILO TATTOO', 'SILLO TATTOO is a Polynesian tattoo artist whose work is deeply influenced by traditional patterns, structure, and the cultural meaning carried within every line.

Each tattoo is approached with intention and respect, not simply as a design, but as a personal story expressed through Polynesian-inspired motifs, balance, and flow. From large-scale body pieces to detailed custom work, SILLO TATTOO focuses on clean execution, strong composition, and designs that honour both the wearer and the cultural origins of the art.

Based in Avignon, France, SILLO TATTOO works by appointment, creating custom tattoos for clients who value authenticity, symbolism, and craftsmanship. Every piece is thoughtfully designed to fit the body naturally, ensuring the tattoo remains timeless, powerful, and meaningful.

At SILLO TATTOO, tattooing is more than decoration, it is identity, respect, and storytelling through ink.', 'Polynesian Tattoo Artist', 'https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logos/sililo.jpg', 'https://linktr.ee/slo72?utm_source=linktree_profile_share&ltsid=adee8b0d-bd2b-427d-b742-28eac77a2b2f', 'slo72@hotmail.fr', '+33648733784', NULL, 'France', 'Arts & Culture', 'active', 'verified', NULL, NULL, '2025-12-23 08:13:31.132338+00', '2026-03-05 02:35:18.829614+00', '2026-02-26', 'Brice SILILO', '{French,English,Uvean}', '{"tiktok": "https://tiktok.com/@sililo.tattoo", "facebook": "https://facebook.com/profile.php?id=100077690003413", "linkedin": "https://linkedin.com/brice-sililo-6154b9192", "instagram": "https://instagram.com/sililo.tattoo"}', NULL, 'Avignon', 'Provence-Alpes-Côte d''Azur', NULL, NULL, 'https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banners/Sililo.png', 'Wallis and Futuna', false, NULL, NULL, 'sililo-tattoo', false, NULL, NULL, true, 'homepage');


