	('81a81d1d-d96f-4cc7-a360-9b23f9889e02', 'businesses', '46d354a9-f6db-43d9-9527-4e0aa8b9820e', 'INSERT', NULL, '{"id": "46d354a9-f6db-43d9-9527-4e0aa8b9820e", "city": "Utah", "name": "Da Utah Taro Leaf Man", "status": "active", "suburb": null, "address": null, "country": "United States", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Food & Agriculture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771882733799.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771882722355.png", "created_at": "2026-02-23T21:49:50.314899+00:00", "updated_at": "2026-02-23T21:49:50.314899+00:00", "description": "Da Utah Taro Leaf Man bridges Hawaiʻi and Utah by delivering fresh, island-grown taro leaves straight to families who crave the real thing.\r\n\r\nWe know that taro leaves aren''t just ingredients — they''re tradition, celebration, and identity. That''s why we source directly from Hawaiʻi farms and ship weekly to ensure freshness and quality you can trust.\r\n\r\nThis isn''t just produce.\r\nThis is culture in a bag.", "postal_code": null, "contact_name": "SENGA NUGA-TUIMASEVE", "created_date": "2026-02-26", "social_links": {}, "state_region": null, "contact_email": "send@mail.pacificmarket.co.nz", "contact_phone": "+1 801 318 4972", "cultural_tags": ["Samoan"], "business_hours": null, "contact_website": "https://alohainutah.org/", "languages_spoken": ["English", "Samoan"], "primary_cultural": "Samoan", "short_description": "From Our Farms to Your Arms", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-26 19:50:26.241842+00'),
	('b8ad0a92-4029-4496-9857-6dc6f6367fd3', 'businesses', '7060b4c5-6c0f-4e29-ba63-d03d9c838dcf', 'INSERT', NULL, '{"id": "7060b4c5-6c0f-4e29-ba63-d03d9c838dcf", "city": "Auckland", "name": "Jztamakaandkickz", "status": "active", "suburb": "Otahuhu", "address": "28 Hauiti Road", "country": "New Zealand", "user_id": null, "featured": true, "industry": "Professional Services", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771896528085.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771896534314.png", "created_at": "2026-01-10T22:23:57.816715+00:00", "updated_at": "2026-02-24T01:29:00.986358+00:00", "description": "We are a small shoe cleaning business. For over 4 years, we have cleaned and conditioned shoes from sneakers to boots to your everyday beaters.\r\nWe have done shoes for Charlie Pomee from 3hd & also ex all black Karl Tuinukuafe. Just to name afew. We''re happy to clean any of shoe and save the from the landfill. Give us a try today. You won''t be disappointed. JT&K", "postal_code": "1062", "contact_name": "Jaydes Katu", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@jayztamaka", "youtube": "https://youtube.com/@JTANDKICKZ", "facebook": "https://facebook.com/jayz.tamaka", "instagram": "https://instagram.com/jztamakaandkickz"}, "state_region": "Auckland", "contact_email": "jztamakaandkickz@hotmail.com", "contact_phone": "0272774465", "cultural_tags": ["Cook Islands Māori"], "business_hours": "Monday to Friday\r\nWeekend Closed (Unless Arranged)", "contact_website": null, "languages_spoken": ["English"], "primary_cultural": "Cook Islands Māori", "short_description": "Want your shoes cleaned? Say Less!", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-26 19:50:26.241842+00'),
	('a8ed991c-2506-4d01-93e5-8e39065cef83', 'businesses', '3966d793-4307-49e0-891e-5fc34c3a0cd8', 'INSERT', NULL, '{"id": "3966d793-4307-49e0-891e-5fc34c3a0cd8", "city": "Avignon", "name": "SILILO TATTOO", "status": "active", "suburb": null, "address": null, "country": "France", "user_id": null, "featured": true, "industry": "Arts & Crafts", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771899176037.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771899167657.png", "created_at": "2025-12-23T08:13:31.132338+00:00", "updated_at": "2026-02-24T02:13:01.769916+00:00", "description": "SILLO TATTOO is a Polynesian tattoo artist whose work is deeply influenced by traditional patterns, structure, and the cultural meaning carried within every line.\r\n\r\nEach tattoo is approached with intention and respect, not simply as a design, but as a personal story expressed through Polynesian-inspired motifs, balance, and flow. From large-scale body pieces to detailed custom work, SILLO TATTOO focuses on clean execution, strong composition, and designs that honour both the wearer and the cultural origins of the art.\r\n\r\nBased in Avignon, France, SILLO TATTOO works by appointment, creating custom tattoos for clients who value authenticity, symbolism, and craftsmanship. Every piece is thoughtfully designed to fit the body naturally, ensuring the tattoo remains timeless, powerful, and meaningful.\r\n\r\nAt SILLO TATTOO, tattooing is more than decoration, it is identity, respect, and storytelling through ink.", "postal_code": null, "contact_name": "Brice SILILO", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@sililo.tattoo", "facebook": "https://facebook.com/profile.php?id=100077690003413", "linkedin": "https://linkedin.com/brice-sililo-6154b9192", "instagram": "https://instagram.com/sililo.tattoo"}, "state_region": "Provence-Alpes-Côte d''Azur", "contact_email": "slo72@hotmail.fr", "contact_phone": "+33648733784", "cultural_tags": ["ʻUvea"], "business_hours": null, "contact_website": "https://linktr.ee/slo72?utm_source=linktree_profile_share&ltsid=adee8b0d-bd2b-427d-b742-28eac77a2b2f", "languages_spoken": ["French", "English", "Uvean"], "primary_cultural": "Wallis and Futuna", "short_description": "Polynesian Tattoo Artist", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-26 19:50:26.241842+00'),
	('4e780dfc-1479-4500-a30b-9e3af2cb0a8e', 'businesses', '9ab9b40a-101a-4afe-a9f2-c17f9b616e87', 'INSERT', NULL, '{"id": "9ab9b40a-101a-4afe-a9f2-c17f9b616e87", "city": "Tahiti", "name": "VAHINE CHIC", "status": "active", "suburb": "Papeete", "address": "Marche de Papeete, pres de l''escalator (Papeete Market - near the escalator)", "country": "French Polynesia", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Arts & Crafts", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771900200203.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771900190798.jpg", "created_at": "2025-12-11T22:41:59.920616+00:00", "updated_at": "2026-02-24T02:30:08.542287+00:00", "description": "Vahine Chic is a celebration of Polynesian artistry — handmade creations crafted with patience, passion, and the timeless beauty of our islands.\r\n\r\nFrom their home in Tahiti, each piece is made with love, blending vibrant colours, natural textures, and traditional inspiration to honour the spirit of Fenua. Their work reflects more than craftsmanship; it carries stories of family, culture, and connection.\r\n\r\nWhether it''s a lovingly woven accessory or a delicately detailed piece of décor, every item invites you to discover the treasures of Fenua and the warmth of the people who create them.\r\n\r\nAt Vahine Chic, artistry is not just a skill — it is a way of sharing joy. A way of keeping culture alive. A way of bringing a little piece of paradise into everyday life.", "postal_code": null, "contact_name": "Timeri Pollock", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/Artisantchic"}, "state_region": "Tahiti", "contact_email": "pacificmarketltd@gmail.com", "contact_phone": "89 54 32 68", "cultural_tags": ["Tahitian"], "business_hours": "10am - 2pm \r\n10h00 - 14h00", "contact_website": null, "languages_s