	('900ae889-286f-4fee-ad28-57f8c9375174', 'businesses', '74845da6-e0b1-421c-8181-7e6753c152f9', 'INSERT', NULL, '{"id": "74845da6-e0b1-421c-8181-7e6753c152f9", "city": "Auckland", "name": "Zeena Khan Coaching", "status": "active", "suburb": null, "address": null, "country": "New Zealand", "user_id": null, "featured": true, "industry": "Professional Services", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771900754213.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771900760675.png", "created_at": "2026-01-17T23:14:01.458139+00:00", "updated_at": "2026-02-24T02:39:28.186094+00:00", "description": "Zeena Khan Coaching stands at the intersection of modern leadership and cultural wisdom, offering a nuanced approach to professional development.\r\n\r\nWith a focus on empowering leaders to build agile and confident teams, Zeena''s coaching practice is particularly attuned to the complexities of the AI era. Her methodology is grounded in a strengths-based framework that encourages individuals to harness their unique capabilities while remaining culturally aware.\r\n\r\nZeena Khan brings a wealth of experience to her coaching engagements, drawing from her own heritage and understanding of diverse cultural perspectives. This blend of insight ensures that her clients are not only prepared to meet the challenges of today''s fast-paced business environment but are also equipped to lead with empathy and respect for the diverse backgrounds within their teams.\r\n\r\nAt the core of Zeena''s practice is the belief that true leadership is about fostering an environment where all team members can thrive. By emphasizing cultural awareness and personal strengths, she helps leaders create workplaces that are both innovative and inclusive. Zeena Khan Coaching is dedicated to nurturing leadership that is as dynamic as the world around us, with a commitment to guiding professionals towards their highest potential.", "postal_code": null, "contact_name": "Zeena Khan", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@ZeenaKhanCoaching", "youtube": "https://youtube.com/@Adaptability Advantage", "instagram": "https://instagram.com/ZeenaKhanCoaching"}, "state_region": "North Island", "contact_email": "hello@zeenakhan.com", "contact_phone": "021364881", "cultural_tags": ["Chinese", "Indian"], "business_hours": null, "contact_website": "https://www.zeenakhan.com", "languages_spoken": ["Hindi"], "primary_cultural": "Fijian", "short_description": "Empowering leaders to foster agile, confident teams in the AI era.", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-26 19:50:26.241842+00'),
	('1dea14dc-0399-4bc7-b381-26ff368cd377', 'businesses', '1bebde9a-bd2f-4c22-a522-228fbef28880', 'INSERT', NULL, '{"id": "1bebde9a-bd2f-4c22-a522-228fbef28880", "city": "Port Moresby", "name": "Pacificana", "status": "active", "suburb": null, "address": null, "country": "Papua New Guinea", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Arts & Crafts", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771897636310.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771897517709.jpg", "created_at": "2025-12-13T02:00:27.00608+00:00", "updated_at": "2026-02-24T01:47:21.730477+00:00", "description": "Pacificana is a proudly Papua New Guinea–owned creative studio bringing the vibrant spirit of the Pacific to life through handcrafted floral art. Every piece is inspired by the colours of our islands, the strength of our women, and the traditions passed down through generations.\r\n\r\nEach handmade bloom is carefully shaped, painted, and detailed with love — transforming iconic Pacific flowers into stunning wearable art for everyday joy, cultural events, weddings, and island celebrations.\r\n\r\nPacificana is more than an accessories brand — it is a celebration of identity. A way for our people to express who we are, wherever we are in the world. Bold, colourful, authentic, and proudly PNG.\r\n\r\nFrom bright hibiscus and frangipani to custom colourways, every design reflects the warmth, resilience, and creativity of our Pacific community.\r\n\r\nWear your culture. Celebrate your roots. Bloom boldly with Pacificana.", "postal_code": null, "contact_name": "Pacificana", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/pacificana.pg"}, "state_region": null, "contact_email": "pacificmarketltd@gmail.com", "contact_phone": "+675 7344 5243", "cultural_tags": ["Papua New Guinean"], "business_h