	('0ce74a94-6e15-43df-a87f-08ff76bae554', 'businesses', 'ce4a274e-c94d-475f-988e-23741f9e58c5', 'INSERT', NULL, '{"id": "ce4a274e-c94d-475f-988e-23741f9e58c5", "city": "Auckland", "name": "Rebalance Qi Acupuncture", "status": "active", "suburb": "Papatoetoe", "address": "34 Great South Road", "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Health & Wellness", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771898477407.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771898465847.png", "created_at": "2025-12-01T02:43:36.084993+00:00", "updated_at": "2026-02-24T02:01:28.354966+00:00", "description": "Rebalance Qi Acupuncture is a calming and supportive clinic\r\nbased in Papatoetoe, South Auckland. Our mission is to help\r\nindividuals restore balance and feel their best through the natural\r\nhealing principles of traditional Chinese medicine. We believe\r\nwellness is not one-size-fits-all that''s why each treatment is\r\nthoughtfully tailored to suit your individual needs. We offer\r\npersonalized acupuncture sessions, cupping therapy, and holistic\r\ncare in a space designed to help you feel grounded, relaxed, and\r\nheard. As an ACC-registered provider, we also make acupuncture\r\nmore accessible for those recovering from injuries. At Rebalance\r\nQi, your health and well-being are our top priority. We''re here to\r\nsupport you on your journey toward lasting relief and renewed\r\nenergy.", "postal_code": "2025", "contact_name": "Sandy Suriyachaik", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/rebalanceqi.acupuncture", "instagram": "https://instagram.com/rebalanceqi.acupuncture"}, "state_region": "Auckland", "contact_email": "info@rebalanceqi.co.nz", "contact_phone": "022 388 5718", "cultural_tags": ["New Zealand"], "business_hours": "Monday - 9:30am-6:30pm\r\nTuesday - Closed\r\nWednesday\t9:30am-6:30pm\r\nThursday - Closed\r\nFriday - 9:30am-2pm\r\nSaturday - 8am-12pm\r\nSunday - Closed", "contact_website": "https://www.rebalanceqi.co.nz", "languages_spoken": ["English"], "primary_cultural": "New Zealand", "short_description": "Restore, Renew, Rebalance.", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-26 19:50:26.241842+00'),
	('a685b403-a615-480e-858a-d7d43a94299e', 'businesses', 'e0e03cd4-3a8b-48f9-8ffa-546abfa7925c', 'INSERT', NULL, '{"id": "e0e03cd4-3a8b-48f9-8ffa-546abfa7925c", "city": "Auckland", "name": "SenseAI", "status": "active", "suburb": null, "address": null, "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Technology", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771898910016.png", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771898919526.png", "created_at": "2026-02-07T18:26:40.653265+00:00", "updated_at": "2026-02-24T02:09:31.924997+00:00", "description": "SenseAI is a supportive space for your thoughts, feelings, and ideas — without judgment, pressure, or noise.\r\n\r\nLife can be complex, and sometimes you just need help making sense of what''s in your head. SenseAI blends journaling with compassionate AI guidance to help you reflect, gain perspective, and move forward with confidence.\r\n\r\nIt''s like having a thoughtful companion who listens, understands, and helps you see things more clearly.", "postal_code": null, "contact_name": "Jasmin Benioni", "created_date": "2026-02-26", "social_links": {}, "state_region": "Auckland", "contact_email": "senseai@mail.pacificmarket.co.nz", "contact_phone": null, "cultural_tags": ["Cook Islands Māori"], "business_hours": null, "contact_website": "https://www.senseai.co.nz", "languages_spoken": ["English"], "primary_cultural": "Cook Islands Māori", "short_description": "AI-Powered Journaling App - Type It, Speak It, Scan It", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-26 19:50:26.241842+00'),
	('30136370-5a38-476b-9905-938cfcba4f43', 'businesses', 'c9fc68e6-da63-4def-9d0b-13991ddc3926', 'INSERT', NULL, '{"id": "c9fc68e6-da63-4def-9d0b-13991ddc3926", "city": "Auckland", "name": "Te Mauri o te Makawe", "status": "active", "suburb": null, "address": null, "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Health & Wellness", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771899866021.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771899858016.jpg", "created_at": "2025-12-01T08:40:49.119488+00:00", "updated_at": "2026-02-24T02:24:31.20184+00:00", "description": "Nuku te manaaki, nuku te manaaki, ka ora ai te iwi.\r\nWith your support and my support, our community will thrive.\r\n\r\nMy name is Iesha Te-Iho. I am a qualified barber, creative, and proud Waiuku local. My journey here was not a straight line — but every challenge sharpened my purpose and showed me that barbering could be more than a trade. It could be a doorway to healing.\r\n\r\nFrom that understanding, Te Mauri o te Makawe: The Koha Manawa was born.\r\n\r\nThis kaupapa delivers professional grooming and braiding through a mobile service, reaching people and places often overlooked — hospices, spinal units, rehabilitation centres, and rural communities where transport and access are barriers. But this work is about far more than hair.\r\n\r\nThrough whakahoki te tapu, hair is treated with care and respectfully returned to Papatūānuku using traditional tikanga — uku (clay), harakeke (flax), and korowai — protecting the mana of our whānau. Alongside this, kōrero is shared and recorded, preserving the voices, stories, and heartbeat of the community.\r\n\r\nThis kaupapa began with one chair and one set of tools, but the vision is a Waka Wānanga — a collective of skilled creatives travelling across Aotearoa and beyond, delivering workshops, teaching tikanga, uplifting hauora, and restoring identity through creativity.\r\n\r\nAt its heart, this is about legacy. About building something that lasts — not just 100 years, but for generations — by caring for people, culture, and community, together.", "postal_code": null, "contact_name": "Iesha Rawinia", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/TeKohaManawa", "instagram": "https://instagram.com/tekohamanawa"}, "state_region": "Auckland", "contact_email": "hairwithesha@gmail.com", "contact_phone": "02102965229", "cultural_tags": ["Māori"], "business_hours": null, "contact_website": "https://msha.ke/beauty_withinyou", "languages_spoken": ["English"], "primary_cultural": "Cook Islands Māori", "short_description": "Any Style. Any Hair. Any Where.", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-26 19:51:35.680668+00'),
	('dfd7c301-f6da-46de-81fc-b032ec58f35e', 'businesses', 'cfaafb58-8f0a-4633-87b0-2a53e8425a6c', 'INSERT', NULL, '{"id": "cfaafb58-8f0a-4633-87b0-2a53e8425a6c", "city": "Auckland", "name": "David Laumatia Art", "status": "active", "suburb": null, "address": null, "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Arts & Crafts", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771895125650.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771895114953.jpg", "created_at": "2025-12-11T21:08:12.207784+00:00", "updated_at": "2026-02-24T01:06:16.106785+00:00", "description": "Where Pacific art is brought to life through innovative 3D mixed media.\r\n\r\nDavid''s creations honour Samoan culture, evoking cherished memories and a deep sense of pride. With each piece, he captures a powerful connection to his homeland — expressing both identity and a heartfelt longing to return to his roots.\r\n\r\nToday, David''s work is shared and celebrated across the world.", "postal_code": null, "contact_name": "David Laumatia", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/davidlaumatiaart", "instagram": "https://instagram.com/davidlaumatiapacificart"}, "state_region": "Auckland", "contact_email": "david.laumatia@gmail.com", "contact_phone": "0272358448", "cultural_tags": ["China"], "business_hours": null, "contact_website": null, "languages_spoken": ["English"], "primary_cultural": "Samoa", "short_description": "Art that carries the soul of Samoa", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-26 19:51:35.680668+00'),
