	('215d495d-1e33-4b2c-a27f-a4c3455d63fe', 'businesses', '464afb2e-e877-458d-a6cb-d0b0e6dd049d', 'INSERT', NULL, '{"id": "464afb2e-e877-458d-a6cb-d0b0e6dd049d", "city": "Christchurch", "name": "The Artwork of Dave Sotogi", "status": "active", "suburb": null, "address": null, "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Arts & Crafts", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771900051547.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771900040353.jpg", "created_at": "2025-12-12T18:55:24.793631+00:00", "updated_at": "2026-02-24T02:27:38.477302+00:00", "description": "Dave Sotogi is a New Zealand artist whose work brings the heart of the Pacific to life through rich symbolism, cultural depth, and emotive portraiture. His paintings blend modern artistry with ancestral influence, honouring the beauty, strength, and stories of Pacific people.\r\n\r\nFrom striking portraits to symbolic, nature-inspired works, each piece reflects Dave''s deep connection to heritage, identity, and the lands and waters that shape us. His art captures moments of reflection, power, and serenity — inviting viewers to feel, remember, and connect.\r\n\r\nToday, Dave''s work is celebrated in homes across Aotearoa and around the world, available as premium canvas prints and carefully crafted wall art. Every creation carries a story, a spirit, and a sense of belonging — an invitation to experience Pacific art through a contemporary lens.", "postal_code": null, "contact_name": "Dave Sotogi", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/desotogi", "instagram": "https://instagram.com/desotogi"}, "state_region": "South Island", "contact_email": "info@desotogi.co.nz", "contact_phone": null, "cultural_tags": ["Māori"], "business_hours": null, "contact_website": "https://desotogi.co.nz", "languages_spoken": ["English"], "primary_cultural": null, "short_description": "Contemporary Maori Art in Motion", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-26 19:51:35.680668+00'),
	('2f2524af-29e4-43b3-8df1-d381d47ca9d5', 'businesses', '669c26b2-ceec-498e-9e38-17329d6b05ec', 'INSERT', NULL, '{"id": "669c26b2-ceec-498e-9e38-17329d6b05ec", "city": "Auckland", "name": "Oceanique Solutions", "status": "active", "suburb": null, "address": null, "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Travel & Tourism", "logo_url": null, "verified": true, "banner_url": null, "created_at": "2025-11-24T09:10:17.344881+00:00", "updated_at": "2026-02-24T01:41:49.317039+00:00", "description": "Oceanique DMC & Consulting:\r\nYour Premier Destination Management (DMC) and tailored business consultancy. We offer unmatched expertise, seamless event planning and execution. With a deep insight into local culture and attention to detail, we guarantee a spectacular experience. Let us handle the details so you can immerse yourself in the adventure.\r\n\r\nChoose Oceanique Solutions for an experience as smooth as the sound of waves lapping the shore, the touch of gentle breeze, the sight of vibrant sunset, the scent of fresh rain, and the taste of a perfectly crafted meal.\r\n\r\nOceanique Travel:\r\nAs seasoned travel professionals, Oceanique - is your one stop travel shop. From island retreats to cultural experiences, we ensure your travels are unforgettable, allowing you to relish every sun-kissed moment.\r\n\r\nOceanique Education:\r\nOur education services forge strong partnerships with top educational institutions, immigration agent, and schools in New Zealand. We are a partnered Tahitian International Education Agency and engage as a Learning & Development Contractor. Our mission is to offer enriching educational experiences that connect cultures and unlock global opportunities.\r\n\r\nJoin us, and let''s embark on a new learning adventure together.", "postal_code": null, "contact_name": "Daniel Maine", "created_date": "2026-02-26", "social_links": {}, "state_region": "Auckland", "contact_email": "travel@danielmaine.com", "contact_phone": null, "cultural_tags": ["Cook Island"], "business_hours": null, "contact_website": null, "languages_spoken": ["English", "French", "Tahitian"], "primary_cultural": "Tahitian", "short_description": "Destination Management, Travel Consulting & Professional Services", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-26 19:51:35.680668+00'),
	('792f5358-b669-46e2-8e0e-b2889b7dda64', 'businesses', 'fcb997d1-fb71-4406-b902-cc5ef3208b03', 'INSERT', NULL, '{"id": "fcb997d1-fb71-4406-b902-cc5ef3208b03", "city": "Bundaberg", "name": "Papua New Guinea Bilums and Baskets", "status": "active", "suburb": null, "address": null, "country": "Australia", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Culture & Heritage", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771898183242.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771898190669.png", "created_at": "2025-12-17T06:11:26.868237+00:00", "updated_at": "2026-02-24T01:56:37.014101+00:00", "description": "Papua New Guinea Bilums & Baskets, run by CJ & LJ Mountford and based in Bundaberg, Queensland, is a small family business dedicated to sharing authentic Papua New Guinea arts and crafts with the wider community.\r\n\r\nSpecialising in traditional bilums and handwoven baskets, each piece is created using techniques passed down through generations. Bilums are traditionally crafted by women, woven in a variety of shapes and sizes to serve different purposes — from everyday use to baby carrying. The baskets are traditionally crafted by men, reflecting distinct cultural roles and knowledge systems.\r\n\r\nOnly three provinces in Papua New Guinea continue this specific weaving tradition:\r\n\r\nNorth Solomon (Buka)\r\nSouthern Highlands\r\nEastern Highlands\r\n\r\nThese handcrafted pieces are both functional and meaningful, suitable for home décor, shopping, picnics, and baby carrying — while carrying the stories, skills, and heritage of the communities who make them.\r\n\r\nBy supporting Papua New Guinea Bilums & Baskets, you are helping preserve traditional knowledge and create income opportunities for PNG artisans.", "postal_code": null, "contact_name": "Linah Mountford", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/PapuaNewGuineaBilumsAndBasketsCjLjMountford", "instagram": "https://instagram.com/pngbilumsnbaskets"}, "state_region": "Queensland", "contact_email": "Cmford@southernphone.com.au", "contact_phone": "0423 819 378", "cultural_tags": ["Papua New Guinean"], "business_hours": "10am to 2pm", "contact_website": null, "languages_spoken": ["Pidgin"], "primary_cultural": "Papua New Guinean", "short_description": "CJ & LJ Mountford", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-26 19:51:35.680668+00'),
