	('cdb255d5-2f1f-403d-8497-63c817d5ff04', 'businesses', '70ea5ff4-fe63-4d3e-b526-cfa3ec0dc95a', 'INSERT', NULL, '{"id": "70ea5ff4-fe63-4d3e-b526-cfa3ec0dc95a", "city": "Draper", "name": "Warrior Lines Tattoo", "status": "active", "suburb": null, "address": "12233 900 E", "country": "United States", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Culture & Heritage", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771900321960.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771900497365.png", "created_at": "2025-12-17T04:52:57.713415+00:00", "updated_at": "2026-02-24T02:35:04.618912+00:00", "description": "Warrior Lines Tattoo is a veteran-owned tattoo studio built on discipline, respect, and the belief that great art comes from a strong, healthy environment.\r\n\r\nWe specialise in bold black and grey work, custom designs, and Polynesian-inspired tattoos that carry meaning, structure, and story.\r\n\r\nThis is a no-nonsense shop for artists and clients who value integrity, craftsmanship, and authenticity. We reject ego, drama, and gatekeeping, and instead foster a space where artists are encouraged to grow, sharpen their skills, and take pride in their work — without judgment or pressure.\r\n\r\nAt Warrior Lines Tattoo, tattooing is more than ink. It''s commitment. It''s brotherhood. It''s honouring the past while building something stronger for the future — one line at a time.", "postal_code": null, "contact_name": "Hans Bennion", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@tribal_touch", "instagram": "https://instagram.com/tribaltouchdesigns"}, "state_region": null, "contact_email": "hans@warriorlines.com", "contact_phone": "4843797885", "cultural_tags": ["Tonga", "Fiji"], "business_hours": "By Appointment Only", "contact_website": "https://www.warriorlines.com", "languages_spoken": ["Fijian", "Tongan", "Samoan"], "primary_cultural": "Samoa", "short_description": "Polynesian-inspired Art and Tattoo Studio", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-26 19:51:35.680668+00'),
	('3be00000-2875-4aac-a12a-a4bf29d65fcd', 'businesses', '6bd8fad1-df64-4c3c-8cd8-7cb63be2926a', 'INSERT', NULL, '{"id": "6bd8fad1-df64-4c3c-8cd8-7cb63be2926a", "city": "Auckland", "name": "Anarra Alofa Est.2020", "status": "active", "suburb": null, "address": null, "country": "New Zealand", "user_id": null, "featured": true, "industry": "Arts & Crafts", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771893925293.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771893916527.jpg", "created_at": "2026-01-06T22:28:48.12743+00:00", "updated_at": "2026-02-24T00:51:09.197655+00:00", "description": "Talofa lava, my name is Sharon, co-founder and owner of Anarra Alofa.\r\nMy creative journey began in 2020, when I first set my heart on making handcrafted board signs. Shortly after, I welcomed my first child — my son — and, like many mothers, I placed that dream on hold. Even so, the desire to create never left me.\r\n\r\nOver time, my inspiration naturally returned through Sei — the floral ear pieces deeply loved and worn by Samoan women. In our culture, Sei are more than adornment; they are expressions of beauty, identity, and pride. The idea of creating them stayed with me, quietly growing until the time felt right.\r\n\r\nAt the beginning of last year, I finally took the step to bring Anarra Alofa to life. Starting small and working with minimal materials, I began handcrafting Sei with love, care, and intention. What started as a simple creative outlet has grown into a heartfelt small business rooted in culture, creativity, and passion.\r\n\r\nAnarra Alofa is a reflection of my journey — as a mother, a Samoan woman, and a creator — and a celebration of the beauty we carry and share through our culture.", "postal_code": null, "contact_name": "Sharon Naseri", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@anarraalofa2020", "facebook": "https://facebook.com/silaumea.ieru", "instagram": "https://instagram.com/anarraalofa2125"}, "state_region": null, "contact_email": "sharonnaseri@gmail.com", "contact_phone": "+64212170344", "cultural_tags": ["Samoan"], "business_hours": "Monday-Friday 9am-5pm", "contact_website": null, "languages_spoken": ["English"], "primary_cultural": "Samoan", "short_description": "Elevate your style with beautifully crafted Sei''s for every occasion at Anarra Alofa.", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-26 19:51:35.680668+00'),
	('d9a01b27-8113-4b5c-b1fc-77691ee1d524', 'businesses', '525e84f2-66d3-4a1b-a896-dd64d01ec033', 'INSERT', NULL, '{"id": "525e84f2-66d3-4a1b-a896-dd64d01ec033", "city": "New Zealand", "name": "Tuhono Design", "status": "active", "suburb": null, "address": null, "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Home & Decor", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771899400009.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771899392291.jpg", "created_at": "2025-12-12T18:28:30.64805+00:00", "updated_at": "2026-02-24T02:16:44.547671+00:00", "description": "Tuhono Design was created by Jay and Sarah, a proud Maori whanau dedicated to revitalising te reo Maori in everyday spaces. Inspired by their own journeys of reconnecting with their heritage, they design bilingual planners, calendars, prints, and educational resources that make Maori language and culture accessible, beautiful, and part of daily life. Their kaupapa is built on whanaungatanga, kotahitanga, and uplifting the next generation so they can grow up confident in their identity. Through thoughtfully crafted products rooted in meaning and connection, Tuhono Design invites whanau everywhere to learn, speak, and live te reo Maori with pride.", "postal_code": null, "contact_name": "Sarah", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@tuhonodesign", "facebook": "https://facebook.com/Tuhonodesign"}, "state_region": "New Zealand", "contact_email": "kiaora@tuhonodesign.com", "contact_phone": null, "cultural_tags": ["Māori"], "business_hours": null, "contact_website": "https://tuhonodesign.com", "languages_spoken": ["Te Reo Māori"], "primary_cultural": "Māori (New Zealand)", "short_description": "Bilingual Maori Resources to Inspire, Learn & Connect", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-26 19:51:51.574468+00'),
