	('1cd3f567-40c1-4ce0-8f1e-3562d238b8cf', 'businesses', '7e83ede6-32fa-4019-b2b5-96f71948a0ae', 'INSERT', NULL, '{"id": "7e83ede6-32fa-4019-b2b5-96f71948a0ae", "city": "Australia", "name": "Island Pepe", "status": "active", "suburb": null, "address": null, "country": "Australia", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Arts & Crafts", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771895626761.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771895620639.jpg", "created_at": "2025-12-15T04:06:38.295736+00:00", "updated_at": "2026-02-24T01:13:53.826878+00:00", "description": "Island Pepe is a family-founded Pasifika brand created with one heartfelt purpose: to preserve and share Pacific language and culture with the next generation.\r\n\r\nRooted in a rich heritage spanning multiple regions of the South Pacific, Island Pepe designs meaningful everyday essentials for babies and children — from clothing and blankets to books and gift sets. Each piece is thoughtfully created to reflect the languages, stories, and traditions passed down by our ancestors, helping parents build lasting cultural connections at home.\r\n\r\nMore than a brand, Island Pepe is a celebration of identity, belonging, and pride. Through respectful collaboration with native speakers and cultural contributors across the Pacific, every design honours authenticity, storytelling, and community.\r\n\r\nIsland Pepe welcomes everyone — Pasifika and non-Pasifika alike — to share in this journey of preserving culture, nurturing identity, and creating memories that children will carry with them for life.", "postal_code": null, "contact_name": "Jen Masoe", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@island_pepe", "facebook": "https://facebook.com/islandpepe", "instagram": "https://instagram.com/island_pepe"}, "state_region": "Australia", "contact_email": "team.islandpepe@gmail.com", "contact_phone": null, "cultural_tags": ["Tonga"], "business_hours": null, "contact_website": "https://www.islandpepe.com", "languages_spoken": ["English"], "primary_cultural": "Samoa", "short_description": "Passing Culture to the Next Generation", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-26 19:51:51.574468+00'),
	('a4b0bb53-aedb-4225-8197-b381b6e1a839', 'businesses', 'c4530355-c5fb-47fb-ac89-07574831f9e7', 'INSERT', NULL, '{"id": "c4530355-c5fb-47fb-ac89-07574831f9e7", "city": "Naples", "name": "Avalon Wellness and Performance", "status": "active", "suburb": "Naples", "address": "10661 Airport Pulling Road N #10, Naples FL 34109", "country": "United States", "user_id": null, "featured": true, "industry": "Health & Wellness", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771894449390.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771894442071.png", "created_at": "2026-01-08T00:54:56.222151+00:00", "updated_at": "2026-02-24T00:54:14.139139+00:00", "description": "Avalon Wellness & Performance is a holistic health clinic dedicated to helping people move better, feel stronger, and live with greater ease and confidence. Through personalised, hands-on care, Avalon supports recovery, long-term wellness, and peak physical performance.\r\n\r\nThe clinic takes an integrative approach to treatment, combining techniques such as Active Release Technique (ART), Osteopathic Manual Therapy, Cranial Sacral Therapy, and therapeutic massage. Each session is tailored to the individual, addressing not only symptoms but the underlying causes of pain, tension, and movement restrictions.\r\n\r\nAt Avalon, the body is viewed as a connected system. Treatment plans are developed through careful assessment and collaboration, ensuring care aligns with each client''s goals — whether that''s injury recovery, pain management, improved mobility, or enhanced athletic performance.\r\n\r\nAvalon Wellness & Performance provides a calm, professional environment where expertise and compassion come together. From deep tissue and mobility-focused work to gentle therapies that support nervous system balance and stress relief, every session is delivered with intention and care.\r\n\r\nMore than treatment, Avalon empowers clients with the tools, support, and knowledge needed to maintain their wellbeing long after their session ends — helping them move forward feeling stronger, balanced, and supported.", "postal_code": "34109", "contact_name": "Avalon Wellness Performance", "created_date": "2026-02-26", "social_links": {"twitter": "https://twitter.com/WellnessAvalon", "facebook": "https://facebook.com/avalonwellnessandperformance", "instagram": "https://instagram.com/avalonwellnessandperformance"}, "state_region": "FL", "contact_email": "avalonwellnessperformance@gmail.com", "contact_phone": "+632394274697", "cultural_tags": ["American"], "business_hours": null, "contact_website": "https://www.avalonwellnessandperformance.com/", "languages_spoken": ["English"], "primary_cultural": "American", "short_description": "Move Better. Feel Better. Live Better.", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-26 19:51:51.574468+00'),
	('9d6a62a4-e095-40ee-9421-8c37ca095d56', 'businesses', '20b54ac1-50ae-4475-89ef-b50569505408', 'INSERT', NULL, '{"id": "20b54ac1-50ae-4475-89ef-b50569505408", "city": "New Zealand", "name": "M.Steven", "status": "active", "suburb": null, "address": null, "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Arts & Crafts", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771896978917.jpeg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771896973343.png", "created_at": "2025-12-14T08:18:01.195186+00:00", "updated_at": "2026-02-24T01:36:25.866805+00:00", "description": "This artist brings worlds to life through intricate, hand-drawn line work, creating pieces that feel both deeply personal and endlessly expansive. Every artwork is built stroke by stroke — layering symbols, creatures, and flowing forms that invite the viewer to slow down and discover something new each time they look.\r\n\r\nInspired by storytelling, movement, and the complexity of lived experience, their work blends fine detail with raw expression. Using acrylic paint and acrylic pen alongside traditional drawing tools, each piece carries its own rhythm — reflecting patience, discipline, and a deep respect for the creative process.\r\n\r\nBeyond visual art, this same care and creativity extend into handcrafted desserts and custom celebration cakes, including wedding and birthday designs. Whether expressed on paper, canvas, or through edible art, the artist approaches every creation with the same intention: balance, beauty, and meaning.\r\n\r\nThese works are never rushed — they are thoughtfully crafted, allowing ideas to unfold naturally. The result is a body of work that feels alive and grounded, celebrating creativity as a form of meditation, expression, and connection across many mediums.", "postal_code": null, "contact_name": "Mario Steven", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@m.stevenfjrot23"}, "state_region": "New Zealand", "contact_email": "mariosteven75@yahoo.co.nz", "contact_phone": null, "cultural_tags": ["Italy"], "business_hours": null, "contact_website": null, "languages_spoken": ["Fijian", "Rotuman", "Hindi", "Te Reo Māori (basic)"], "primary_cultural": "Fijian", "short_description": "Stories in Every Intricate Stroke & Sweet Creation", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-26 19:51:51.574468+00'),
	('6bfe0fd5-ca21-4e6f-89d3-c74ff3931be2', 'businesses', 'a1fb7177-900d-41f8-b635-c155a16c2e43', 'INSERT', NULL, '{"id": "a1fb7177-900d-41f8-b635-c155a16c2e43", "city": "Raiatea", "name": "L''ame Du Pareu by Vai''ohani", "status": "active", "suburb": "Tumaraa", "address": "PK30.9 C/mer - Motu Nuutere", "country": "French Polynesia", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Arts & Crafts", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771896719956.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771896711215.jpg", "created_at": "2025-11-27T07:23:16.513022+00:00", "updated_at": "2026-02-24T01:33:01.119244+00:00", "description": "Discover the magic of pareo art with Vaihere in beautiful Raiatea. In this hands-on workshop, you''ll learn the traditional craft of painting your own pareo, using colours and patterns that reflect your personal story.\r\n\r\nChoose from three experience levels:\r\n🎨 Child''s Pareo (3 hrs) — A fun, creative session perfect for young artists.\r\n🎨 Guided Design (3 hrs) — Vaihere sketches your chosen idea, and you bring it to life with paint.\r\n🎨 Create Your Own (4 hrs) — Design and paint your own pareo from scratch.\r\n\r\nAll materials are included — just bring yourself and your creativity, and leave with a beautiful handmade pareo to take home. A meaningful and memorable activity for both locals and visitors.\r\n\r\nDécouvrez la magie de l''art du pareo avec Vaihere sur la magnifique île de Raiatea. Lors de cet atelier créatif et immersif, vous apprendrez à peindre votre propre pareo en utilisant des couleurs et des motifs qui racontent votre histoire personnelle.\r\n\r\nChoisissez parmi trois niveaux d''expérience :\r\n🎨 Pareo Enfant (3h) — Une activité amusante et créative, idéale pour les jeunes artistes.\r\n🎨 Design Guidé (3h) — Vaihere dessine le motif de votre choix, et vous lui donnez vie avec la peinture.\r\n🎨 Créez Votre Propre Motif (4h) — Concevez et peignez votre pareo de A à Z.\r\n\r\nTout le matériel est fourni — il vous suffit d''apporter votre créativité et vous repartirez avec un pareo unique, réalisé de vos propres mains. Une expérience", "postal_code": null, "contact_name": "Vaihere Pito", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@vaiohani", "facebook": "https://facebook.com/100046471642888", "instagram": "https://instagram.com/pareubyvaiohani.00"}, "state_region": "Ils Sous Le Vent", "contact_email": "lornapitovai@gmail.com", "contact_phone": "+689 87376668", "cultural_tags": ["Tahitian"], "business_hours": null, "contact_website": null, "languages_spoken": ["English", "French", "Tahitian"], "primary_cultural": "Tahitian", "short_description": "A hands-on pareu painting experience in Raiatea", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-26 19:51:51.574468+00'),
	('275da860-6c7a-4542-890f-6f2faba7bd5c', 'businesses', 'cc214a50-bbbb-4a98-9c77-feb1899c1cae', 'INSERT', NULL, '{"id": "cc214a50-bbbb-4a98-9c77-feb1899c1cae", "city": "Sydney", "name": "Mana Carvings", "status": "active", "suburb": null, "address": null, "country": "Australia", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Arts & Crafts", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771897109293.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771897099046.jpg", "created_at": "2025-12-12T17:30:11.143898+00:00", "updated_at": "2026-02-24T01:38:34.078553+00:00", "description": "Mana Carvings is a celebration of Cook Islands heritage, storytelling, and craftsmanship. Every piece — whether carved on wood, engraved on drinkware, or designed for the home — carries deep cultural meaning, ancestral patterns, and the spirit of mana.\r\n\r\nEach artwork is handcrafted with precision and intention, transforming traditional motifs into modern, functional pieces that honour identity and connection. From symbolic creatures to intricate Polynesian designs, every creation holds a story — one that reflects culture, legacy, and the pride of the Pacific.\r\n\r\nMade with heart and guided by tradition, Mana Carvings exists to keep our stories alive, one handcrafted design at a time.", "postal_code": null, "contact_name": "Kai Strickland", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/profile.php?id=61577910021592", "instagram": "https://instagram.com/manacarvings"}, "state_region": "NSW", "contact_email": "manacarvings@gmail.com", "contact_phone": null, "cultural_tags": ["Cook Islands Māori"], "business_hours": null, "contact_website": null, "languages_spoken": ["English"], "primary_cultural": "Cook Islands Māori", "short_description": "Handcrafted with Culture, Carved with Mana", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-26 19:51:51.574468+00'),
	('3a700532-9565-44a3-b7d2-857d0ad578f2', 'businesses', '385a01f6-0b40-4abf-a15e-d2bb3bd646eb', 'INSERT', NULL, '{"id": "385a01f6-0b40-4abf-a15e-d2bb3bd646eb", "city": "Orlando", "name": "Pacific Stain", "status": "active", "suburb": null, "address": null, "country": "United States", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Arts & Crafts", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771897416975.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771897408351.jpg", "created_at": "2025-12-12T08:38:00.862376+00:00", "updated_at": "2026-02-24T01:43:41.808436+00:00", "description": "Pacific Stain is the creative expression of a Samoan family dedicated to honouring and preserving the stories of their ancestors. Through intricate 3D mixed media, pyrography, traditional motifs, and handcrafted wooden creations, they bring Polynesian culture to life — piece by piece.\r\n\r\nEvery artwork carries the mana of Polynesian heritage, blending ancestral knowledge with modern craftsmanship. From carved bowls and decorative panels to symbolic designs inspired by tatau and natural elements, Pacific Stain celebrates identity, memory, and the deep connection between people and their roots.\r\n\r\nDriven by a passion to share Polynesian art with the world, Pacific Stain creates pieces that are not only visually striking but spiritually meaningful — art that speaks, remembers, and continues the legacy of Polynesia.", "postal_code": null, "contact_name": "Patrick Etu Ah-wong", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@pacificstain", "facebook": "https://facebook.com/pacific.stain", "instagram": "https://instagram.com/pacificstain_official"}, "state_region": "Florida", "contact_email": "pacificstain@aol.com", "contact_phone": null, "cultural_tags": ["Samoan"], "business_hours": null, 