	('f114ec06-9430-4d0d-8918-8dd7fe497364', 'businesses', '53d84963-82c7-40e1-92f8-8f9f7d06f2c5', 'INSERT', NULL, '{"id": "53d84963-82c7-40e1-92f8-8f9f7d06f2c5", "city": "Noumea", "name": "Pacifikmarket.nc", "status": "active", "suburb": null, "address": null, "country": "French Polynesia", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Arts & Crafts", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771897738091.png", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771898014567.png", "created_at": "2025-12-16T02:55:48.501002+00:00", "updated_at": "2026-02-24T01:53:45.246863+00:00", "description": "Pacifikmarket.nc is a vibrant Pacific-led platform based in Nouvelle-Calédonie, dedicated to celebrating, showcasing, and uplifting Pacific designers, artisans, and creative talent from across the region.\r\n\r\nMore than a marketplace, Pacifikmarket.nc is a cultural movement — bringing together fashion shows, artisan markets, creative collaborations, and community events that highlight the richness, diversity, and contemporary expression of Pacific identity. From traditional craftsmanship to modern Pacific fashion, each piece and event tells a story of heritage, pride, and innovation.\r\n\r\nPacifikmarket.nc creates meaningful opportunities for Pacific creatives to be seen, supported, and celebrated — locally and internationally — while building strong connections between cultures, generations, and islands.\r\n\r\nThrough fashion, storytelling, and community-driven events, Pacifikmarket.nc continues to amplify Pacific voices and create spaces where culture thrives.", "postal_code": null, "contact_name": "Christiane Waneissi", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@pacifikmarket_nc", "facebook": "https://facebook.com/Pacifikmarketnc", "linkedin": "https://linkedin.com/company/pa