	('3b38cafb-1c9d-48fa-9709-8794e41c67dc', 'businesses', '9ab9b40a-101a-4afe-a9f2-c17f9b616e87', 'UPDATE', '{"id": "9ab9b40a-101a-4afe-a9f2-c17f9b616e87", "city": "Tahiti", "name": "VAHINE CHIC", "status": "active", "suburb": "Papeete", "address": "Marche de Papeete, pres de l''escalator (Papeete Market - near the escalator)", "country": "French Polynesia", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Arts & Crafts", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771900200203.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771900190798.jpg", "created_at": "2025-12-11T22:41:59.920616+00:00", "updated_at": "2026-02-24T02:30:08.542287+00:00", "description": "Vahine Chic is a celebration of Polynesian artistry — handmade creations crafted with patience, passion, and the timeless beauty of our islands.\r\n\r\nFrom their home in Tahiti, each piece is made with love, blending vibrant colours, natural textures, and traditional inspiration to honour the spirit of Fenua. Their work reflects more than craftsmanship; it carries stories of family, culture, and connection.\r\n\r\nWhether it''s a lovingly woven accessory or a delicately detailed piece of décor, every item invites you to discover the treasures of Fenua and the warmth of the people who create them.\r\n\r\nAt Vahine Chic, artistry is not just a skill — it is a way of sharing joy. A way of keeping culture alive. A way of bringing a little piece of paradise into everyday life.", "postal_code": null, "contact_name": "Timeri Pollock", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/Artisantchic"}, "state_region": "Tahiti", "contact_email": "pacificmarketltd@gmail.com", "contact_phone": "89 54 32 68", "cultural_tags": ["Tahitian"], "business_hours": "10am - 2pm \r\n10h00 - 14h00", "contact_website": null, "languages_spoken"