dustry": "Technology", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771898910016.png", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771898919526.png", "created_at": "2026-02-07T18:26:40.653265+00:00", "updated_at": "2026-02-26T20:51:09.463207+00:00", "description": "SenseAI is a supportive space for your thoughts, feelings, and ideas — without judgment, pressure, or noise.\r\n\r\nLife can be complex, and sometimes you just need help making sense of what''s in your head. SenseAI blends journaling with compassionate AI guidance to help you reflect, gain perspective, and move forward with confidence.\r\n\r\nIt''s like having a thoughtful companion who listens, understands, and helps you see things more clearly.", "postal_code": null, "contact_name": "Jasmin Benioni", "created_date": "2026-02-26", "social_links": {}, "state_region": "Auckland", "contact_email": "senseai@mail.pacificmarket.co.nz", "contact_phone": null, "cultural_tags": ["Cook Islands Māori"], "business_hours": null, "contact_website": "https://www.senseai.co.nz", "languages_spoken": ["English"], "primary_cultural": "Cook Islands Māori", "cultural_identity": "Cook Islands Māori, Cook Islands Māori", "short_description": "AI-Powered Journaling App - Type It, Speak It, Scan It", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-26 20:51:09.463207+00'),
	('24fe040b-209d-45ff-8326-d64d9ecc5001', 'businesses', 'c9fc68e6-da63-4def-9d0b-13991ddc3926', 'UPDATE', '{"id": "c9fc68e6-da63-4def-9d0b-13991ddc3926", "city": "Auckland", "name": "Te Mauri o te Makawe", "status": "active", "suburb": null, "address": null, "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Health & Wellness", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771899866021.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771899858016.jpg", "created_at": "2025-12-01T08:40:49.119488+00:00", "updated_at": "2026-02-24T02:24:31.20184+00:00", "description": "Nuku te manaaki, nuku te manaaki, ka ora ai te iwi.\r\nWith your support and my support, our community will thrive.\r\n\r\nMy name is Iesha Te-Iho. I am a qualified barber, creative, and proud Waiuku local. My journey here was not a straight line — but every challenge sharpened my purpose and showed me that barbering could be more than a trade. It could be a doorway to healing.\r\n\r\nFrom that understanding, Te Mauri o te Makawe: The Koha Manawa was born.\r\n\r\nThis kaupapa delivers professional grooming and braiding through a mobile service, reaching people and places often overlooked — hospices, spinal units, rehabilitation centres, and rural communities where transport and access are barriers. But this work is about far more than hair.\r\n\r\nThrough whakahoki te tapu, hair is treated with care and respectfully returned to Papatūānuku using traditional tikanga — uku (clay), harakeke (flax), and korowai — protecting the mana of our whānau. Alongside this, kōrero is shared and recorded, preserving the voices, stories, and heartbeat of the community.\r\n\r\nThis kaupapa began with one chair and one set of tools, but the vision is a Waka Wānanga — a collective of skilled creatives travelling across Aotearoa and beyond, delivering workshops, teaching tikanga, uplifting hauora, and restoring identity through creativity.\r\n\r\nAt its heart, this is about legacy. About building something that lasts — not just 100 years, but for generations — by caring for people, culture, and community, together.", "postal_code": null, "contact_name": "Iesha Rawinia", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/TeKohaManawa", "instagram": "https://instagram.com/tekohamanawa"}, "state_region": "Auckland", "contact_email": "hairwithesha@gmail.com", "contact_phone": "02102965229", "cultural_tags": ["Māori"], "business_hours": null, "contact_website": "https://msha.ke/beauty_withinyou", "languages_spoken": ["English"], "primary_cultural": "Cook Islands Māori", "cultural_identity": null, "short_description": "Any Style. Any Hair. Any Where.", "subscription_tier": "featured", "stripe_customer_id": null}', '{"id": "c9fc68e6-da63-4def-9d0b-13991ddc3926", "city": "Auckland", "name": "Te Mauri o te Makawe", "status": "active", "suburb": null, "address": null, "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Health & Wellness", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771899866021.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771899858016.jpg", "created_at": "2025-12-01T08:40:49.119488+00:00", "updated_at": "2026-02-26T20:51:09.463207+00:00", "description": "Nuku te manaaki, nuku te manaaki, ka ora ai te iwi.\r\nWith your support and my support, our community will thrive.\r\n\r\nMy name is Iesha Te-Iho. I am a qualified barber, creative, and proud Waiuku local. My journey here was not a straight line — but every challenge sharpened my purpose and showed me that barbering could be more than a trade. It could be a doorway to healing.\r\n\r\nFrom that understanding, Te Mauri o te Makawe: The Koha Manawa was born.\r\n\r\nThis kaupapa delivers professional grooming and braiding through a mobile service, reaching people and places often overlooked — hospices, spinal units, rehabilitation centres, and rural communities where transport and access are barriers. But this work is about far more than hair.\r\n\r\nThrough whakahoki te tapu, hair is treated with care and respectfully returned to Papatūānuku using traditional tikanga — uku (clay), harakeke (flax), and korowai — protecting the mana of our whānau. Alongside this, kōrero is shared and recorded, preserving the voices, stories, and heartbeat of the community.\r\n\r\nThis kaupapa began with one chair and one set of tools, but the vision is a Waka Wānanga — a collective of skilled creatives travelling across Aotearoa and beyond, delivering workshops, teaching tikanga, uplifting hauora, and restoring identity through creativity.\r\n\r\nAt its heart, this is about legacy. About building something that lasts — not just 100 years, but for generations — by caring for people, culture, and community, together.", "postal_code": null, "contact_name": "Iesha Rawinia", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/TeKohaManawa", "instagram": "https://instagram.com/tekohamanawa"}, "state_region": "Auckland", "contact_email": "hairwithesha@gmail.com", "contact_phone": "02102965229", "cultural_tags": ["Māori"], "business_hours": null, "contact_website": "https://msha.ke/beauty_withinyou", "languages_spoken": ["English"], "primary_cultural": "Cook Islands Māori", "cultural_identity": "Cook Islands Māori, Māori", "short_description": "Any Style. Any Hair. Any Where.", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-26 20:51:09.463207+00'),
