	('73612038-9faa-476e-b893-7d31ef1f42aa', 'businesses', '669c26b2-ceec-498e-9e38-17329d6b05ec', 'UPDATE', '{"id": "669c26b2-ceec-498e-9e38-17329d6b05ec", "city": "Auckland", "name": "Oceanique Solutions", "status": "active", "suburb": null, "address": null, "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Travel & Tourism", "logo_url": null, "verified": true, "banner_url": null, "created_at": "2025-11-24T09:10:17.344881+00:00", "updated_at": "2026-02-24T01:41:49.317039+00:00", "description": "Oceanique DMC & Consulting:\r\nYour Premier Destination Management (DMC) and tailored business consultancy. We offer unmatched expertise, seamless event planning and execution. With a deep insight into local culture and attention to detail, we guarantee a spectacular experience. Let us handle the details so you can immerse yourself in the adventure.\r\n\r\nChoose Oceanique Solutions for an experience as smooth as the sound of waves lapping the shore, the touch of gentle breeze, the sight of vibrant sunset, the scent of fresh rain, and the taste of a perfectly crafted meal.\r\n\r\nOceanique Travel:\r\nAs seasoned travel professionals, Oceanique - is your one stop travel shop. From island retreats to cultural experiences, we ensure your travels are unforgettable, allowing you to relish every sun-kissed moment.\r\n\r\nOceanique Education:\r\nOur education services forge strong partnerships with top educational institutions, immigration agent, and schools in New Zealand. We are a partnered Tahitian International Education Agency and engage as a Learning & Development Contractor. Our mission is to offer enriching educational experiences that connect cultures and unlock global opportunities.\r\n\r\nJoin us, and let''s embark on a new learning adventure together.", "postal_code": null, "contact_name": "Daniel Maine", "created_date": "2026-02-26", "social_links": {}, "state_region": "Auckland", "contact_email": "travel@danielmaine.com", "contact_phone": null, "cultural_tags": ["Cook Island"], "business_hours": null, "contact_website": null, "languages_spoken": ["English", "French", "Tahitian"], "primary_cultural": "Tahitian", "cultural_identity": null, "short_description": "Destination Management, Travel Consulting & Professional Services", "subscription_tier": "featured", "stripe_customer_id": null}', '{"id": "669c26b2-ceec-498e-9e38-17329d6b05ec", "city": "Auckland", "name": "Oceanique Solutions", "status": "active", "suburb": null, "address": null, "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Travel & Tourism", "logo_url": null, "verified": true, "banner_url": null, "created_at": "2025-11-24T09:10:17.344881+00:00", "updated_at": "2026-02-26T20:51:09.463207+00:00", "description": "Oceanique DMC & Consulting:\r\nYour Premier Destination Management (DMC) and tailored business consultancy. We offer unmatched expertise, seamless event planning and execution. With a deep insight into local culture and attention to detail, we guarantee a spectacular experience. Let us handle the details so you can immerse yourself in the adventure.\r\n\r\nChoose Oceanique Solutions for an experience as smooth as the sound of waves lapping the shore, the touch of gentle breeze, the sight of vibrant sunset, the scent of fresh rain, and the taste of a perfectly crafted meal.\r\n\r\nOceanique Travel:\r\nAs seasoned travel professionals, Oceanique - is your one stop travel shop. From island retreats to cultural experiences, we ensure your travels are unforgettable, allowing you to relish every sun-kissed moment.\r\n\r\nOceanique Education:\r\nOur education services forge strong partnerships with top educational institutions, immigration agent, and schools in New Zealand. We are a partnered Tahitian International Education Agency and engage as a Learning & Development Contractor. Our mission is to offer enriching educational experiences that connect cultures and unlock global opportunities.\r\n\r\nJoin us, and let''s embark on a new learning adventure together.", "postal_code": null, "contact_name": "Daniel Maine", "created_date": "2026-02-26", "social_links": {}, "state_region": "Auckland", "contact_email": "travel@danielmaine.com", "contact_phone": null, "cultural_tags": ["Cook Island"], "business_hours": null, "contact_website": null, "languages_spoken": ["English", "French", "Tahitian"], "primary_cultural": "Tahitian", "cultural_identity": "Tahitian, Cook Island", "short_description": "Destination Management, Travel Consulting & Professional Services", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-26 20:51:09.463207+00'),
	('b4e3f95d-c742-448b-b1c3-8f3b2ff38453', 'businesses', 'fcb997d1-fb71-4406-b902-cc5ef3208b03', 'UPDATE', '{"id": "fcb997d1-fb71-4406-b902-cc5ef3208b03", "city": "Bundaberg", "name": "Papua New Guinea Bilums and Baskets", "status": "active", "suburb": null, "address": null, "country": "Australia", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Culture & Heritage", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771898183242.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771898190669.png", "created_at": "2025-12-17T06:11:26.868237+00:00", "updated_at": "2026-02-24T01:56:37.014101+00:00", "description": "Papua New Guinea Bilums & Baskets, run by CJ & LJ Mountford and based in Bundaberg, Queensland, is a small family business dedicated to sharing authentic Papua New Guinea arts and crafts with the wider community.\r\n\r\nSpecialising in traditional bilums and handwoven baskets, each piece is created using techniques passed down through generations. Bilums are traditionally crafted by women, woven in a variety of shapes and sizes to serve different purposes — from everyday use to baby carrying. The baskets are traditionally crafted by men, reflecting distinct cultural roles and knowledge systems.\r\n\r\nOnly three provinces in Papua New Guinea continue this specific weaving tradition:\r\n\r\nNorth Solomon (Buka)\r\nSouthern Highlands\r\nEastern Highlands\r\n\r\nThese handcrafted pieces are both functional and meaningful, suitable for home décor, shopping, picnics, and baby carrying — while carrying the stories, skills, and heritage of the communities who make them.\r\n\r\nBy supporting Papua New Guinea Bilums & Baskets, you are helping preserve traditional knowledge and create income opportunities for PNG artisans.", "postal_code": null, "contact_name": "Linah Mountford", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/PapuaNewGuineaBilumsAndBasketsCjLjMountford", "instagram": "https://instagram.com/pngbilumsnbaskets"}, "state_region": "Queensland", "contact_email": "Cmford@southernphone.com.au", "contact_phone": "0423 819 378", "cultural_tags": ["Papua New Guinean"], "business_hours": "10am to 2pm", "contact_website": null, "languages_spoken": ["Pidgin"], "primary_cultural": "Papua New Guinean", "cultural_identity": null, "short_description": "CJ & LJ Mountford", "subscription_tier": "featured", "stripe_customer_id": null}', '{"id": "fcb997d1-fb71-4406-b902-cc5ef3208b03", "city": "Bundaberg", "name": "Papua New Guinea Bilums and Baskets", "status": "active", "suburb": null, "address": null, "country": "Australia", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Culture & Heritage", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771898183242.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771898190669.png", "created_at": "2025-12-17T06:11:26.868237+00:00", "updated_at": "2026-02-26T20:51:09.463207+00:00", "description": "Papua New Guinea Bilums & Baskets, run by CJ & LJ Mountford and based in Bundaberg, Queensland, is a small family business dedicated to sharing authentic Papua New Guinea arts and crafts with the wider community.\r\n\r\nSpecialising in traditional bilums and handwoven baskets, each piece is created using techniques passed down through generations. Bilums are traditionally crafted by women, woven in a variety of shapes and sizes to serve different purposes — from everyday use to baby carrying. The baskets are traditionally crafted by men, reflecting distinct cultural roles and knowledge systems.\r\n\r\nOnly three provinces in Papua New Guinea continue this specific weaving tradition:\r\n\r\nNorth Solomon (Buka)\r\nSouthern Highlands\r\nEastern Highlands\r\n\r\nThese handcrafted pieces are both functional and meaningful, suitable for home décor, shopping, picnics, and baby carrying — while carrying the stories, skills, and heritage of the communities who make them.\r\n\r\nBy supporting Papua New Guinea Bilums & Baskets, you are helping preserve traditional knowledge and create income opportunities for PNG artisans.", "postal_code": null, "contact_name": "Linah Mountford", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/PapuaNewGuineaBilumsAndBasketsCjLjMountford", "instagram": "https://instagram.com/pngbilumsnbaskets"}, "state_region": "Queensland", "contact_email": "Cmford@southernphone.com.au", "contact_phone": "0423 819 378", "cultural_tags": ["Papua New Guinean"], "business_hours": "10am to 2pm", "contact_website": null, "languages_spoken": ["Pidgin"], "primary_cultural": "Papua New Guinean", "cultural_identity": "Papua New Guinean, Papua New Guinean", "short_description": "CJ & LJ Mountford", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-26 20:51:09.463207+00'),
	('3b5e7476-77de-4daf-9f8f-68a1b9243262', 'businesses', '70ea5ff4-fe63-4d3e-b526-cfa3ec0dc95a', 'UPDATE', '{"id": "70ea5ff4-fe63-4d3e-b526-cfa3ec0dc95a", "city": "Draper", "name": "Warrior Lines Tattoo", "status": "active", "suburb": null, "address": "12233 900 E", "country": "United States", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Culture & Heritage", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771900321960.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771900497365.png", "created_at": "2025-12-17T04:52:57.713415+00:00", "updated_at": "2026-02-24T02:35:04.618912+00:00", "description": "Warrior Lines Tattoo is a veteran-owned tattoo studio built on discipline, respect, and the belief that great art comes from a strong, healthy environment.\r\n\r\nWe specialise in bold black and grey work, custom designs, and Polynesian-inspired tattoos that carry meaning, structure, and story.\r\n\r\nThis is a no-nonsense shop for artists and clients who value integrity, craftsmanship, and authenticity. We reject ego, drama, and gatekeeping, and instead foster a space where artists are encouraged to grow, sharpen their skills, and take pride in their work — without judgment or pressure.\r\n\r\nAt Warrior Lines Tattoo, tattooing is more than ink. It''s commitment. It''s brotherhood. It''s honouring the past while building something stronger for the future — one line at a time.", "postal_code": null, "contact_name": "Hans Bennion", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@tribal_touch", "instagram": "https://instagram.com/tribaltouchdesigns"}, "state_region": null, "contact_email": "hans@warriorlines.com", "contact_phone": "4843797885", "cultural_tags": ["Tonga", "Fiji"], "business_hours": "By Appointment Only", "contact_website": "https://www.warriorlines.com", "languages