	('6faab3b4-1549-40b5-b992-a7e41e055549', 'businesses', 'a1fb7177-900d-41f8-b635-c155a16c2e43', 'UPDATE', '{"id": "a1fb7177-900d-41f8-b635-c155a16c2e43", "city": "Raiatea", "name": "L''ame Du Pareu by Vai''ohani", "status": "active", "suburb": "Tumaraa", "address": "PK30.9 C/mer - Motu Nuutere", "country": "French Polynesia", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Arts & Crafts", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771896719956.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771896711215.jpg", "created_at": "2025-11-27T07:23:16.513022+00:00", "updated_at": "2026-02-24T01:33:01.119244+00:00", "description": "Discover the magic of pareo art with Vaihere in beautiful Raiatea. In this hands-on workshop, you''ll learn the traditional craft of painting your own pareo, using colours and patterns that reflect your personal story.\r\n\r\nChoose from three experience levels:\r\n🎨 Child''s Pareo (3 hrs) — A fun, creative session perfect for young artists.\r\n🎨 Guided Design (3 hrs) — Vaihere sketches your chosen idea, and you bring it to life with paint.\r\n🎨 Create Your Own (4 hrs) — Design and paint your own pareo from scratch.\r\n\r\nAll materials are included — just bring yourself and your creativity, and leave with a beautiful handmade pareo to take home. A meaningful and memorable activity for both locals and visitors.\r\n\r\nDécouvrez la magie de l''art du pareo avec Vaihere sur la magnifique île de Raiatea. Lors de cet atelier créatif et immersif, vous apprendrez à peindre votre propre pareo en utilisant des couleurs et des motifs qui racontent votre histoire personnelle.\r\n\r\nChoisissez parmi trois niveaux d''expérience :\r\n🎨 Pareo Enfant (3h) — Une activité amusante et créative, idéale pour les jeunes artistes.\r\n🎨 Design Guidé (3h) — Vaihere dessine le motif de votre choix, et v