	('2ed99c2c-63d8-4877-9c3a-24efb21d1bef', 'businesses', '385a01f6-0b40-4abf-a15e-d2bb3bd646eb', 'UPDATE', '{"id": "385a01f6-0b40-4abf-a15e-d2bb3bd646eb", "city": "Orlando", "name": "Pacific Stain", "status": "active", "suburb": null, "address": null, "country": "United States", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Arts & Crafts", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771897416975.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771897408351.jpg", "created_at": "2025-12-12T08:38:00.862376+00:00", "updated_at": "2026-02-24T01:43:41.808436+00:00", "description": "Pacific Stain is the creative expression of a Samoan family dedicated to honouring and preserving the stories of their ancestors. Through intricate 3D mixed media, pyrography, traditional motifs, and handcrafted wooden creations, they bring Polynesian culture to life — piece by piece.\r\n\r\nEvery artwork carries the mana of Polynesian heritage, blending ancestral knowledge with modern craftsmanship. From carved bowls and decorative panels to symbolic designs inspired by tatau and natural elements, Pacific Stain celebrates identity, memory, and the deep connection between people and their roots.\r\n\r\nDriven by a passion to share Polynesian art with the world, Pacific Stain creates pieces that are not only visually striking but spiritually meaningful — art that speaks, remembers, and continues the legacy of Polynesia.", "postal_code": null, "contact_name": "Patrick Etu Ah-wong", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@pacificstain", "facebook": "https://facebook.com/pacific.stain", "instagram": "https://instagram.com/pacificstain_official"}, "state_region": "Florida", "contact_email": "pacificstain@aol.com", "contact_phone": null, "cultural_tags": ["Samoan"], "business_hours": null, "contact_website": null, "languages_spoken": ["English"], "primary_cultural": "Samoan", "cultural_identity": null, "short_description": "Carving the Spirit of Samoa", "subscription_tier": "featured", "stripe_customer_id": null}', '{"id": "385a01f6-0b40-4abf-a15e-d2bb3bd646eb", "city": "Orlando", "name": "Pacific Stain", "status": "active", "suburb": null, "address": null, "country": "United States", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Arts & Crafts", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771897416975.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771897408351.jpg", "created_at": "2025-12-12T08:38:00.862376+00:00", "updated_at": "2026-02-26T20:51:09.463207+00:00", "description": "Pacific Stain is the creative expression of a Samoan family dedicated to honouring and preserving the stories of their ancestors. Through intricate 3D mixed media, pyrography, traditional motifs, and handcrafted wooden creations, they bring Polynesian culture to life — piece by piece.\r\n\r\nEvery artwork carries the mana of Polynesian heritage, blending ancestral knowledge with modern craftsmanship. From carved bowls and decorative panels to symbolic designs inspired by tatau and natural elements, Pacific Stain celebrates identity, memory, and the deep connection between people and their roots.\r\n\r\nDriven by a passion to share Polynesian art with the world, Pacific Stain creates pieces that are not only visually striking but spiritually meaningful — art that speaks, remembers, and continues the legacy of Polynesia.", "postal_code": null, "contact_name": "Patrick Etu Ah-wong", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@pacificstain", "facebook": "https://facebook.com/pacific.stain", "instagram": "https://instagram.com/pacificstain_official"}, "state_region": "Florida", "contact_email": "pacificstain@aol.com", "contact_phone": null, "cultural_tags": ["Samoan"], "business_hours": null, "contact_website": null, "languages_spoken": ["English"], "primary_cultural": "Samoan", "cultural_identity": "Samoan, Samoan", "short_description": "Carving the Spirit of Samoa", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-26 20:51:09.463207+00'),
	('e8f972df-2e08-437e-9828-5eaab6654364', 'businesses', '53d84963-82c7-40e1-92f8-8f9f7d06f2c5', 'UPDATE', '{"id": "53d84963-82c7-40e1-92f8-8f9f7d06f2c5", "city": "Noumea", "name": "Pacifikmarket.nc", "status": "active", "suburb": null, "address": null, "country": "French Polynesia", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Arts & Crafts", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771897738091.png", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771898014567.png", "created_at": "2025-12-16T02:55:48.501002+00:00", "updated_at": "2026-02-24T01:53:45.246863+00:00", "description": "Pacifikmarket.nc is a vibrant Pacific-led platform based in Nouvelle-Calédonie, dedicated to celebrating, showcasing, and uplifting Pacific designers, artisans, and creative talent from across the region.\r\n\r\nMore than a marketplace, Pacifikmarket.nc is a cultural movement — bringing together fashion shows, artisan markets, creative collaborations, and community events that highlight the richness, diversity, and contemporary expression of Pacific identity. From traditional craftsmanship to modern Pacific fashion, each piece and event tells a story of heritage, pride, and innovation.\r\n\r\nPacifikmarket.nc creates meaningful opportunities for Pacific creatives to be seen, supported, and celebrated — locally and internationally — while building strong connections between cultures, generations, and islands.\r\n\r\nThrough fashion, storytelling, and community-driven events, Pacifikmarket.nc continues to amplify Pacific voices and create spaces where culture thrives.", "postal_code": null, "contact_name": "Christiane Waneissi", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@pacifikmarket_nc", "facebook": "https://facebook.com/Pacifikmarketnc", "linkedin": "https://linkedin.com/company/pacifikm