	('6d534c7c-b9ac-4541-b124-ea0c2b22c910', 'businesses', '20e382e4-f9d9-4369-bb08-5b6016f7a091', 'INSERT', NULL, '{"id": "20e382e4-f9d9-4369-bb08-5b6016f7a091", "city": "Auckland ", "name": "Zeena Khan Coaching ", "status": "active", "suburb": null, "address": null, "claimed": true, "country": "New Zealand", "user_id": null, "featured": true, "industry": "Professional Services", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771900754213.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771900760675.png", "claimed_at": "2026-02-26T22:33:27.633401+00:00", "claimed_by": "system", "created_at": "2026-01-17T23:14:01.458139+00:00", "updated_at": "2026-02-24T02:39:28.186094+00:00", "description": "Zeena Khan Coaching stands at the intersection of modern leadership and cultural wisdom, offering a nuanced approach to professional development.&nbsp;<div><br></div><div>With a focus on empowering leaders to build agile and confident teams, Zeena''s coaching practice is particularly attuned to the complexities of the AI era. Her methodology is grounded in a strengths-based framework that encourages individuals to harness their unique capabilities while remaining culturally aware.<span style=\"font-family: Inter, sans-serif; letter-spacing: normal;\">&nbsp;</span></div><div><span style=\"font-family: Inter, sans-serif; letter-spacing: normal;\"><br></span></div><div><span style=\"font-family: Inter, sans-serif; letter-spacing: normal;\">Zeena Khan brings a wealth of experience to her coaching engagements, drawing from her own heritage and understanding of diverse cultural perspectives. This blend of insight ensures that her clients are not only prepared to meet the challenges of today''s fast-paced business environment but are also equipped to lead with empathy and respect for the diverse backgrounds within their teams.&nbsp;</span></div><div><span style=\"font-family: Inter, sans-serif; letter-spacing: normal;\"><br></span></div><div><span style=\"font-family: Inter, sans-serif; letter-spacing: normal;\">At the core of Zeena''s practice is the belief that true leadership is about fostering an environment where all team members can thrive. By emphasizing cultural awareness and personal strengths, she helps leaders create workplaces that are both innovative and inclusive. Zeena Khan Coaching is dedicated to nurturing leadership that is as dynamic as the world around us, with a commitment to guiding professionals towards their highest potential.</span></div>", "postal_code": null, "contact_name": "Zeena Khan ", "created_date": "2026-01-17", "social_links": {"tiktok": "https://tiktok.com/@ZeenaKhanCoaching ", "youtube": "https://youtube.com/@Adaptability Advantage ", "instagram": "https://instagram.com/ZeenaKhanCoaching "}, "state_region": null, "contact_email": "hello@zeenakhan.com", "contact_phone": "021364881", "business_hours": null, "contact_website": "https://www.zeenakhan.com", "languages_spoken": ["English"], "cultural_identity": "Fijian", "short_description": "Empowering leaders to foster agile, confident teams in the AI era.", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-26 22:33:27.633401+00'),
	('11bcc5c7-59d3-4620-b821-8d5129a9127b', 'businesses', '8e3c51fd-f7f9-4873-a91e-5edafb7b10f0', 'INSERT', NULL, '{"id": "8e3c51fd-f7f9-4873-a91e-5edafb7b10f0", "city": "Auckland", "name": "Inailau", "status": "active", "suburb": null, "address": null, "claimed": true, "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Culture & Heritage", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771895498319.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771895489445.png", "claimed_at": "2026-02-26T22:33:27.633401+00:00", "claimed_by": "system", "created_at": "2025-12-14T20:05:18.903507+00:00", "updated_at": "2026-02-24T01:11:43.222777+00:00", "description": "<p><strong>Inailau Business Women’s Network</strong> is a community-driven platform dedicated to uplifting, connecting, and empowering Pacific women in business.</p><p><br></p>\n<p>Rooted in collaboration and collective growth, Inailau creates safe, supportive spaces where women can share knowledge, build confidence, and grow both personally and professionally. Through networking events, workshops, mentoring sessions, and global connections, Inailau supports Pacific women entrepreneurs at every stage of their journey — from early ideas to established businesses.</p><p><br></p>\n<p>The network champions visibility, leadership, and economic empowerment, recognising that when Pacific women rise, families, communities, and future generations rise with them.</p><p><br></p>\n<p>More than a business network, Inailau is a movement grounded in culture, connection, and purpose — bringing Pacific women together to reflect, realign, and rise together.</p>", "postal_code": null, "contact_name": "Jackie Curry", "created_date": "2025-12-14", "social_links": {"facebook": "https://facebook.com/www.facebook.com/profile.php?id=61552017680960", "instagram": "https://instagram.com/inailaubusinessnetwork"}, "state_region": "North Island", "contact_email": "inailau.womens.network@gmail.com", "contact_phone": null, "business_hours": null, "contact_website": null, "languages_spoken": ["English"], "cultural_identity": "Samoan", "short_description": "Business Women???s Network", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-26 22:33:27.633401+00'),
	('021b9b6f-2cc9-4576-82ee-28615e109816', 'businesses', 'f9ba8226-cffa-44af-9481-0bcfbd86c100', 'INSERT', NULL, '{"id": "f9ba8226-cffa-44af-9481-0bcfbd86c100", "city": "Auckland", "name": "DAN KAS Construction", "status": "active", "suburb": null, "address": null, "claimed": true, "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Trades & Industry", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771895035280.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771894987932.png", "claimed_at": "2026-02-26T22:33:27.633401+00:00", "claimed_by": "system", "created_at": "2026-01-06T18:27:30.26066+00:00", "updated_at": "2026-02-24T01:04:03.115217+00:00", "description": "<p>Dan Kas Construction is an Auckland-based building company built on hard work, attention to detail, and a genuine commitment to quality workmanship. Led by a skilled Samoan crew, the team brings values of service, care, and collective strength into every project, delivering work with integrity and pride.</p><p><br></p>\n<p>Specialising in new builds, renovations, decking, fencing, recladding, and general maintenance, Dan Kas Construction provides reliable, well-crafted solutions designed to last. Each project is approached with a focus on durability, functionality, and clean, professional finishes, ensuring results that are both practical and visually appealing.</p><p><br></p>\n<p>Known throughout Auckland for their strong work ethic, clear communication, and fair, competitive pricing, the team works closely with clients to make every build a collaborative and stress-free experience. Client ideas are respected and combined with expert guidance to achieve outcomes that balance vision with craftsmanship.</p><p><br></p>\n<p>More than just construction, Dan Kas Construction is about building long-term relationships and creating homes and structures that support families and communities. Whether upgrading an existing space or starting a new build, the team brings precision, reliability, and Pacific heart to every stage of the journey.</p>", "postal_code": null, "contact_name": "Dan Kas", "created_date": "2026-01-06", "social_links": {"tiktok": "https://tiktok.com/@dan.kas7", "facebook": "https://facebook.com/dan.kas.construction"}, "state_region": null, "contact_email": "pacificmarketltd@gmail.com", "contact_phone": "021 0887 8365", "business_hours": null, "contact_website": "https://dan-kas-construction.nz", "languages_spoken": ["English"], "cultural_identity": "Samoan", "short_description": "Built on Trust, Crafted by Community", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-26 22:33:27.633401+00'),
	('180aa2dc-e8ad-4554-a9f0-63994fa07454', 'businesses', '5a9d097b-f9b8-40c0-8fa8-81173d741b6c', 'INSERT', NULL, '{"id": "5a9d097b-f9b8-40c0-8fa8-81173d741b6c", "city": "Hamilton", "name": "Good Day Catering", "status": "active", "suburb": "Frankton", "address": "124 Commerce St, Frankton", "claimed": true, "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Food & Agriculture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771895347748.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771895339394.png", "claimed_at": "2026-02-26T22:33:27.633401+00:00", "claimed_by": "system", "created_at": "2025-12-15T20:47:33.428856+00:00", "updated_at": "2026-02-24T01:09:14.319904+00:00", "description": "<p><strong>Good-Day Catering</strong> is a Hamilton-based Pacific catering business proudly serving fresh, authentic Polynesian food for community gatherings, church events, pop-ups, and special occasions.</p><p><br></p>\n<p>Rooted in service and connection, Good-Day Catering is known for generous portions, traditional flavours, and food made with care — whether it’s for a church function, cultural celebration, or local market pop-up. Every dish is prepared with love, respect for culture, and a strong sense of community.</p><p><br></p>\n<p>From beautifully presented desserts to hearty Pacific favourites, Good-Day Catering brings people together through food that feels like home.</p>", "postal_code": "3204", "contact_name": "Liesl Laulu", "created_date": "2025-12-15", "social_links": {"facebook": "https://facebook.com/profile.php?id=61551654938620", "instagram": "https://instagram.com/goodday_catering"}, "state_region": "North Island", "contact_email": "liesl.laulu@gmail.com", "contact_phone": "0210796359", "business_hours": "Tuesday to Friday 11am-5pm \nSaturday 9am-3pm", "contact_website": null, "languages_spoken": ["English"], "cultural_identity": "Samoan", "short_description": "Samoan takeaway and catering for Pacific Island Communities", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-26 22:33:27.633401+00'),
	('28ba2cbd-fd73-4cb6-a3c5-3f13a9486225', 'businesses', '847bde54-f369-40c3-a22b-a4d045850982', 'INSERT', NULL, '{"id": "847bde54-f369-40c3-a22b-a4d045850982", "city": "Auckland", "name": "Paulo Mauia", "status": "active", "suburb": null, "address": null, "claimed": true, "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Arts & Crafts", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771898295405.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771898286727.jpg", "claimed_at": "2026-02-26T22:33:27.633401+00:00", "claimed_by": "system", "created_at": "2025-12-17T05:28:29.873448+00:00", "updated_at": "2026-02-24T01:58:21.816457+00:00", "description": "<p><strong>Arts Finest Tattoo Shop</strong>, owned and led by <strong>Paulo Mauia</strong>, is a respected Samoan tattoo studio known for delivering finely detailed, culturally grounded tattoo work with skill, care, and integrity.</p><p><br></p>\n<p>Specialising in Samoan and Polynesian tattoo designs, Paulo brings years of experience and a deep understanding of traditional patterns, symbolism, and placement. Each piece is carefully crafted to reflect identity, story, and cultural pride — whether through bold traditional work, custom designs, or finely executed modern pieces.</p><p><br></p>\n<p>Arts Finest Tattoo Shop is more than a place to get tattooed; it is a space where art, heritage, and craftsmanship come together. With a strong reputation across Samoa and New Zealand — and expanding to Australia from January 2026 — the studio continues to serve clients who value authenticity, cultural respect, and high-quality tattooing.</p>", "postal_code": null, "contact_name": "Paulo Mauia", "created_date": "2025-12-17", "social_links": {"tiktok": "https://tiktok.com/@paulomauia", "facebook": "https://facebook.com/profile.php?id=100060918442844", "instagram": "https://instagram.com/paulomauia_tattoo"}, "state_region": null, "contact_email": "paulomauia3@gmail.com", "contact_phone": null, "business_hours": "24hrs", "contact_website": null, "languages_spoken": ["English"], "cultural_identity": "Samoan", "short_description": "Arts Finest", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-26 22:33:27.633401+00'),
	('68241e74-714a-48c5-8c88-eb4de04e37ab', 'businesses', 'ebbc9e74-75cc-4b8f-808a-4798ab5e1afd', 'INSERT', NULL, '{"id": "ebbc9e74-75cc-4b8f-808a-4798ab5e1afd", "city": "Apia", "name": "NAUNA", "status": "active", "suburb": null, "address": "Fugalei  (Vaai Compound)", "claimed": true, "country": "Samoa", "user_id": null, "featured": true, "industry": "Arts & Crafts", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771885311143.webp", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771885298227.jpg", "claimed_at": "2026-02-26T22:33:27.633401+00:00", "claimed_by": "system", "created_at": "2026-01-05T03:06:07.035478+00:00", "updated_at": "2026-02-23T22:22:13.293521+00:00", "description": "<p><strong>Nauna</strong> is a vibrant creative and cultural brand based in <strong>Apia, Samoa</strong>, celebrated for its <strong>authentic elei fashion and Pacific-inspired designs</strong>. Rooted in Samoan artistry and storytelling, Nauna showcases clothing and creative expressions that reflect contemporary Pacific identity while honouring traditional patterns and aesthetics.</p><p><br></p>\n<p>Known for its bold, beautiful pieces and strong community engagement, Nauna has built a dedicated following by blending <strong>island heritage with modern style</strong>, making traditional influences accessible and wearable for everyday life. Whether through fashion, creative content, or collaborations with local artists, Nauna is a cultural voice that elevates Pacific design and celebrates Samoan creative excellence.</p>", "postal_code": null, "contact_name": "Adriana Kamu", "created_date": "2026-01-05", "social_links": {"facebook": "https://facebook.com/profile.php?id=61564135313244", "instagram": "https://instagram.com/nauna.samoa"}, "state_region": "Samoa", "contact_email": "nauna_@outlook.com", "contact_phone": "+6857539518", "business_hours": "Mon/Friday: 8am - 5pm\nSaturday: 8am-2pm", "contact_website": "https://linktr.ee/nauna_", "languages_spoken": ["English"], "cultural_identity": "Samoan", "short_description": "Authentic Elei - Made in Samoa", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-26 22:33:27.633401+00'),
	('338874f1-9d80-48b6-9d6c-0be46bcf7115', 'businesses', '03031b71-e999-40e7-ad4d-efc301d32b2d', 'INSERT', NULL, '{"id": "03031b71-e999-40e7-ad4d-efc301d32b2d", "city": "Auckland", "name": "Aki Store", "status": "active", "suburb": "Manukau", "address": "Unit C3 710 Great South Road, Manukau", "claimed": true, "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Arts & Crafts", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771893804500.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771893796718.jpg", "claimed_at": "2026-02-26T22:33:27.633401+00:00", "claimed_by": "system", "created_at": "2025-12-12T18:03:21.327378+00:00", "updated_at": "2026-02-24T00:43:30.66825+00:00", "description": "<p>Our name combines two Māori terms: <strong>“ā”</strong> and <strong>“ki.”</strong> Together, they symbolise the idea of <em>possessing direction</em> — guiding ownership of your space with purpose and intention. It reflects our belief that the environments we live and work in should empower us, not just surround us. Through meaningful décor, we help you shape spaces that feel aligned, intentional, and uniquely yours.</p>\n<p>Aki Store is proudly owned by <strong>VAKA</strong>, a 3D printing company committed to igniting a new wave of everyday entrepreneurs. Our team of Māori and Pasifika creatives, born and raised in South Auckland, are driven by a shared mission: to inspire you to become the curator of your own home.</p>\n<p>We understand that home is more than a physical space. It is a sanctuary for creativity, comfort, and connection.</p>\n<p>Our collection blends cultural aesthetics with modern minimalism, allowing each piece to harmonise effortlessly with any interior style. Every design is created to transform your environment into a reflection of who you are — grounded in culture, elevated through simplicity.</p>\n<p>Our goal is simple: to empower you to embrace your individuality and reimagine your living and working spaces.</p>\n<p>Join us on this journey of self-expression and transformation. Let us help you elevate your space with pieces designed to inspire.</p>", "postal_code": "2104", "contact_name": "Andrea Fua", "created_date": "2025-12-12", "social_links": {"facebook": "https://facebook.com/akistore.co.nz", "instagram": "https://instagram.com/akistore.co.nz"}, "state_region": "Auckland", "contact_email": "support@akistore.co.nz", "contact_phone": null, "business_hours": "Monday: 9 AM - 5 PM\nTuesday: 9 AM - 5 PM\nWednesday: 9 AM - 5 PM\nThursday: 9 AM - 5 PM\nFriday: 9 AM - 5 PM\n\nSaturday, Sunday and Public Holidays: Closed", "contact_website": "https://akistore.co.nz/", "languages_spoken": ["English"], "cultural_identity": "Samoan", "short_description": "Designed to Inspire, Crafted to Glow", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-26 22:33:27.633401+00'),
	('da6768c3-5d40-4d82-9a8b-cdaded514504', 'businesses', '1ceaf4d4-8a5e-4f25-b75f-43a05cd656fb', 'INSERT', NULL, '{"id": "1ceaf4d4-8a5e-4f25-b75f-43a05cd656fb", "city": "Auckland", "name": "SaaSy Cookies", "status": "active", "suburb": null, "address": null, "claimed": true, "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Digital Media & Technology", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771898738509.png", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771898720198.png", "claimed_at": "2026-02-26T22:33:27.633401+00:00", "claimed_by": "system", "created_at": "2025-11-27T05:54:58.04014+00:00", "updated_at": "2026-02-24T02:06:30.235317+00:00", "description": "<p><strong>SaaSy Cookies</strong> is the exclusive technology partner for <strong>Pacific Market</strong>, supporting the incredible small businesses that form the heart of the Pacific community.</p><p><br></p>\n<p>We build simple, effective websites and help vendors set up and optimise their Pacific Market listings so they can be discovered, trusted, and chosen by customers. As the official tech team behind the platform, we remove the confusion from online setup — offering friendly, clear, and reliable support every step of the way.</p><p><br></p>\n<p>From first-time sellers to established brands, we’re here to make your digital presence effortless and professional.</p>\n<p>Our promise is simple:</p>\n<ul>\n<li>\n<p>Make websites easy</p>\n</li>\n<li>\n<p>Make listings shine</p>\n</li><li><p><span style=\"font-family: &quot;Open Sans&quot;, &quot;Open Sans Fallback&quot;, sans-serif;\">Support Pacific businesses with care and expertise</span></p></li><li><p><span style=\"font-family: &quot;Open Sans&quot;, &quot;Open Sans Fallback&quot;, sans-serif;\"><br></span></p></li>\n</ul>\n<p>We’re proud to help grow the Pacific Market ecosystem by empowering every vendor to succeed online.</p>", "postal_code": null, "contact_name": "Jasmin Benioni", "created_date": "2025-11-27", "social_links": {}, "state_region": null, "contact_email": "saasycookies@gmail.com", "contact_phone": null, "business_hours": null, "contact_website": "https://www.saasycookies.com", "languages_spoken": ["English"], "cultural_identity": "Cook Islands M??ori", "short_description": "Digital products for freelancers, creators, and small businesses.", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-26 22:33:27.633401+00'),
	('ccbf9139-00aa-4030-8c5a-0f4398a7b250', 'businesses', 'fa253572-ef34-4f2b-8ea1-11293b37b492', 'INSERT', NULL, '{"id": "fa253572-ef34-4f2b-8ea1-11293b37b492", "city": "Draper", "name": "Warrior Lines Tattoo ", "status": "active", "suburb": null, "address": "12233 900 E", "claimed": true, "country": "US", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Culture & Heritage", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771900321960.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771900497365.png", "claimed_at": "2026-02-26T22:33:27.633401+00:00", "claimed_by": "system", "created_at": "2025-12-17T04:52:57.713415+00:00", "updated_at": "2026-02-24T02:35:04.618912+00:00", "description": "<p><strong>Warrior Lines Tattoo</strong> is a veteran-owned tattoo studio built on discipline, respect, and the belief that great art comes from a strong, healthy environment.<span style=\"font-family: &quot;Open Sans&quot;, &quot;Open Sans Fallback&quot;, sans-serif;\">&nbsp;</span></p><p><span style=\"font-family: &quot;Open Sans&quot;, &quot;Open Sans Fallback&quot;, sans-serif;\"><br></span></p><p><span style=\"font-family: &quot;Open Sans&quot;, &quot;Open Sans Fallback&quot;, sans-serif;\">We specialise in bold black and grey work, custom designs, and Polynesian-inspired tattoos that carry meaning, structure, and story.</span></p><p><span style=\"font-family: &quot;Open Sans&quot;, &quot;Open Sans Fallback&quot;, sans-serif;\"><br></span></p>\n<p>This is a no-nonsense shop for artists and clients who value integrity, craftsmanship, and authenticity. We reject ego, drama, and gatekeeping, and instead foster a space where artists are encouraged to grow, sharpen their skills, and take pride in their work — without judgment or pressure.</p><p><br></p>\n<p>At Warrior Lines Tattoo, tattooing is more than ink. It’s commitment. It’s brotherhood. It’s honouring the past while building something stronger for the future — one line at a time.</p>", "postal_code": null, "contact_name": "Hans Bennion", "created_date": "2025-12-17", "social_links": {"tiktok": "https://tiktok.com/@tribal_touch", "instagram": "https://instagram.com/tribaltouchdesigns"}, "state_region": null, "contact_email": "hans@warriorlines.com", "contact_phone": "4843797885", "business_hours": "By Appointment Only", "contact_website": "https://www.warriorlines.com", "languages_spoken": ["English"], "cultural_identity": "Other, Samoa", "short_description": "Polynesian-inspired Art and Tattoo Studio", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-26 22:33:27.633401+00'),
