	('181f460a-1082-431f-8d45-50e22c6701d8', 'businesses', 'c4530355-c5fb-47fb-ac89-07574831f9e7', 'UPDATE', '{"id": "c4530355-c5fb-47fb-ac89-07574831f9e7", "city": "Naples", "name": "Avalon Wellness and Performance", "status": "active", "suburb": "Naples", "address": "10661 Airport Pulling Road N #10, Naples FL 34109", "claimed": true, "country": "United States", "user_id": null, "featured": true, "industry": "Health & Wellness", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771894449390.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771894442071.png", "claimed_at": "2026-02-26T21:10:10.394806+00:00", "claimed_by": "system", "created_at": "2026-01-08T00:54:56.222151+00:00", "updated_at": "2026-02-26T21:10:10.394806+00:00", "description": "Avalon Wellness & Performance is a holistic health clinic dedicated to helping people move better, feel stronger, and live with greater ease and confidence. Through personalised, hands-on care, Avalon supports recovery, long-term wellness, and peak physical performance.\r\n\r\nThe clinic takes an integrative approach to treatment, combining techniques such as Active Release Technique (ART), Osteopathic Manual Therapy, Cranial Sacral Therapy, and therapeutic massage. Each session is tailored to the individual, addressing not only symptoms but the underlying causes of pain, tension, and movement restrictions.\r\n\r\nAt Avalon, the body is viewed as a connected system. Treatment plans are developed through careful assessment and collaboration, ensuring care aligns with each client''s goals — whether that''s injury recovery, pain management, improved mobility, or enhanced athletic performance.\r\n\r\nAvalon Wellness & Performance provides a calm, professional environment where expertise and compassion come together. From deep tissue and mobility-focused work to gentle therapies that support nervous system balance and stress relief, every session is delivered with intention and care.\r\n\r\nMore than treatment, Avalon empowers clients with the tools, support, and knowledge needed to maintain their wellbeing long after their session ends — helping them move forward feeling stronger, balanced, and supported.", "postal_code": "34109", "contact_name": "Avalon Wellness Performance", "created_date": "2026-02-26", "social_links": {"twitter": "https://twitter.com/WellnessAvalon", "facebook": "https://facebook.com/avalonwellnessandperformance", "instagram": "https://instagram.com/avalonwellnessandperformance"}, "state_region": "FL", "contact_email": "avalonwellnessperformance@gmail.com", "contact_phone": "+632394274697", "business_hours": null, "contact_website": "https://www.avalonwellnessandperformance.com/", "languages_spoken": ["English"], "cultural_identity": "American, American", "short_description": "Move Better. Feel Better. Live Better.", "subscription_tier": "featured", "stripe_customer_id": null}', '{"id": "c4530355-c5fb-47fb-ac89-07574831f9e7", "city": "Naples", "name": "Avalon Wellness and Performance", "status": "active", "suburb": "Naples", "address": "10661 Airport Pulling Road N #10, Naples FL 34109", "claimed": true, "country": "United States", "user_id": null, "featured": true, "industry": "Health & Wellness", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771894449390.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771894442071.png", "claimed_at": "2026-02-26T21:10:10.394806+00:00", "claimed_by": "system", "created_at": "2026-01-08T00:54:56.222151+00:00", "updated_at": "2026-02-26T22:39:51.064663+00:00", "description": "Avalon Wellness & Performance is a holistic health clinic dedicated to helping people move better, feel stronger, and live with greater ease and confidence. Through personalised, hands-on care, Avalon supports