	('d0fea496-3ce6-429d-bfd3-fedc083181fc', 'businesses', 'fcb997d1-fb71-4406-b902-cc5ef3208b03', 'UPDATE', '{"id": "fcb997d1-fb71-4406-b902-cc5ef3208b03", "city": "Bundaberg", "name": "Papua New Guinea Bilums and Baskets", "status": "active", "suburb": null, "address": null, "claimed": true, "country": "Australia", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Culture & Heritage", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771898183242.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771898190669.png", "claimed_at": "2026-02-26T21:10:10.394806+00:00", "claimed_by": "system", "created_at": "2025-12-17T06:11:26.868237+00:00", "updated_at": "2026-02-26T21:23:29.160834+00:00", "description": "Papua New Guinea Bilums & Baskets, run by CJ & LJ Mountford and based in Bundaberg, Queensland, is a small family business dedicated to sharing authentic Papua New Guinea arts and crafts with the wider community.\r\n\r\nSpecialising in traditional bilums and handwoven baskets, each piece is created using techniques passed down through generations. Bilums are traditionally crafted by women, woven in a variety of shapes and sizes to serve different purposes — from everyday use to baby carrying. The baskets are traditionally crafted by men, reflecting distinct cultural roles and knowledge systems.\r\n\r\nOnly three provinces in Papua New Guinea continue this specific weaving tradition:\r\n\r\nNorth Solomon (Buka)\r\nSouthern Highlands\r\nEastern Highlands\r\n\r\nThese handcrafted pieces are both functional and meaningful, suitable for home décor, shopping, picnics, and baby carrying — while carrying the stories, skills, and heritage of the communities who make them.\r\n\r\nBy supporting Papua New Guinea Bilums & Baskets, you are helping preserve traditional knowledge and create income opportunities for PNG artisans.", "postal_code": null, "contact_name": "Linah Mountford", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/PapuaNewGuineaBilumsAndBasketsCjLjMountford", "instagram": "https://instagram.com/pngbilumsnbaskets"}, "state_region": "Queensland", "contact_email": "Cmford@southernphone.com.au", "contact_phone": "0423 819 378", "business_hours": "10am to 2pm", "contact_website": null, "languages_spoken": ["Pidgin"], "cultural_identity": "Papua New Guinean", "short_description": "CJ & LJ Mountford", "subscription_tier": "featured", "stripe_customer_id": null}', '{"id": "fcb997d1-fb71-4406-b902-cc5ef3208b03", "city": "Bundaberg", "name": "Papua New Guinea Bilums and Baskets", "status": "active", "suburb": null, "address": null, "claimed": true, "country": "Australia", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771898183242.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771898190669.png", "claimed_at": "2026-02-26T21:10:10.394806+00:00", "claimed_by": "system", "created_at": "2025-12-17T06:11:26.868237+00:00", "updated_at": "2026-02-26T22:51:12.876887+00:00", "description": "Papua New Guinea Bilums & Baskets, run by CJ & LJ Mountford and based in Bundaberg, Queensland, is a small family business dedicated to sharing authentic Papua New Guinea arts and crafts with the wider community.\r\n\r\nSpecialising in traditional bilums and handwoven baskets, each piece is created using techniques passed down through generations. Bilums are traditionally crafted by women, woven in a variety of shapes and sizes to serve different purposes — from everyday use to baby carrying. The baskets are traditionally crafted by men, reflecting distinct cultural roles and knowledge systems.\r\n\r\nOnly three provinces in Papua New Guinea continue this specific weaving tradition:\r\n\r\nNorth Solomon (Buka)\r\nSouthern Highlands\r\nEastern Highlands\r\n\r\nThese handcrafted pieces are both functional and meaningful, suitable for home décor, shopping, picnics, and baby carrying — while carrying the stories, skills, and heritage of the communities who make them.\r\n\r\nBy supporting Papua New Guinea Bilums & Baskets, you are helping preserve traditional knowledge and create income opportunities for PNG artisans.", "postal_code": null, "contact_name": "Linah Mountford", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/PapuaNewGuineaBilumsAndBasketsCjLjMountford", "instagram": "https://instagram.com/pngbilumsnbaskets"}, "state_region": "Queensland", "contact_email": "Cmford@southernphone.com.au", "contact_phone": "0423 819 378", "business_hours": "10am to 2pm", "contact_website": null, "languages_spoken": ["Pidgin"], "cultural_identity": "Papua New Guinean", "short_description": "CJ & LJ Mountford", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-26 22:51:12.876887+00'),
	('164869d7-02e8-447c-afd7-af8931309371', 'businesses', 'c4530355-c5fb-47fb-ac89-07574831f9e7', 'UPDATE', '{"id": "c4530355-c5fb-47fb-ac89-07574831f9e7", "city": "Naples", "name": "Avalon Wellness and Performance", "status": "active", "suburb": "Naples", "address": "10661 Airport Pulling Road N #10, Naples FL 34109", "claimed": true, "country": "United States", "user_id": null, "featured": true, "industry": "Health & Wellness", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771894449390.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771894442071.png", "claimed_at": "2026-02-26T21:10:10.394806+00:00", "claimed_by": "system", "created_at": "2026-01-08T00:54:56.222151+00:00", "updated_at": "2026-02-26T22:39:51.064663+00:00", "description": "Avalon Wellness & Performance is a holistic health clinic dedicated to helping people move better, feel stronger, and live with greater ease and confidence. Through personalised, hands-on care, Avalon supports recovery, long-term wellness, and peak physical performance.\r\n\r\nThe clinic takes an integrative approach to treatment, combining techniques such as Active Release Technique (ART), Osteopathic Manual Therapy, Cranial Sacral Therapy, and therapeutic massage. Each session is tailored to the individual, addressing not only symptoms but the underlying causes of pain, tension, and movement restrictions.\r\n\r\nAt Avalon, the body is viewed as a connected system. Treatment plans are developed through careful assessment and collaboration, ensuring care aligns with each client''s goals — whether that''s injury recovery, pain management, improved mobility, or enhanced athletic performance.\r\n\r\nAvalon Wellness & Performance provides a calm, professional environment where expertise and compassion come together. From deep tissue and mobility-focused work to gentle therapies that support nervous system balance and stress relief, every session is delivered with intention and care.\r\n\r\nMore than treatment, Avalon empowers clients with the tools, support, and knowledge needed to maintain their wellbeing long after their session ends — helping them move forward feeling stronger, balanced, and supported.", "postal_code": "34109", "contact_name": "Avalon Wellness Performance", "created_date": "2026-02-26", "social_links": {"twitter": "https://twitter.com/WellnessAvalon", "facebook": "https://facebook.com/avalonwellnessandperformance", "instagram": "https://instagram.com/avalonwellnessandperformance"}, "state_region": "FL", "contact_email": "avalonwellnessperformance@gmail.com", "contact_phone": "+632394274697", "business_hours": null, "contact_website": "https://www.avalonwellnessandperformance.com/", "languages_spoken": ["English"], "cultural_identity": null, "short_description": "Move Better. Feel Better. Live Better.", "subscription_tier": "featured", "stripe_customer_id": null}', '{"id": "c4530355-c5fb-47fb-ac89-07574831f9e7", "city": "Naples", "name": "Avalon Wellness and Performance", "status": "active", "suburb": "Naples", "address": "10661 Airport Pulling Road N #10, Naples FL 34109", "claimed": true, "country": "United States", "user_id": null, "featured": true, "industry": "Health & Wellness", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771894449390.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771894442071.png", "claimed_at": "2026-02-26T21:10:10.394806+00:00", "claimed_by": "system", "created_at": "2026-01-08T00:54:56.222151+00:00", "updated_at": "2026-02-26T22:51:12.876887+00:00", "description": "Avalon Wellness & Performance is a holistic health clinic dedicated to helping people move better, feel stronger, and live with greater ease and confidence. Through personalised, hands-on care, Avalon supports recovery, long-