z", "status": "active", "suburb": "Otahuhu", "address": "28 Hauiti Road", "claimed": true, "country": "New Zealand", "user_id": null, "featured": true, "industry": "Consulting & Professional Services", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771896528085.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771896534314.png", "claimed_at": "2026-02-26T21:10:10.394806+00:00", "claimed_by": "system", "created_at": "2026-01-10T22:23:57.816715+00:00", "updated_at": "2026-02-26T22:51:12.876887+00:00", "description": "We are a small shoe cleaning business. For over 4 years, we have cleaned and conditioned shoes from sneakers to boots to your everyday beaters.\r\nWe have done shoes for Charlie Pomee from 3hd & also ex all black Karl Tuinukuafe. Just to name afew. We''re happy to clean any of shoe and save the from the landfill. Give us a try today. You won''t be disappointed. JT&K", "postal_code": "1062", "contact_name": "Jaydes Katu", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@jayztamaka", "youtube": "https://youtube.com/@JTANDKICKZ", "facebook": "https://facebook.com/jayz.tamaka", "instagram": "https://instagram.com/jztamakaandkickz"}, "state_region": "Auckland", "contact_email": "jztamakaandkickz@hotmail.com", "contact_phone": "0272774465", "business_hours": "Monday to Friday\r\nWeekend Closed (Unless Arranged)", "contact_website": null, "languages_spoken": ["English"], "cultural_identity": "Cook Islands Māori", "short_description": "Want your shoes cleaned? Say Less!", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-26 22:51:12.876887+00'),
	('01f56a45-6c4d-4959-bc9a-71304adb3e93', 'businesses', 'c9fc68e6-da63-4def-9d0b-13991ddc3926', 'UPDATE', '{"id": "c9fc68e6-da63-4def-9d0b-13991ddc3926", "city": "Auckland", "name": "Te Mauri o te Makawe", "status": "active", "suburb": null, "address": null, "claimed": true, "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Health & Wellness", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771899866021.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771899858016.jpg", "claimed_at": "2026-02-26T21:10:10.394806+00:00", "claimed_by": "system", "created_at": "2025-12-01T08:40:49.119488+00:00", "updated_at": "2026-02-26T21:10:10.394806+00:00", "description": "Nuku te manaaki, nuku te manaaki, ka ora ai te iwi.\r\nWith your support and my support, our community will thrive.\r\n\r\nMy name is Iesha Te-Iho. I am a qualified barber, creative, and proud Waiuku local. My journey here was not a straight line — but every challenge sharpened my purpose and showed me that barbering could be more than a trade. It could be a doorway to healing.\r\n\r\nFrom that understanding, Te Mauri o te Makawe: The Koha Manawa was born.\r\n\r\nThis kaupapa delivers professional grooming and braiding through a mobile service, reaching people and places often overlooked — hospices, spinal units, rehabilitation centres, and rural communities where transport and access are barriers. But this work is about far more than hair.\r\n\r\nThrough whakahoki te tapu, hair is treated with care and respectfully returned to Papatūānuku using traditional tikanga — uku (clay), harakeke (flax), and korowai — protecting the mana of our whānau. Alongside this, kōrero is shared and recorded, preserving the voices, stories, and heartbeat of the community.\r\n\r\nThis kaupapa began with one chair and one set of tools, but the vision is a Waka Wānanga — a collective of skilled creatives travelling across Aotearoa and beyond, delivering workshops, teaching tikanga, uplifting hauora, and restoring identity through creativity.\r\n\r\nAt its heart, this is about legacy. About building something that lasts — not just 100 years, but for generations — by caring for people, culture, and community, together.", "postal_code": null, "contact_name": "Iesha Rawinia", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/TeKohaManawa", "instagram": "https://instagram.com/tekohamanawa"}, "state_region": "Auckland", "contact_email": "hairwithesha@gmail.com", "contact_phone": "02102965229", "business_hours": null, "contact_website": "https://msha.ke/beauty_withinyou", "languages_spoken": ["English"], "cultural_identity": "Cook Islands Māori, Māori", "short_description": "Any Style. Any Hair. Any Where.", "subscription_tier": "featured", "stripe_customer_id": null}', '{"id": "c9fc68e6-da63-4def-9d0b-13991ddc3926", "city": "Auckland", "name": "Te Mauri o te Makawe", "status": "active", "suburb": null, "address": null, "claimed": true, "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Health & Wellness", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771899866021.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771899858016.jpg", "claimed_at": "2026-02-26T21:10:10.394806+00:00", "claimed_by": "system", "created_at": "2025-12-01T08:40:49.119488+00:00", "updated_at": "2026-02-26T22:51:12.876887+00:00", "description": "Nuku te manaaki, nuku te manaaki, ka ora ai te iwi.\r\nWith your support and my support, our community will thrive.\r\n\r\nMy name is Iesha Te-Iho. I am a qualified barber, creative, and proud Waiuku local. My journey here was not a straight line — but every challenge sharpened my purpose and showed me that barbering could be more than a trade. It could be a doorway to healing.\r\n\r\nFrom that understanding, Te Mauri o te Makawe: The Koha Manawa was born.\r\n\r\nThis kaupapa delivers professional grooming and braiding through a mobile service, reaching people and places often overlooked — hospices, spinal units, rehabilitation centres, and rural communities where transport and access are barriers. But this work is about far more than hair.\r\n\r\nThrough whakahoki te tapu, hair is treated with care and respectfully returned to Papatūānuku using traditional tikanga — uku (clay), harakeke (flax), and korowai — protecting the mana of our whānau. Alongside this, kōrero is shared and recorded, preserving the voices, stories, and heartbeat of the community.\r\n\r\nThis kaupapa began with one chair and one set of tools, but the vision is a Waka Wānanga — a collective of skilled creatives travelling across Aotearoa and beyond, delivering workshops, teaching tikanga, uplifting hauora, and restoring identity through creativity.\r\n\r\nAt its heart, this is about legacy. About building something that lasts — not just 100 years, but for generations — by caring for people, culture, and community, together.", "postal_code": null, "contact_name": "Iesha Rawinia", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/TeKohaManawa", "instagram": "https://instagram.com/tekohamanawa"}, "state_region": "Auckland", "contact_email": "hairwithesha@gmail.com", "contact_phone": "02102965229", "business_hours": null, "contact_website": "https://msha.ke/beauty_withinyou", "languages_spoken": ["English"], "cultural_identity": "Cook Islands Māori, Māori", "short_description": "Any Style. Any Hair. Any Where.", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-26 22:51:12.876887+00'),
	('e399bf04-9812-413c-b29a-8f52797fcb8b', 'businesses', 'cfaafb58-8f0a-4633-87b0-2a53e8425a6c', 'UPDATE', '{"id": "cfaafb58-8f0a-4633-87b0-2a53e8425a6c", "city": "Auckland", "name": "David Laumatia Art", "status": "active", "suburb": null, "address": null, "claimed": true, "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Arts & Crafts", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771895125650.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771895114953.jpg", "claimed_at": "2026-02-26T21:10:10.394806+00:00", "claimed_by": "system", "created_at": "2025-12-11T21:08:12.207784+00:00", "updated_at": "2026-02-26T21:10:10.394806+00:00", "description": "Where Pacific art is brought to life through innovative 3D mixed media.\r\n\r\nDavid''s creations honour Samoan culture, evoking cherished memories and a deep sense of pride. With each piece, he captures a powerful connection to his homeland — expressing both identity and a heartfelt longing to return to his roots.\r\n\r\nToday, David''s work is shared and celebrated across the world.", "postal_code": null, "contact_name": "David Laumatia", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/davidlaumatiaart", "instagram": "https://instagram.com/davidlaumatiapacificart"}, "state_region": "Auckland", "contact_email": "david.laumatia@gmail.com", "contact_phone": "0272358448", "business_hours": null, "contact_website": null, "languages_spoken": ["English"], "cultural_identity": "Samoa, China", "short_description": "Art that carries the soul of Samoa", "subscription_tier": "featured", "stripe_customer_id": null}', '{"id": "cfaafb58-8f0a-4633-87b0-2a53e8425a6c", "city": "Auckland", "name": "David Laumatia Art", "status": "active", "suburb": null, "address": null, "claimed": true, "country": "New Zealand", "user