	('87dea167-3366-4025-8b11-4c6b151b4245', 'businesses', '3966d793-4307-49e0-891e-5fc34c3a0cd8', 'UPDATE', '{"id": "3966d793-4307-49e0-891e-5fc34c3a0cd8", "city": "Avignon", "name": "SILILO TATTOO", "status": "active", "suburb": null, "address": null, "claimed": true, "country": "France", "user_id": null, "featured": true, "industry": "Arts & Crafts", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771899176037.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771899167657.png", "claimed_at": "2026-02-26T21:10:10.394806+00:00", "claimed_by": "system", "created_at": "2025-12-23T08:13:31.132338+00:00", "updated_at": "2026-02-26T21:10:10.394806+00:00", "description": "SILLO TATTOO is a Polynesian tattoo artist whose work is deeply influenced by traditional patterns, structure, and the cultural meaning carried within every line.\r\n\r\nEach tattoo is approached with intention and respect, not simply as a design, but as a personal story expressed through Polynesian-inspired motifs, balance, and flow. From large-scale body pieces to detailed custom work, SILLO TATTOO focuses on clean execution, strong composition, and designs that honour both the wearer and the cultural origins of the art.\r\n\r\nBased in Avignon, France, SILLO TATTOO works by appointment, creating custom tattoos for clients who value authenticity, symbolism, and craftsmanship. Every piece is thoughtfully designed to fit the body naturally, ensuring the tattoo remains timeless, powerful, and meaningful.\r\n\r\nAt SILLO TATTOO, tattooing is more than decoration, it is identity, respect, and storytelling through ink.", "postal_code": null, "contact_name": "Brice SILILO", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@sililo.tattoo", "facebook": "https://facebook.com/profile.php?id=100077690003413", "linkedin": "https://linkedin.com/brice-sililo-6154b