	('2da16c33-698f-4ec2-ac3e-1f3615bced1d', 'businesses', 'f9ba8226-cffa-44af-9481-0bcfbd86c100', 'UPDATE', '{"id": "f9ba8226-cffa-44af-9481-0bcfbd86c100", "city": "Auckland", "name": "DAN KAS Construction", "status": "active", "suburb": null, "address": null, "claimed": true, "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Trades & Industry", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771895035280.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771894987932.png", "claimed_at": "2026-02-26T22:33:27.633401+00:00", "claimed_by": "system", "created_at": "2026-01-06T18:27:30.26066+00:00", "updated_at": "2026-02-24T01:04:03.115217+00:00", "description": "<p>Dan Kas Construction is an Auckland-based building company built on hard work, attention to detail, and a genuine commitment to quality workmanship. Led by a skilled Samoan crew, the team brings values of service, care, and collective strength into every project, delivering work with integrity and pride.</p><p><br></p>\n<p>Specialising in new builds, renovations, decking, fencing, recladding, and general maintenance, Dan Kas Construction provides reliable, well-crafted solutions designed to last. Each project is approached with a focus on durability, functionality, and clean, professional finishes, ensuring results that are both practical and visually appealing.</p><p><br></p>\n<p>Known throughout Auckland for their strong work ethic, clear communication, and fair, competitive pricing, the team works closely with clients to make every build a collaborative and stress-free experience. Client ideas are respected and combined with expert guidance to achieve outcomes that balance vision with craftsmanship.</p><p><br></p>\n<p>More than just construction, Dan Kas Construction is about building long-term relationships and creating ho