	('3db347a8-fa8d-4993-ba48-7762671ea6d6', 'businesses', '847bde54-f369-40c3-a22b-a4d045850982', 'UPDATE', '{"id": "847bde54-f369-40c3-a22b-a4d045850982", "city": "Auckland", "name": "Paulo Mauia", "status": "active", "suburb": null, "address": null, "claimed": true, "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Arts & Crafts", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771898295405.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771898286727.jpg", "claimed_at": "2026-02-26T22:33:27.633401+00:00", "claimed_by": "system", "created_at": "2025-12-17T05:28:29.873448+00:00", "updated_at": "2026-02-24T01:58:21.816457+00:00", "description": "<p><strong>Arts Finest Tattoo Shop</strong>, owned and led by <strong>Paulo Mauia</strong>, is a respected Samoan tattoo studio known for delivering finely detailed, culturally grounded tattoo work with skill, care, and integrity.</p><p><br></p>\n<p>Specialising in Samoan and Polynesian tattoo designs, Paulo brings years of experience and a deep understanding of traditional patterns, symbolism, and placement. Each piece is carefully crafted to reflect identity, story, and cultural pride — whether through bold traditional work, custom designs, or finely executed modern pieces.</p><p><br></p>\n<p>Arts Finest Tattoo Shop is more than a place to get tattooed; it is a space where art, heritage, and craftsmanship come together. With a strong reputation across Samoa and New Zealand — and expanding to Australia from January 2026 — the studio continues to serve clients who value authenticity, cultural respect, and high-quality tattooing.</p>", "postal_code": null, "contact_name": "Paulo Mauia", "created_date": "2025-12-17", "social_links": {"tiktok": "https://tiktok.com/@paulomauia", "facebook": "https://facebook.com/profile.php?id=100060918442844", 