	('5f7d1811-b64c-427e-8fe7-3f239dbf6144', 'businesses', '525e84f2-66d3-4a1b-a896-dd64d01ec033', 'UPDATE', '{"id": "525e84f2-66d3-4a1b-a896-dd64d01ec033", "city": "New Zealand", "name": "Tuhono Design", "status": "active", "suburb": null, "address": null, "claimed": true, "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Other", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771899400009.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771899392291.jpg", "claimed_at": "2026-02-26T21:10:10.394806+00:00", "claimed_by": "system", "created_at": "2025-12-12T18:28:30.64805+00:00", "updated_at": "2026-02-26T22:51:12.876887+00:00", "description": "Tuhono Design was created by Jay and Sarah, a proud Maori whanau dedicated to revitalising te reo Maori in everyday spaces. Inspired by their own journeys of reconnecting with their heritage, they design bilingual planners, calendars, prints, and educational resources that make Maori language and culture accessible, beautiful, and part of daily life. Their kaupapa is built on whanaungatanga, kotahitanga, and uplifting the next generation so they can grow up confident in their identity. Through thoughtfully crafted products rooted in meaning and connection, Tuhono Design invites whanau everywhere to learn, speak, and live te reo Maori with pride.", "postal_code": null, "contact_name": "Sarah", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@tuhonodesign", "facebook": "https://facebook.com/Tuhonodesign"}, "state_region": "New Zealand", "contact_email": "kiaora@tuhonodesign.com", "contact_phone": null, "business_hours": null, "contact_website": "https://tuhonodesign.com", "languages_spoken": ["Te Reo Māori"], "cultural_identity": "Maori", "short_description": "Bilingual Maori Resources to Inspire, Learn & Connect", "su