	('418c52ba-f2d7-448d-832e-832752c51530', 'businesses', '8e3c51fd-f7f9-4873-a91e-5edafb7b10f0', 'UPDATE', '{"id": "8e3c51fd-f7f9-4873-a91e-5edafb7b10f0", "city": "Auckland", "name": "Inailau", "status": "active", "suburb": null, "address": null, "claimed": true, "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Consulting & Professional Services", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771895498319.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771895489445.png", "claimed_at": "2026-02-26T22:33:27.633401+00:00", "claimed_by": "system", "created_at": "2025-12-14T20:05:18.903507+00:00", "updated_at": "2026-02-26T22:56:26.982992+00:00", "description": "<p><strong>Inailau Business Women’s Network</strong> is a community-driven platform dedicated to uplifting, connecting, and empowering Pacific women in business.</p><p><br></p>\n<p>Rooted in collaboration and collective growth, Inailau creates safe, supportive spaces where women can share knowledge, build confidence, and grow both personally and professionally. Through networking events, workshops, mentoring sessions, and global connections, Inailau supports Pacific women entrepreneurs at every stage of their journey — from early ideas to established businesses.</p><p><br></p>\n<p>The network champions visibility, leadership, and economic empowerment, recognising that when Pacific women rise, families, communities, and future generations rise with them.</p><p><br></p>\n<p>More than a business network, Inailau is a movement grounded in culture, connection, and purpose — bringing Pacific women together to reflect, realign, and rise together.</p>", "postal_code": null, "contact_name": "Jackie Curry", "created_date": "2025-12-14", "social_links": {"facebook": "https://facebook.com/www.facebook.com/profile.php?id=61552017680960",