	('b3df6d67-3fa9-4ac8-9fe4-75c6e7715ed5', 'businesses', '03031b71-e999-40e7-ad4d-efc301d32b2d', 'UPDATE', '{"id": "03031b71-e999-40e7-ad4d-efc301d32b2d", "city": "Auckland", "name": "Aki Store", "status": "active", "suburb": "Manukau", "address": "Unit C3 710 Great South Road, Manukau", "claimed": true, "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771893804500.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771893796718.jpg", "claimed_at": "2026-02-26T22:33:27.633401+00:00", "claimed_by": "system", "created_at": "2025-12-12T18:03:21.327378+00:00", "updated_at": "2026-02-26T22:51:12.876887+00:00", "description": "<p>Our name combines two Māori terms: <strong>“ā”</strong> and <strong>“ki.”</strong> Together, they symbolise the idea of <em>possessing direction</em> — guiding ownership of your space with purpose and intention. It reflects our belief that the environments we live and work in should empower us, not just surround us. Through meaningful décor, we help you shape spaces that feel aligned, intentional, and uniquely yours.</p>\n<p>Aki Store is proudly owned by <strong>VAKA</strong>, a 3D printing company committed to igniting a new wave of everyday entrepreneurs. Our team of Māori and Pasifika creatives, born and raised in South Auckland, are driven by a shared mission: to inspire you to become the curator of your own home.</p>\n<p>We understand that home is more than a physical space. It is a sanctuary for creativity, comfort, and connection.</p>\n<p>Our collection blends cultural aesthetics with modern minimalism, allowing each piece to harmonise effortlessly with any interior style. Every design is created to transform your environment into a reflection of who you are — grounded in culture, elevated through simplicity.</p>\n<p>Our goal is simple: to empower you to embrace your individuality and reimagine your living and working spaces.</p>\n<p>Join us on this journey of self-expression and transformation. Let us help you elevate your space with pieces designed to inspire.</p>", "postal_code": "2104", "contact_name": "Andrea Fua", "created_date": "2025-12-12", "social_links": {"facebook": "https://facebook.com/akistore.co.nz", "instagram": "https://instagram.com/akistore.co.nz"}, "state_region": "Auckland", "contact_email": "support@akistore.co.nz", "contact_phone": null, "business_hours": "Monday: 9 AM - 5 PM\nTuesday: 9 AM - 5 PM\nWednesday: 9 AM - 5 PM\nThursday: 9 AM - 5 PM\nFriday: 9 AM - 5 PM\n\nSaturday, Sunday and Public Holidays: Closed", "contact_website": "https://akistore.co.nz/", "languages_spoken": ["English"], "cultural_identity": "Samoan", "short_description": "Designed to Inspire, Crafted to Glow", "subscription_tier": "featured", "stripe_customer_id": null}', '{"id": "03031b71-e999-40e7-ad4d-efc301d32b2d", "city": "Auckland", "name": "Aki Store", "status": "active", "suburb": "Manukau", "address": "Unit C3 710 Great South Road, Manukau", "claimed": true, "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771893804500.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771893796718.jpg", "claimed_at": "2026-02-26T22:33:27.633401+00:00", "claimed_by": "system", "created_at": "2025-12-12T18:03:21.327378+00:00", "updated_at": "2026-02-27T04:40:35.250108+00:00", "description": "Our name combines two Māori terms: “ā” and “ki.” Together, they symbolise the idea of possessing direction — guiding ownership of your space with purpose and intention. It reflects our belief that the environments we live and work in should empower us, not just surround us. Through meaningful décor, we help you shape spaces that feel aligned, intentional, and uniquely yours.\r\n\r\nAki Store is proudly owned by VAKA, a 3D printing company committed to igniting a new wave of everyday entrepreneurs. Our team of Māori and Pasifika creatives, born and raised in South Auckland, are driven by a shared mission: to inspire you to become the curator of your own home.\r\n\r\nWe understand that home is more than a physical space. It is a sanctuary for creativity, comfort, and connection.\r\n\r\nOur collection blends cultural aesthetics with modern minimalism, allowing each piece to harmonise effortlessly with any interior style. Every design is created to transform your environment into a reflection of who you are — grounded in culture, elevated through simplicity.\r\n\r\nOur goal is simple: to empower you to embrace your individuality and reimagine your living and working spaces.\r\n\r\nJoin us on this journey of self-expression and transformation. Let us help you elevate your space with pieces designed to inspire.", "postal_code": "2104", "contact_name": "Andrea Fua", "created_date": "2025-12-12", "social_links": {"facebook": "https://facebook.com/akistore.co.nz", "instagram": "https://instagram.com/akistore.co.nz"}, "state_region": "Auckland", "contact_email": "support@akistore.co.nz", "contact_phone": null, "business_hours": "Monday: 9 AM - 5 PM\nTuesday: 9 AM - 5 PM\nWednesday: 9 AM - 5 PM\nThursday: 9 AM - 5 PM\nFriday: 9 AM - 5 PM\n\nSaturday, Sunday and Public Holidays: Closed", "contact_website": "https://akistore.co.nz/", "languages_spoken": ["English"], "cultural_identity": "Samoan", "short_description": "Designed to Inspire, Crafted to Glow", "subscription_tier": "featured", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-27 04:40:35.250108+00'),
	('00829d76-f9fb-497c-8dcd-7cfcd57e6655', 'businesses', 'f9ba8226-cffa-44af-9481-0bcfbd86c100', 'UPDATE', '{"id": "f9ba8226-cffa-44af-9481-0bcfbd86c100", "city": "Auckland", "name": "DAN KAS Construction", "status": "active", "suburb": null, "address": null, "claimed": true, "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "featured": true, "industry": "Construction & Trades", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771895035280.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771894987932.png", "claimed_at": "2026-02-26T22:33:27.633401+00:00", "claimed_by": "system", "created_at": "2026-01-06T18:27:30.26066+00:00", "updated_at": "2026-02-26T22:51:12.876887+00:00", "description": "<p>Dan Kas Construction is an Auckland-based building company built on hard work, attention to detail, and a genuine commitment to quality workmanship. Led by a skilled Samoan crew, the team brings values of service, care, and collective strength into every project, delivering work with integrity and pride.</p><p><br></p>\n<p>Specialising in new builds, renovations, decking, fencing, recladding, and general maintenance, Dan Kas Construction provides reliable, well-crafted solutions designed to last. Each project is approached with a focus on durability, functionality, and clean, professional finishes, ensuring results that are both practical and visually appealing.</p><p><br></p>\n<p>Known throughout Auckland for their strong work ethic, clear communication, and fair, competitive pricing, the team works closely with clients to make every build a collaborative and stress-free experience. Client ideas are respected and combined with expert guidance to achieve outcomes that balance vision with craftsmanship.</p><p><br></p>\n<p>More than just construction, Dan Kas Construction is about building long-term relationships and creatin