	('ed626d6a-7871-40d9-b19b-760d19608d6e', 'businesses', '74845da6-e0b1-421c-8181-7e6753c152f9', 'UPDATE', '{"id": "74845da6-e0b1-421c-8181-7e6753c152f9", "city": "Auckland", "name": "Zeena Khan Coaching", "status": "active", "suburb": null, "address": null, "claimed": true, "country": "New Zealand", "user_id": null, "featured": true, "industry": "Consulting & Professional Services", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771900754213.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771900760675.png", "claimed_at": "2026-02-26T21:10:10.394806+00:00", "claimed_by": "system", "created_at": "2026-01-17T23:14:01.458139+00:00", "updated_at": "2026-02-26T22:51:12.876887+00:00", "description": "Zeena Khan Coaching stands at the intersection of modern leadership and cultural wisdom, offering a nuanced approach to professional development.\r\n\r\nWith a focus on empowering leaders to build agile and confident teams, Zeena''s coaching practice is particularly attuned to the complexities of the AI era. Her methodology is grounded in a strengths-based framework that encourages individuals to harness their unique capabilities while remaining culturally aware.\r\n\r\nZeena Khan brings a wealth of experience to her coaching engagements, drawing from her own heritage and understanding of diverse cultural perspectives. This blend of insight ensures that her clients are not only prepared to meet the challenges of today''s fast-paced business environment but are also equipped to lead with empathy and respect for the diverse backgrounds within their teams.\r\n\r\nAt the core of Zeena''s practice is the belief that true leadership is about fostering an environment where all team members can thrive. By emphasizing cultural awareness and personal strengths, she helps leaders create workplaces that are both innovative and inclusive. Zeena Khan Coaching 