	('19880c9b-977a-4710-b0bf-f39daf82e8ef', 'businesses', '6bd8fad1-df64-4c3c-8cd8-7cb63be2926a', 'UPDATE', '{"id": "6bd8fad1-df64-4c3c-8cd8-7cb63be2926a", "city": "Auckland", "name": "Anarra Alofa Est.2020", "status": "active", "suburb": null, "address": null, "claimed": true, "country": "New Zealand", "user_id": null, "featured": true, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771893925293.jpg", "verified": true, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771893916527.jpg", "claimed_at": "2026-02-26T21:10:10.394806+00:00", "claimed_by": "system", "created_at": "2026-01-06T22:28:48.12743+00:00", "updated_at": "2026-02-26T22:51:12.876887+00:00", "description": "Talofa lava, my name is Sharon, co-founder and owner of Anarra Alofa.\r\nMy creative journey began in 2020, when I first set my heart on making handcrafted board signs. Shortly after, I welcomed my first child — my son — and, like many mothers, I placed that dream on hold. Even so, the desire to create never left me.\r\n\r\nOver time, my inspiration naturally returned through Sei — the floral ear pieces deeply loved and worn by Samoan women. In our culture, Sei are more than adornment; they are expressions of beauty, identity, and pride. The idea of creating them stayed with me, quietly growing until the time felt right.\r\n\r\nAt the beginning of last year, I finally took the step to bring Anarra Alofa to life. Starting small and working with minimal materials, I began handcrafting Sei with love, care, and intention. What started as a simple creative outlet has grown into a heartfelt small business rooted in culture, creativity, and passion.\r\n\r\nAnarra Alofa is a reflection of my journey — as a mother, a Samoan woman, and a creator — and a celebration of the beauty we carry and share through our culture.", "postal_code": null, "contact_name": "Sharon Naseri", "