	('24d24af5-628c-42ed-a3fd-85d99296a9f4', 'businesses', 'f9ba8226-cffa-44af-9481-0bcfbd86c100', 'UPDATE', '{"id": "f9ba8226-cffa-44af-9481-0bcfbd86c100", "city": "Auckland", "name": "DAN KAS Construction", "status": "active", "suburb": null, "address": null, "claimed": true, "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "industry": "Construction & Trades", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771895035280.jpg", "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771894987932.png", "claimed_at": "2026-02-26T22:33:27.633401+00:00", "claimed_by": "system", "created_at": "2026-01-06T18:27:30.26066+00:00", "updated_at": "2026-02-27T04:40:35.250108+00:00", "description": "Dan Kas Construction is an Auckland-based building company built on hard work, attention to detail, and a genuine commitment to quality workmanship. Led by a skilled Samoan crew, the team brings values of service, care, and collective strength into every project, delivering work with integrity and pride.\r\n\r\nSpecialising in new builds, renovations, decking, fencing, recladding, and general maintenance, Dan Kas Construction provides reliable, well-crafted solutions designed to last. Each project is approached with a focus on durability, functionality, and clean, professional finishes, ensuring results that are both practical and visually appealing.\r\n\r\nKnown throughout Auckland for their strong work ethic, clear communication, and fair, competitive pricing, the team works closely with clients to make every build a collaborative and stress-free experience. Client ideas are respected and combined with expert guidance to achieve outcomes that balance vision with craftsmanship.\r\n\r\nMore than just construction, Dan Kas Construction is about building long-term relationships and creating homes and structures that support families and communities. Whether upgra