	('c8003750-8d8b-4eed-98be-64bd3c807450', 'businesses', '03031b71-e999-40e7-ad4d-efc301d32b2d', 'UPDATE', '{"id": "03031b71-e999-40e7-ad4d-efc301d32b2d", "city": "Auckland", "name": "Aki Store", "status": "active", "suburb": "Manukau", "address": "Unit C3 710 Great South Road, Manukau", "claimed": true, "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771893804500.jpg", "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771893796718.jpg", "claimed_at": "2026-02-26T22:33:27.633401+00:00", "claimed_by": "system", "created_at": "2025-12-12T18:03:21.327378+00:00", "updated_at": "2026-02-27T04:40:35.250108+00:00", "description": "Our name combines two Māori terms: “ā” and “ki.” Together, they symbolise the idea of possessing direction — guiding ownership of your space with purpose and intention. It reflects our belief that the environments we live and work in should empower us, not just surround us. Through meaningful décor, we help you shape spaces that feel aligned, intentional, and uniquely yours.\r\n\r\nAki Store is proudly owned by VAKA, a 3D printing company committed to igniting a new wave of everyday entrepreneurs. Our team of Māori and Pasifika creatives, born and raised in South Auckland, are driven by a shared mission: to inspire you to become the curator of your own home.\r\n\r\nWe understand that home is more than a physical space. It is a sanctuary for creativity, comfort, and connection.\r\n\r\nOur collection blends cultural aesthetics with modern minimalism, allowing each piece to harmonise effortlessly with any interior style. Every design is created to transform your environment into a reflection of who you are — grounded in culture, elevated through simplicity.\r\n\r\nOur goal is simple: to empower you to embrace your individuality and reimagine your living and working spaces.\r\n\r\nJoin us on this journey of self-expression and transformation. Let us help you elevate your space with pieces designed to inspire.", "postal_code": "2104", "contact_name": "Andrea Fua", "created_date": "2025-12-12", "social_links": {"facebook": "https://facebook.com/akistore.co.nz", "instagram": "https://instagram.com/akistore.co.nz"}, "state_region": "Auckland", "contact_email": "support@akistore.co.nz", "contact_phone": null, "business_hours": "Monday: 9 AM - 5 PM\nTuesday: 9 AM - 5 PM\nWednesday: 9 AM - 5 PM\nThursday: 9 AM - 5 PM\nFriday: 9 AM - 5 PM\n\nSaturday, Sunday and Public Holidays: Closed", "contact_website": "https://akistore.co.nz/", "languages_spoken": ["English"], "cultural_identity": "Samoan", "short_description": "Designed to Inspire, Crafted to Glow", "subscription_tier": "featured", "stripe_customer_id": null}', '{"id": "03031b71-e999-40e7-ad4d-efc301d32b2d", "city": "Auckland", "name": "Aki Store", "status": "active", "suburb": "Manukau", "address": "Unit C3 710 Great South Road, Manukau", "claimed": true, "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771893804500.jpg", "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771893796718.jpg", "claimed_at": "2026-02-26T22:33:27.633401+00:00", "claimed_by": "system", "created_at": "2025-12-12T18:03:21.327378+00:00", "updated_at": "2026-02-27T23:23:47.549036+00:00", "description": "Our name combines two Māori terms: “ā” and “ki.” Together, they symbolise the idea of possessing direction — guiding ownership of your space with purpose and intention. It reflects our belief that the environments we live and work in should empower us, not just surround us. Through meaningful décor, we help you shape spaces that feel aligned, intentional, and uniquely yours.