	('1efc7018-bcf1-4649-b03b-97b73aeef110', 'businesses', '1bebde9a-bd2f-4c22-a522-228fbef28880', 'UPDATE', '{"id": "1bebde9a-bd2f-4c22-a522-228fbef28880", "city": "Port Moresby", "name": "Pacificana", "status": "active", "suburb": null, "address": null, "claimed": true, "country": "Papua New Guinea", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771897636310.jpg", "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771897517709.jpg", "claimed_at": "2026-02-26T21:10:10.394806+00:00", "claimed_by": "system", "created_at": "2025-12-13T02:00:27.00608+00:00", "updated_at": "2026-02-26T22:56:26.982992+00:00", "description": "Pacificana is a proudly Papua New Guinea–owned creative studio bringing the vibrant spirit of the Pacific to life through handcrafted floral art. Every piece is inspired by the colours of our islands, the strength of our women, and the traditions passed down through generations.\r\n\r\nEach handmade bloom is carefully shaped, painted, and detailed with love — transforming iconic Pacific flowers into stunning wearable art for everyday joy, cultural events, weddings, and island celebrations.\r\n\r\nPacificana is more than an accessories brand — it is a celebration of identity. A way for our people to express who we are, wherever we are in the world. Bold, colourful, authentic, and proudly PNG.\r\n\r\nFrom bright hibiscus and frangipani to custom colourways, every design reflects the warmth, resilience, and creativity of our Pacific community.\r\n\r\nWear your culture. Celebrate your roots. Bloom boldly with Pacificana.", "postal_code": null, "contact_name": "Pacificana", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/pacificana.pg"}, "state_region": null, "contact_email": "pacificmarketltd@gmail.com", "contact_phone": "+675 7344 5243", "