	('f729870c-93f2-42de-9cfd-354f699b5093', 'businesses', '6bd8fad1-df64-4c3c-8cd8-7cb63be2926a', 'UPDATE', '{"id": "6bd8fad1-df64-4c3c-8cd8-7cb63be2926a", "city": "Auckland", "name": "Anarra Alofa Est.2020", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "New Zealand", "user_id": null, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771893925293.jpg", "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771893916527.jpg", "claimed_at": null, "claimed_by": null, "created_at": "2026-01-06T22:28:48.12743+00:00", "updated_at": "2026-02-27T23:23:47.549036+00:00", "description": "Talofa lava, my name is Sharon, co-founder and owner of Anarra Alofa.\r\nMy creative journey began in 2020, when I first set my heart on making handcrafted board signs. Shortly after, I welcomed my first child — my son — and, like many mothers, I placed that dream on hold. Even so, the desire to create never left me.\r\n\r\nOver time, my inspiration naturally returned through Sei — the floral ear pieces deeply loved and worn by Samoan women. In our culture, Sei are more than adornment; they are expressions of beauty, identity, and pride. The idea of creating them stayed with me, quietly growing until the time felt right.\r\n\r\nAt the beginning of last year, I finally took the step to bring Anarra Alofa to life. Starting small and working with minimal materials, I began handcrafting Sei with love, care, and intention. What started as a simple creative outlet has grown into a heartfelt small business rooted in culture, creativity, and passion.\r\n\r\nAnarra Alofa is a reflection of my journey — as a mother, a Samoan woman, and a creator — and a celebration of the beauty we carry and share through our culture.", "postal_code": null, "shop_handle": null, "contact_name": "Sharon Naseri", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@anarraalofa2020", "facebook": "https://facebook.com/silaumea.ieru", "instagram": "https://instagram.com/anarraalofa2125"}, "state_region": null, "contact_email": "sharonnaseri@gmail.com", "contact_phone": "+64212170344", "business_hours": "Monday-Friday 9am-5pm", "contact_website": null, "languages_spoken": ["English"], "cultural_identity": "Samoan", "short_description": "Elevate your style with beautifully crafted Sei''s for every occasion at Anarra Alofa.", "subscription_tier": "featured_plus", "stripe_customer_id": null}', '{"id": "6bd8fad1-df64-4c3c-8cd8-7cb63be2926a", "city": "Auckland", "name": "Anarra Alofa Est.2020", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "New Zealand", "user_id": null, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771893925293.jpg", "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771893916527.jpg", "claimed_at": null, "claimed_by": null, "created_at": "2026-01-06T22:28:48.12743+00:00", "updated_at": "2026-02-28T00:04:58.146465+00:00", "description": "Talofa lava, my name is Sharon, co-founder and owner of Anarra Alofa.\r\nMy creative journey began in 2020, when I first set my heart on making handcrafted board signs. Shortly after, I welcomed my first child — my son — and, like many mothers, I placed that dream on hold. Even so, the desire to create never left me.\r\n\r\nOver time, my inspiration naturally returned through Sei — the floral ear pieces deeply loved and worn by Samoan women. In our culture, Sei are more than adornment; they are expressions of beauty, identity, and pride. The idea of creating them stayed with me, quietly growing until the time felt right.\r\n\r\nAt the beginning of last year, I finally took the step to bring Anarra Alofa to life. Starting small and working with minimal materials, I began handcrafting Sei with love, care, and intention. What started as a simple creative outlet has grown into a heartfelt small business rooted in culture, creativity, and passion.\r\n\r\nAnarra Alofa is a reflection of my journey — as a mother, a Samoan woman, and a creator — and a celebration of the beauty we carry and share through our culture.", "postal_code": null, "shop_handle": "anarra-alofa-est-2020", "contact_name": "Sharon Naseri", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@anarraalofa2020", "facebook": "https://facebook.com/silaumea.ieru", "instagram": "https://instagram.com/anarraalofa2125"}, "state_region": null, "contact_email": "sharonnaseri@gmail.com", "contact_phone": "+64212170344", "business_hours": "Monday-Friday 9am-5pm", "contact_website": null, "languages_spoken": ["English"], "cultural_identity": "Samoan", "short_description": "Elevate your style with beautifully crafted Sei''s for every occasion at Anarra Alofa.", "subscription_tier": "featured_plus", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-28 00:04:58.146465+00'),
	('81f06524-3f30-4bbd-aadb-ea7baab4c411', 'businesses', 'a1fb7177-900d-41f8-b635-c155a16c2e43', 'UPDATE', '{"id": "a1fb7177-900d-41f8-b635-c155a16c2e43", "city": "Raiatea", "name": "L''ame Du Pareu by Vai''ohani", "status": "active", "suburb": "Tumaraa", "address": "PK30.9 C/mer - Motu Nuutere", "claimed": true, "country": "French Polynesia", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771896719956.jpg", "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771896711215.jpg", "claimed_at": "2026-02-26T21:10:10.394806+00:00", "claimed_by": "system", "created_at": "2025-11-27T07:23:16.513022+00:00", "updated_at": "2026-02-27T23:23:47.549036+00:00", "description": "Discover the magic of pareo art with Vaihere in beautiful Raiatea. In this hands-on workshop, you''ll learn the traditional craft of painting your own pareo, using colours and patterns that reflect your personal story.\r\n\r\nChoose from three experience levels:\r\n🎨 Child''s Pareo (3 hrs) — A fun, creative session perfect for young artists.\r\n🎨 Guided Design (3 hrs) — Vaihere sketches your chosen idea, and you bring it to life with paint.\r\n🎨 Create Your Own (4 hrs) — Design and paint your own pareo from scratch.\r\n\r\nAll materials are included — just bring yourself and your creativity, and leave with a beautiful handmade pareo to take home. A meaningful and memorable activity for both locals and visitors.\r\n\r\nDécouvrez la magie de l''art du pareo avec Vaihere sur la magnifique île de Raiatea. Lors de cet atelier créatif et immersif, vous apprendrez à peindre votre propre pareo en utilisant des couleurs et des motifs qui racontent votre histoire personnelle.\r\n\r\nChoisissez parmi trois niveaux d''expérience :\r\n🎨 Pareo Enfant (3h) — Une activité amusante et créative, idéale pour les jeunes artistes.\r\n🎨 Design Guidé (3h) — Vaihere dessine le motif de votre choix, et vous lui donnez vie avec la peinture.\r\n🎨 Créez Votre Propre Motif (4h) — Concevez et peignez votre pareo de A à Z.\r\n\r\nTout le matériel est fourni — il vous suffit d''apporter votre créativité et vous repartirez avec un pareo unique, réalisé de vos propres mains. Une expérience", "postal_code": null, "shop_handle": null, "contact_name": "Vaihere Pito", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@vaiohani", "facebook": "https://facebook.com/100046471642888", "instagram": "https://instagram.com/pareubyvaiohani.00"}, "state_region": "Ils Sous Le Vent", "contact_email": "lornapitovai@gmail.com", "contact_phone": "+689 87376668", "business_hours": null, "contact_website": null, "languages_spoken": ["English", "French", "Tahitian"], "cultural_identity": "Tahitian", "short_description": "A hands-on pareu painting experience in Raiatea", "subscription_tier": "featured_plus", "stripe_customer_id": null}', '{"id": "a1fb7177-900d-41f8-b635-c155a16c2e43", "city": "Raiatea", "name": "L''ame Du Pareu by Vai''ohani", "status": "active", "suburb": "Tumaraa", "address": "PK30.9 C/mer - Motu Nuutere", "claimed": true, "country": "French Polynesia", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771896719956.jpg", "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771896711215.jpg", "claimed_at": "2026-02-26T21:10:10.394806+00:00", "claimed_by": "system", "created_at": "2025-11-27T07:23:16.513022+00:00", "updated_at": "2026-02-28T00:04:58.146465+00:00", "description": "Discover the magic of pareo art with Vaihere in beautiful Raiatea. In this hands-on workshop, you''ll learn the traditional craft of painting your own pareo, using colours and patterns that reflect your personal story.\r\n\r\nChoose from three 