	('79cd8afb-7d6b-43d0-88ea-79d059ceba86', 'businesses', 'fcb997d1-fb71-4406-b902-cc5ef3208b03', 'UPDATE', '{"id": "fcb997d1-fb71-4406-b902-cc5ef3208b03", "city": "Bundaberg", "name": "Papua New Guinea Bilums and Baskets", "status": "active", "suburb": null, "address": null, "claimed": true, "country": "Australia", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771898183242.jpg", "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771898190669.png", "claimed_at": "2026-02-26T21:10:10.394806+00:00", "claimed_by": "system", "created_at": "2025-12-17T06:11:26.868237+00:00", "updated_at": "2026-02-27T23:23:47.549036+00:00", "description": "Papua New Guinea Bilums & Baskets, run by CJ & LJ Mountford and based in Bundaberg, Queensland, is a small family business dedicated to sharing authentic Papua New Guinea arts and crafts with the wider community.\r\n\r\nSpecialising in traditional bilums and handwoven baskets, each piece is created using techniques passed down through generations. Bilums are traditionally crafted by women, woven in a variety of shapes and sizes to serve different purposes — from everyday use to baby carrying. The baskets are traditionally crafted by men, reflecting distinct cultural roles and knowledge systems.\r\n\r\nOnly three provinces in Papua New Guinea continue this specific weaving tradition:\r\n\r\nNorth Solomon (Buka)\r\nSouthern Highlands\r\nEastern Highlands\r\n\r\nThese handcrafted pieces are both functional and meaningful, suitable for home décor, shopping, picnics, and baby carrying — while carrying the stories, skills, and heritage of the communities who make them.\r\n\r\nBy supporting Papua New Guinea Bilums & Baskets, you are helping preserve traditional knowledge and create income opportunities for PNG artisans.", "postal_code": null, "shop_handle": nu