	('d0ed9f91-7bb7-4f71-a156-ce4cfe056bee', 'businesses', 'c4530355-c5fb-47fb-ac89-07574831f9e7', 'UPDATE', '{"id": "c4530355-c5fb-47fb-ac89-07574831f9e7", "city": "Naples", "name": "Avalon Wellness and Performance", "status": "active", "suburb": "Naples", "address": "10661 Airport Pulling Road N #10, Naples FL 34109", "claimed": false, "country": "United States", "user_id": null, "industry": "Health & Wellness", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771894449390.jpg", "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771894442071.png", "claimed_at": null, "claimed_by": null, "created_at": "2026-01-08T00:54:56.222151+00:00", "updated_at": "2026-02-27T23:23:47.549036+00:00", "description": "Avalon Wellness & Performance is a holistic health clinic dedicated to helping people move better, feel stronger, and live with greater ease and confidence. Through personalised, hands-on care, Avalon supports recovery, long-term wellness, and peak physical performance.\r\n\r\nThe clinic takes an integrative approach to treatment, combining techniques such as Active Release Technique (ART), Osteopathic Manual Therapy, Cranial Sacral Therapy, and therapeutic massage. Each session is tailored to the individual, addressing not only symptoms but the underlying causes of pain, tension, and movement restrictions.\r\n\r\nAt Avalon, the body is viewed as a connected system. Treatment plans are developed through careful assessment and collaboration, ensuring care aligns with each client''s goals — whether that''s injury recovery, pain management, improved mobility, or enhanced athletic performance.\r\n\r\nAvalon Wellness & Performance provides a calm, professional environment where expertise and compassion come together. From deep tissue and mobility-focused work to gentle therapies that support nervous system balance and stress relief, every session is delivered with intention and care.\r\n\r\nMore than treatment, Avalon empowers clients with the tools, support, and knowledge needed to maintain their wellbeing long after their session ends — helping them move forward feeling stronger, balanced, and supported.", "postal_code": "34109", "shop_handle": null, "contact_name": "Avalon Wellness Performance", "created_date": "2026-02-26", "social_links": {"twitter": "https://twitter.com/WellnessAvalon", "facebook": "https://facebook.com/avalonwellnessandperformance", "instagram": "https://instagram.com/avalonwellnessandperformance"}, "state_region": "FL", "contact_email": "avalonwellnessperformance@gmail.com", "contact_phone": "+632394274697", "business_hours": null, "contact_website": "https://www.avalonwellnessandperformance.com/", "languages_spoken": ["English"], "cultural_identity": null, "short_description": "Move Better. Feel Better. Live Better.", "subscription_tier": "featured_plus", "stripe_customer_id": null}', '{"id": "c4530355-c5fb-47fb-ac89-07574831f9e7", "city": "Naples", "name": "Avalon Wellness and Performance", "status": "active", "suburb": "Naples", "address": "10661 Airport Pulling Road N #10, Naples FL 34109", "claimed": false, "country": "United States", "user_id": null, "industry": "Health & Wellness", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771894449390.jpg", "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771894442071.png", "claimed_at": null, "claimed_by": null, "created_at": "2026-01-08T00:54:56.222151+00:00", "updated_at": "2026-02-28T00:04:58.146465+00:00", "description": "Avalon Wellness & Performance is a holistic health clinic dedicated to helping people move better, feel stronger, and live with greater ease and confidence. Through personalised, hands-on care, Avalon supports recovery, long-term wellness, and peak physical performance.\r\n\r\nThe clinic takes an integrative approach to treatment, combining techniques such as Active Release Technique (ART), Osteopathic Manual Therapy, Cranial Sacral Therapy, and therapeutic massage. Each session is tailored to the individual, addressing not only symptoms but the underlying causes of pain, tension, and movement restrictions.\r\n\r\nAt Avalon, the body is viewed as a connected system. Treatment plans are developed through careful assessment and collaboration, ensuring care aligns with each client''s goals — whether that''s injury recovery, pain management, improved mobility, or enhanced athletic performance.\r\n\r\nAvalon Wellness & Performance provides a calm, professional environment where expertise and compassion come together. From deep tissue and mobility-focused work to gentle therapies that support nervous system balance and stress relief, every session is delivered with intention and care.\r\n\r\nMore than treatment, Avalon empowers clients with the tools, support, and knowledge needed to maintain their wellbeing long after their session ends — helping them move forward feeling stronger, balanced, and supported.", "postal_code": "34109", "shop_handle": "avalon-wellness-and-performance", "contact_name": "Avalon Wellness Performance", "created_date": "2026-02-26", "social_links": {"twitter": "https://twitter.com/WellnessAvalon", "facebook": "https://facebook.com/avalonwellnessandperformance", "instagram": "https://instagram.com/avalonwellnessandperformance"}, "state_region": "FL", "contact_email": "avalonwellnessperformance@gmail.com", "contact_phone": "+632394274697", "business_hours": null, "contact_website": "https://www.avalonwellnessandperformance.com/", "languages_spoken": ["English"], "cultural_identity": null, "short_description": "Move Better. Feel Better. Live Better.", "subscription_tier": "featured_plus", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-28 00:04:58.146465+00'),
	('11a7ec76-c589-40eb-9307-ad72f14320b7', 'businesses', '7e83ede6-32fa-4019-b2b5-96f71948a0ae', 'UPDATE', '{"id": "7e83ede6-32fa-4019-b2b5-96f71948a0ae", "city": "Australia", "name": "Island Pepe", "status": "active", "suburb": null, "address": null, "claimed": true, "country": "Australia", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771895626761.jpg", "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771895620639.jpg", "claimed_at": "2026-02-26T21:10:10.394806+00:00", "claimed_by": "system", "created_at": "2025-12-15T04:06:38.295736+00:00", "updated_at": "2026-02-27T23:23:47.549036+00:00", "description": "Island Pepe is a family-founded Pasifika brand created with one heartfelt purpose: to preserve and share Pacific language and culture with the next generation.\r\n\r\nRooted in a rich heritage spanning multiple regions of the South Pacific, Island Pepe designs meaningful everyday essentials for babies and children — from clothing and blankets to books and gift sets. Each piece is thoughtfully created to reflect the languages, stories, and traditions passed down by our ancestors, helping parents build lasting cultural connections at home.\r\n\r\nMore than a brand, Island Pepe is a celebration of identity, belonging, and pride. Through respectful collaboration with native speakers and cultural contributors across the Pacific, every design honours authenticity, storytelling, and community.\r\n\r\nIsland Pepe welcomes everyone — Pasifika and non-Pasifika alike — to share in this journey of preserving culture, nurturing identity, and creating memories that children will carry with them for life.", "postal_code": null, "shop_handle": null, "contact_name": "Jen Masoe", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@island_pepe", "facebook": "https://facebook.com/islandpepe", "instagram": "https://instagram.com/island_pepe"}, "state_region": "Australia", "contact_email": "team.islandpepe@gmail.com", "contact_phone": null, "business_hours": null, "contact_website": "https://www.islandpepe.com", "languages_spoken": ["English"], "cultural_identity": "Samoa, Tonga", "short_description": "Passing Culture to the Next Generation", "subscription_tier": "featured_plus", "stripe_customer_id": null}', '{"id": "7e83ede6-32fa-4019-b2b5-96f71948a0ae", "city": "Australia", "name": "Island Pepe", "status": "active", "suburb": null, "address": null, "claimed": true, "country": "Australia", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771895626761.jpg", "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771895620639.jpg", "claimed_at": "2026-02-26T21:10:10.394806+00:00", "claimed_by": "system", "created_at": "2025-12-15T04:06:38.295736+00:00", "updated_at": "2026-02-28T00:04:58.146465+00:00", "description": "Island Pepe is a family-founded Pasifika brand created with one heartfelt purpose: to preserve and share Pacific language and culture with the next generation.\r\n\r\nRooted in a rich heritage spanning multiple regions of the South Pacific, Island Pepe designs meaningful everyday essentials for babies and children — from clothing and blankets to books and gift sets. Each piece is thoughtfully created to reflect the languages, stories, and traditions passed down by our ancestors, helping parents build lasting cultural connections at home.\r\n\r\nMore than a brand, Island Pepe is a celebration of identity, belonging, and pride. Through respectful collaboration with native speakers and cultural contributors across the Pacific, every design honours authenticity, storytelling, and community.\r\n\r\nIsland Pepe welcomes everyone — Pasifika and non-P