	('5afb5af9-cf75-4a6d-b634-e7a028d832a4', 'businesses', '20b54ac1-50ae-4475-89ef-b50569505408', 'UPDATE', '{"id": "20b54ac1-50ae-4475-89ef-b50569505408", "city": "New Zealand", "name": "M.Steven", "status": "active", "suburb": null, "address": null, "claimed": true, "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771896978917.jpeg", "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771896973343.png", "claimed_at": "2026-02-26T21:10:10.394806+00:00", "claimed_by": "system", "created_at": "2025-12-14T08:18:01.195186+00:00", "updated_at": "2026-02-27T23:23:47.549036+00:00", "description": "This artist brings worlds to life through intricate, hand-drawn line work, creating pieces that feel both deeply personal and endlessly expansive. Every artwork is built stroke by stroke — layering symbols, creatures, and flowing forms that invite the viewer to slow down and discover something new each time they look.\r\n\r\nInspired by storytelling, movement, and the complexity of lived experience, their work blends fine detail with raw expression. Using acrylic paint and acrylic pen alongside traditional drawing tools, each piece carries its own rhythm — reflecting patience, discipline, and a deep respect for the creative process.\r\n\r\nBeyond visual art, this same care and creativity extend into handcrafted desserts and custom celebration cakes, including wedding and birthday designs. Whether expressed on paper, canvas, or through edible art, the artist approaches every creation with the same intention: balance, beauty, and meaning.\r\n\r\nThese works are never rushed — they are thoughtfully crafted, allowing ideas to unfold naturally. The result is a body of work that feels alive and grounded, celebrating creativity as a form of meditation, expression, and connection across many mediums.", "postal_code": null, "shop_handle": null, "contact_name": "Mario Steven", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@m.stevenfjrot23"}, "state_region": "New Zealand", "contact_email": "mariosteven75@yahoo.co.nz", "contact_phone": null, "business_hours": null, "contact_website": null, "languages_spoken": ["Fijian", "Rotuman", "Hindi", "Te Reo Māori (basic)"], "cultural_identity": "Fijian, Italy", "short_description": "Stories in Every Intricate Stroke & Sweet Creation", "subscription_tier": "featured_plus", "stripe_customer_id": null}', '{"id": "20b54ac1-50ae-4475-89ef-b50569505408", "city": "New Zealand", "name": "M.Steven", "status": "active", "suburb": null, "address": null, "claimed": true, "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771896978917.jpeg", "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771896973343.png", "claimed_at": "2026-02-26T21:10:10.394806+00:00", "claimed_by": "system", "created_at": "2025-12-14T08:18:01.195186+00:00", "updated_at": "2026-02-28T00:04:58.146465+00:00", "description": "This artist brings worlds to life through intricate, hand-drawn line work, creating pieces that feel both deeply personal and endlessly expansive. Every artwork is built stroke by stroke — layering symbols, creatures, and flowing forms that invite the viewer to slow down and discover something new each time they look.\r\n\r\nInspired by storytelling, movement, and the complexity of lived experience, their work blends fine detail with raw expression. Using acrylic paint and acrylic pen alongside traditional drawing tools, each piece carries its own rhythm — reflecting patience, discipline, and a deep respect for the creative process.\r\n\r\nBeyond visual art, this same care and creativity exte