	('78983ddf-14e6-486b-b903-d8604e475524', 'businesses', '847bde54-f369-40c3-a22b-a4d045850982', 'UPDATE', '{"id": "847bde54-f369-40c3-a22b-a4d045850982", "city": "Auckland", "name": "Paulo Mauia", "status": "active", "suburb": null, "address": null, "claimed": true, "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771898295405.jpg", "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771898286727.jpg", "claimed_at": "2026-02-26T22:33:27.633401+00:00", "claimed_by": "system", "created_at": "2025-12-17T05:28:29.873448+00:00", "updated_at": "2026-02-28T00:04:58.146465+00:00", "description": "Arts Finest Tattoo Shop, owned and led by Paulo Mauia, is a respected Samoan tattoo studio known for delivering finely detailed, culturally grounded tattoo work with skill, care, and integrity.\r\n\r\nSpecialising in Samoan and Polynesian tattoo designs, Paulo brings years of experience and a deep understanding of traditional patterns, symbolism, and placement. Each piece is carefully crafted to reflect identity, story, and cultural pride — whether through bold traditional work, custom designs, or finely executed modern pieces.\r\n\r\nArts Finest Tattoo Shop is more than a place to get tattooed; it is a space where art, heritage, and craftsmanship come together. With a strong reputation across Samoa and New Zealand — and expanding to Australia from January 2026 — the studio continues to serve clients who value authenticity, cultural respect, and high-quality tattooing.", "postal_code": null, "shop_handle": "paulo-mauia", "contact_name": "Paulo Mauia", "created_date": "2025-12-17", "social_links": {"tiktok": "https://tiktok.com/@paulomauia", "facebook": "https://facebook.com/profile.php?id=100060918442844", "instagram": "https://instagram.com/paulomauia_tattoo"}, "state_region