	('3e1f6fbe-b506-4837-9071-a7c7c4c65036', 'businesses', 'a1fb7177-900d-41f8-b635-c155a16c2e43', 'UPDATE', '{"id": "a1fb7177-900d-41f8-b635-c155a16c2e43", "city": "Raiatea", "name": "L''ame Du Pareu by Vai''ohani", "status": "active", "suburb": "Tumaraa", "address": "PK30.9 C/mer - Motu Nuutere", "claimed": true, "country": "French Polynesia", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771896719956.jpg", "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771896711215.jpg", "claimed_at": "2026-02-26T21:10:10.394806+00:00", "claimed_by": "system", "created_at": "2025-11-27T07:23:16.513022+00:00", "updated_at": "2026-02-28T00:04:58.146465+00:00", "description": "Discover the magic of pareo art with Vaihere in beautiful Raiatea. In this hands-on workshop, you''ll learn the traditional craft of painting your own pareo, using colours and patterns that reflect your personal story.\r\n\r\nChoose from three experience levels:\r\n🎨 Child''s Pareo (3 hrs) — A fun, creative session perfect for young artists.\r\n🎨 Guided Design (3 hrs) — Vaihere sketches your chosen idea, and you bring it to life with paint.\r\n🎨 Create Your Own (4 hrs) — Design and paint your own pareo from scratch.\r\n\r\nAll materials are included — just bring yourself and your creativity, and leave with a beautiful handmade pareo to take home. A meaningful and memorable activity for both locals and visitors.\r\n\r\nDécouvrez la magie de l''art du pareo avec Vaihere sur la magnifique île de Raiatea. Lors de cet atelier créatif et immersif, vous apprendrez à peindre votre propre pareo en utilisant des couleurs et des motifs qui racontent votre histoire personnelle.\r\n\r\nChoisissez parmi trois niveaux d''expérience :\r\n🎨 Pareo Enfant (3h) — Une activité amusante et créative, idéale pour les jeunes artistes.\r\n🎨 Design Guidé (3h) — Vaihere dessine le motif de votre choix, et vous lui donnez vie avec la peinture.\r\n🎨 Créez Votre Propre Motif (4h) — Concevez et peignez votre pareo de A à Z.\r\n\r\nTout le matériel est fourni — il vous suffit d''apporter votre créativité et vous repartirez avec un pareo unique, réalisé de vos propres mains. Une expérience", "postal_code": null, "shop_handle": "l-ame-du-pareu-by-vai-ohani", "contact_name": "Vaihere Pito", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@vaiohani", "facebook": "https://facebook.com/100046471642888", "instagram": "https://instagram.com/pareubyvaiohani.00"}, "state_region": "Ils Sous Le Vent", "contact_email": "lornapitovai@gmail.com", "contact_phone": "+689 87376668", "business_hours": null, "contact_website": null, "languages_spoken": ["English", "French", "Tahitian"], "cultural_identity": "Tahitian", "short_description": "A hands-on pareu painting experience in Raiatea", "subscription_tier": "featured_plus", "stripe_customer_id": null}', '{"id": "a1fb7177-900d-41f8-b635-c155a16c2e43", "city": "Raiatea", "name": "L''ame Du Pareu by Vai''ohani", "status": "active", "suburb": "Tumaraa", "address": "PK30.9 C/mer - Motu Nuutere", "claimed": false, "country": "French Polynesia", "user_id": null, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771896719956.jpg", "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771896711215.jpg", "claimed_at": null, "claimed_by": null, "created_at": "2025-11-27T07:23:16.513022+00:00", "updated_at": "2026-02-28T02:28:45.479033+00:00", "description": "Discover the magic of pareo art with Vaihere in beautiful Raiatea. In this hands-on workshop, you''ll learn the traditional craft of painting your own pareo, using colours and patterns that reflect your personal story.\r\n\r\nChoose from three experience levels:\r\n🎨 Child''s Pareo (3 