	('db102331-8580-4afa-bb3e-f81bf590580d', 'businesses', 'fcb997d1-fb71-4406-b902-cc5ef3208b03', 'UPDATE', '{"id": "fcb997d1-fb71-4406-b902-cc5ef3208b03", "city": "Bundaberg", "name": "Papua New Guinea Bilums and Baskets", "status": "active", "suburb": null, "address": null, "claimed": true, "country": "Australia", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771898183242.jpg", "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771898190669.png", "claimed_at": "2026-02-26T21:10:10.394806+00:00", "claimed_by": "system", "created_at": "2025-12-17T06:11:26.868237+00:00", "updated_at": "2026-02-28T00:04:58.146465+00:00", "description": "Papua New Guinea Bilums & Baskets, run by CJ & LJ Mountford and based in Bundaberg, Queensland, is a small family business dedicated to sharing authentic Papua New Guinea arts and crafts with the wider community.\r\n\r\nSpecialising in traditional bilums and handwoven baskets, each piece is created using techniques passed down through generations. Bilums are traditionally crafted by women, woven in a variety of shapes and sizes to serve different purposes — from everyday use to baby carrying. The baskets are traditionally crafted by men, reflecting distinct cultural roles and knowledge systems.\r\n\r\nOnly three provinces in Papua New Guinea continue this specific weaving tradition:\r\n\r\nNorth Solomon (Buka)\r\nSouthern Highlands\r\nEastern Highlands\r\n\r\nThese handcrafted pieces are both functional and meaningful, suitable for home décor, shopping, picnics, and baby carrying — while carrying the stories, skills, and heritage of the communities who make them.\r\n\r\nBy supporting Papua New Guinea Bilums & Baskets, you are helping preserve traditional knowledge and create income opportunities for PNG artisans.", "postal_code": null, "shop_handle": "papua-new-guinea-bilums-and-baskets", "contact_name": "Linah Mountford", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/PapuaNewGuineaBilumsAndBasketsCjLjMountford", "instagram": "https://instagram.com/pngbilumsnbaskets"}, "state_region": "Queensland", "contact_email": "Cmford@southernphone.com.au", "contact_phone": "0423 819 378", "business_hours": "10am to 2pm", "contact_website": null, "languages_spoken": ["Pidgin"], "cultural_identity": "Papua New Guinean", "short_description": "CJ & LJ Mountford", "subscription_tier": "featured_plus", "stripe_customer_id": null}', '{"id": "fcb997d1-fb71-4406-b902-cc5ef3208b03", "city": "Bundaberg", "name": "Papua New Guinea Bilums and Baskets", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "Australia", "user_id": null, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771898183242.jpg", "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771898190669.png", "claimed_at": null, "claimed_by": null, "created_at": "2025-12-17T06:11:26.868237+00:00", "updated_at": "2026-02-28T02:28:45.479033+00:00", "description": "Papua New Guinea Bilums & Baskets, run by CJ & LJ Mountford and based in Bundaberg, Queensland, is a small family business dedicated to sharing authentic Papua New Guinea arts and crafts with the wider community.\r\n\r\nSpecialising in traditional bilums and handwoven baskets, each piece is created using techniques passed down through generations. Bilums are traditionally crafted by women, woven in a variety of shapes and sizes to serve different purposes — from everyday use to baby carrying. The baskets are traditionally crafted by men, reflecting distinct cultural roles and knowledge systems.\r\n\r\nOnly three provinces in Papua New Guinea continue this specific weaving tradition:\r\n\r\nNorth Solomon (Buka)\r\nSouthern Highlands\r\nEastern Highlands\r\n\r\nThese handcrafted pieces are both functional and meaningful, suitable for home décor, shopping, picnics, and baby carrying — while carrying the stories, skills, and heritage of the communities who make them.\r\n\r\nBy supporting Papua New Guinea Bilums & Baskets, you are helping preserve traditional knowledge and create income opportunities for PNG artisans.", "postal_code": null, "shop_handle": "papua-new-guinea-bilums-and-baskets", "contact_name": "Linah Mountford", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/PapuaNewGuineaBilumsAndBasketsCjLjMountford", "instagram": "https://instagram.com/pngbilumsnbaskets"}, "state_region": "Queensland", "contact_email": "Cmford@southernphone.com.au", "contact_phone": "0423 819 378", "business_hours": "10am to 2pm", "contact_website": null, "languages_spoken": ["Pidgin"], "cultural_identity": "Papua New Guinean", "short_description": "CJ & LJ Mountford", "subscription_tier": "featured_plus", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-28 02:28:45.479033+00'),
	('162e2c4e-8f58-4102-a9f7-1b604711b975', 'businesses', '464afb2e-e877-458d-a6cb-d0b0e6dd049d', 'UPDATE', '{"id": "464afb2e-e877-458d-a6cb-d0b0e6dd049d", "city": "Christchurch", "name": "The Artwork of Dave Sotogi", "status": "active", "suburb": null, "address": null, "claimed": true, "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771900051547.jpg", "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771900040353.jpg", "claimed_at": "2026-02-26T21:10:10.394806+00:00", "claimed_by": "system", "created_at": "2025-12-12T18:55:24.793631+00:00", "updated_at": "2026-02-28T00:04:58.146465+00:00", "description": "Dave Sotogi is a New Zealand artist whose work brings the heart of the Pacific to life through rich symbolism, cultural depth, and emotive portraiture. His paintings blend modern artistry with ancestral influence, honouring the beauty, strength, and stories of Pacific people.\r\n\r\nFrom striking portraits to symbolic, nature-inspired works, each piece reflects Dave''s deep connection to heritage, identity, and the lands and waters that shape us. His art captures moments of reflection, power, and serenity — inviting viewers to feel, remember, and connect.\r\n\r\nToday, Dave''s work is celebrated in homes across Aotearoa and around the world, available as premium canvas prints and carefully crafted wall art. Every creation carries a story, a spirit, and a sense of belonging — an invitation to experience Pacific art through a contemporary lens.", "postal_code": null, "shop_handle": "the-artwork-of-dave-sotogi", "contact_name": "Dave Sotogi", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/desotogi", "instagram": "https://instagram.com/desotogi"}, "state_region": "South Island", "contact_email": "info@desotogi.co.nz", "contact_