.com/desotogi"}, "state_region": "South Island", "contact_email": "info@desotogi.co.nz", "contact_phone": null, "business_hours": null, "contact_website": "https://desotogi.co.nz", "languages_spoken": ["English"], "cultural_identity": "Māori", "short_description": "Contemporary Maori Art in Motion", "subscription_tier": "featured_plus", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-28 02:28:45.479033+00'),
	('1825bfc1-039f-4ac8-889b-ef7654f80bb9', 'businesses', '7e83ede6-32fa-4019-b2b5-96f71948a0ae', 'UPDATE', '{"id": "7e83ede6-32fa-4019-b2b5-96f71948a0ae", "city": "Australia", "name": "Island Pepe", "status": "active", "suburb": null, "address": null, "claimed": true, "country": "Australia", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771895626761.jpg", "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771895620639.jpg", "claimed_at": "2026-02-26T21:10:10.394806+00:00", "claimed_by": "system", "created_at": "2025-12-15T04:06:38.295736+00:00", "updated_at": "2026-02-28T00:04:58.146465+00:00", "description": "Island Pepe is a family-founded Pasifika brand created with one heartfelt purpose: to preserve and share Pacific language and culture with the next generation.\r\n\r\nRooted in a rich heritage spanning multiple regions of the South Pacific, Island Pepe designs meaningful everyday essentials for babies and children — from clothing and blankets to books and gift sets. Each piece is thoughtfully created to reflect the languages, stories, and traditions passed down by our ancestors, helping parents build lasting cultural connections at home.\r\n\r\nMore than a brand, Island Pepe is a celebration of identity, belonging, and pride. Through respectful collaboration with native speakers and cultural contributors across the Pacific, every design honours authenticity, storytelling, and community.\r\n\r\nIsland Pepe welcomes everyone — Pasifika and non-Pasifika alike — to share in this journey of preserving culture, nurturing identity, and creating memories that children will carry with them for life.", "postal_code": null, "shop_handle": "island-pepe", "contact_name": "Jen Masoe", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@island_pepe", "facebook": "ht