	('c81c73dd-9727-489a-a6f3-aab66407b5d7', 'businesses', '20b54ac1-50ae-4475-89ef-b50569505408', 'UPDATE', '{"id": "20b54ac1-50ae-4475-89ef-b50569505408", "city": "New Zealand", "name": "M.Steven", "status": "active", "suburb": null, "address": null, "claimed": true, "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771896978917.jpeg", "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771896973343.png", "claimed_at": "2026-02-26T21:10:10.394806+00:00", "claimed_by": "system", "created_at": "2025-12-14T08:18:01.195186+00:00", "updated_at": "2026-02-28T00:04:58.146465+00:00", "description": "This artist brings worlds to life through intricate, hand-drawn line work, creating pieces that feel both deeply personal and endlessly expansive. Every artwork is built stroke by stroke — layering symbols, creatures, and flowing forms that invite the viewer to slow down and discover something new each time they look.\r\n\r\nInspired by storytelling, movement, and the complexity of lived experience, their work blends fine detail with raw expression. Using acrylic paint and acrylic pen alongside traditional drawing tools, each piece carries its own rhythm — reflecting patience, discipline, and a deep respect for the creative process.\r\n\r\nBeyond visual art, this same care and creativity extend into handcrafted desserts and custom celebration cakes, including wedding and birthday designs. Whether expressed on paper, canvas, or through edible art, the artist approaches every creation with the same intention: balance, beauty, and meaning.\r\n\r\nThese works are never rushed — they are thoughtfully crafted, allowing ideas to unfold naturally. The result is a body of work that feels alive and grounded, celebrating creativity as a form of meditation, expression, and connection across many mediums.", "postal_code": null, "shop_handle": "m-steven", "contact_name": "Mario Steven", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@m.stevenfjrot23"}, "state_region": "New Zealand", "contact_email": "mariosteven75@yahoo.co.nz", "contact_phone": null, "business_hours": null, "contact_website": null, "languages_spoken": ["Fijian", "Rotuman", "Hindi", "Te Reo Māori (basic)"], "cultural_identity": "Fijian, Italy", "short_description": "Stories in Every Intricate Stroke & Sweet Creation", "subscription_tier": "featured_plus", "stripe_customer_id": null}', '{"id": "20b54ac1-50ae-4475-89ef-b50569505408", "city": "New Zealand", "name": "M.Steven", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "New Zealand", "user_id": null, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771896978917.jpeg", "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771896973343.png", "claimed_at": null, "claimed_by": null, "created_at": "2025-12-14T08:18:01.195186+00:00", "updated_at": "2026-02-28T02:28:45.479033+00:00", "description": "This artist brings worlds to life through intricate, hand-drawn line work, creating pieces that feel both deeply personal and endlessly expansive. Every artwork is built stroke by stroke — layering symbols, creatures, and flowing forms that invite the viewer to slow down and discover something new each time they look.\r\n\r\nInspired by storytelling, movement, and the complexity of lived experience, their work blends fine detail with raw expression. Using acrylic paint and acrylic pen alongside traditional drawing tools, each piece carries its own rhythm — reflecting patience, discipline, and a deep respect for the creative process.\r\n\r\nBeyond visual art, this same care and creativity extend into handcrafted desserts and custom celebration cakes, including wedding and birthday designs. Whether expressed on paper, canvas, or through edible art, the artist approaches every creation with the same intention: balance, beauty, and meaning.\r\n\r\nThese works are never rushed — they are thoughtfully crafted, allowing ideas to unfold naturally. The result is a body of work that feels alive and grounded, celebrating creativity as a form of meditation, expression, and connection across many mediums.", "postal_code": null, "shop_handle": "m-steven", "contact_name": "Mario Steven", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@m.stevenfjrot23"}, "state_region": "New Zealand", "contact_email": "mariosteven75@yahoo.co.nz", "contact_phone": null, "business_hours": null, "contact_website": null, "languages_spoken": ["Fijian", "Rotuman", "Hindi", "Te Reo Māori (basic)"], "cultural_identity": "Fijian, Italy", "short_description": "Stories in Every Intricate Stroke & Sweet Creation", "subscription_tier": "featured_plus", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-02-28 02:28:45.479033+00'),
	('0059895e-d99f-4745-b80d-dea4c2a2c2b5', 'businesses', 'cc214a50-bbbb-4a98-9c77-feb1899c1cae', 'UPDATE', '{"id": "cc214a50-bbbb-4a98-9c77-feb1899c1cae", "city": "Sydney", "name": "Mana Carvings", "status": "active", "suburb": null, "address": null, "claimed": true, "country": "Australia", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771897109293.jpg", "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771897099046.jpg", "claimed_at": "2026-02-26T21:10:10.394806+00:00", "claimed_by": "system", "created_at": "2025-12-12T17:30:11.143898+00:00", "updated_at": "2026-02-28T00:04:58.146465+00:00", "description": "Mana Carvings is a celebration of Cook Islands heritage, storytelling, and craftsmanship. Every piece — whether carved on wood, engraved on drinkware, or designed for the home — carries deep cultural meaning, ancestral patterns, and the spirit of mana.\r\n\r\nEach artwork is handcrafted with precision and intention, transforming traditional motifs into modern, functional pieces that honour identity and connection. From symbolic creatures to intricate Polynesian designs, every creation holds a story — one that reflects culture, legacy, and the pride of the Pacific.\r\n\r\nMade with heart and guided by tradition, Mana Carvings exists to keep our stories alive, one handcrafted design at a time.", "postal_code": null, "shop_handle": "mana-carvings", "contact_name": "Kai Strickland", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/profile.php?id=61577910021592", "instagram": "https://instagram.com/manacarvings"}, "state_region": "NSW", "contact_email": "manacarvings@gmail.com", "contact_phone": null, "business_hours": null, "contact_website": null, "languages_spoken": ["English"], "cultural_identity": "Cook Islands Māori", "short_description": "Handcrafted with Culture, Carved with Mana", "subscription_tier": "featured_plus", "stripe_customer_id": null}', '{"id": "cc214a50-bbbb-4a98-9c77-feb1899c1cae", "city": "Sydney", "name": "Mana Carvings", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "Australia", "user_id": null, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771897109293.jpg", "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771897099046.jpg", "claimed_at": null, "claimed_by": null, "created_at": "2025-12-12T17:30:11.143898+00:00", "updated_at": "2026-02-28T02:28:45.479033+00:00", "description": "Mana Carvings is a celebration of Cook Islands heritage, storytelling, and craftsmanship. Every piece — whether carved on wood, engraved on drinkware, or designed for the home — carries deep cultural meaning, ancestral patterns, and the spirit of mana.\r\n\r\nEach artwork is handcrafted with precision and intention, transforming traditional motifs into modern, functional pieces that honour identity and connection. From symbolic creatures to intricate Polynesian designs, every creation holds a story — one that reflects culture, legacy, and the pride of the Pacific.\r\n\r\nMade with heart and guided by tradition, Mana Carvings exists to keep our stories alive, one handcrafted design at a time.", "postal_code": null, "shop_handle": "mana-carvings", "contact_name": "Kai Strickland", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/profile.php?id=61577910021592", "instagram": "https://instagram.com/manacarvings"}, "state_region": "NSW", "contact_email": "manacarvings@gmail.com", "contact_phone": null, "business_hours": null, "contact_website": null, "languages_spoken": ["English"], "cultural_identity": "Cook Islands Māori", "short_description": "Handcrafted with Culture, Carved with Mana", "subscription_tier": "fea