	('d295e5ce-01d4-43cc-8fe4-c7c25b082fe8', 'businesses', '8e3c51fd-f7f9-4873-a91e-5edafb7b10f0', 'UPDATE', '{"id": "8e3c51fd-f7f9-4873-a91e-5edafb7b10f0", "city": "Auckland", "name": "Inailau", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "New Zealand", "user_id": null, "industry": "Consulting & Professional Services", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771895498319.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771895489445.png", "claimed_at": null, "claimed_by": null, "created_at": "2025-12-14T20:05:18.903507+00:00", "updated_at": "2026-02-28T02:28:45.479033+00:00", "description": "Inailau Business Women''s Network is a community-driven platform dedicated to uplifting, connecting, and empowering Pacific women in business.\r\n\r\nRooted in collaboration and collective growth, Inailau creates safe, supportive spaces where women can share knowledge, build confidence, and grow both personally and professionally. Through networking events, workshops, mentoring sessions, and global connections, Inailau supports Pacific women entrepreneurs at every stage of their journey — from early ideas to established businesses.\r\n\r\nThe network champions visibility, leadership, and economic empowerment, recognising that when Pacific women rise, families, communities, and future generations rise with them.\r\n\r\nMore than a business network, Inailau is a movement grounded in culture, connection, and purpose — bringing Pacific women together to reflect, realign, and rise together.", "postal_code": null, "proof_links": null, "shop_handle": "inailau", "contact_name": "Jackie Curry", "created_date": "2025-12-14", "social_links": {"facebook": "https://facebook.com/www.facebook.com/profile.php?id=61552017680960", "instagram": "https://instagram.com/inailaubusinessnetwork"}, "state_region": "North Island", "