	('7a9d2f59-d23f-4966-8432-22d16f1f7ef8', 'businesses', '385a01f6-0b40-4abf-a15e-d2bb3bd646eb', 'UPDATE', '{"id": "385a01f6-0b40-4abf-a15e-d2bb3bd646eb", "city": "Orlando", "name": "Pacific Stain", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "United States", "user_id": null, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771897416975.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771897408351.jpg", "claimed_at": null, "claimed_by": null, "created_at": "2025-12-12T08:38:00.862376+00:00", "updated_at": "2026-02-28T02:28:45.479033+00:00", "description": "Pacific Stain is the creative expression of a Samoan family dedicated to honouring and preserving the stories of their ancestors. Through intricate 3D mixed media, pyrography, traditional motifs, and handcrafted wooden creations, they bring Polynesian culture to life — piece by piece.\r\n\r\nEvery artwork carries the mana of Polynesian heritage, blending ancestral knowledge with modern craftsmanship. From carved bowls and decorative panels to symbolic designs inspired by tatau and natural elements, Pacific Stain celebrates identity, memory, and the deep connection between people and their roots.\r\n\r\nDriven by a passion to share Polynesian art with the world, Pacific Stain creates pieces that are not only visually striking but spiritually meaningful — art that speaks, remembers, and continues the legacy of Polynesia.", "postal_code": null, "proof_links": null, "shop_handle": "pacific-stain", "contact_name": "Patrick Etu Ah-wong", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@pacificstain", "facebook": "https://facebook.com/pacific.stain", "instagram": "https://instagram.com/pacificstain_official"}, "state_region": "Florida", "contact_email": "pacificstain@aol.com", "contact_phone": null