gi", "instagram": "https://instagram.com/desotogi"}, "state_region": "South Island", "contact_email": "info@desotogi.co.nz", "contact_phone": null, "owner_user_id": null, "business_hours": null, "contact_website": "https://desotogi.co.nz", "languages_spoken": ["English"], "cultural_identity": "New Zealand Māori", "short_description": "Contemporary Maori Art in Motion", "subscription_tier": "featured_plus", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-03-02 19:53:44.541214+00'),
	('6d6f896c-62a7-4335-a354-5c48ce8aed82', 'businesses', '03031b71-e999-40e7-ad4d-efc301d32b2d', 'UPDATE', '{"id": "03031b71-e999-40e7-ad4d-efc301d32b2d", "city": "Auckland", "name": "Aki Store", "status": "active", "suburb": "Manukau", "address": "Unit C3 710 Great South Road, Manukau", "claimed": false, "country": "New Zealand", "user_id": null, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771893804500.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banners/Aki%20Store.png", "claimed_at": null, "claimed_by": null, "created_at": "2025-12-12T18:03:21.327378+00:00", "updated_at": "2026-03-03T05:37:35.636743+00:00", "description": "Our name combines two Māori terms: “ā” and “ki.” Together, they symbolise the idea of possessing direction — guiding ownership of your space with purpose and intention. It reflects our belief that the environments we live and work in should empower us, not just surround us. Through meaningful décor, we help you shape spaces that feel aligned, intentional, and uniquely yours.\r\n\r\nAki Store is proudly owned by VAKA, a 3D printing company committed to igniting a new wave of everyday entrepreneurs. Our team of Māori and Pasifika creatives, born and raised in South Auckland, are driven by a shared mission: to inspire you to become the curator of your own home.\r\n\r\nWe understand that home is more than a physical space. It is a sanctuary for creativity, comfort, and connection.\r\n\r\nOur collection blends cultural aesthetics with modern minimalism, allowing each piece to harmonise effortlessly with any interior style. Every design is created to transform your environment into a reflection of who you are — grounded in culture, elevated through simplicity.\r\n\r\nOur goal is simple: to empower you to embrace your individuality and reimagine your living and working spaces.\r\n\r\nJoin us on this journey of self-expression and transformation. Let us help you elevate your space with pieces designed to inspire.", "postal_code": "2104", "proof_links": null, "shop_handle": "aki-store", "contact_name": "Andrea Fua", "created_date": "2025-12-12", "social_links": {"facebook": "https://facebook.com/akistore.co.nz", "instagram": "https://instagram.com/akistore.co.nz"}, "state_region": "Auckland", "contact_email": "support@akistore.co.nz", "contact_phone": null, "owner_user_id": null, "business_hours": "Monday: 9 AM - 5 PM\nTuesday: 9 AM - 5 PM\nWednesday: 9 AM - 5 PM\nThursday: 9 AM - 5 PM\nFriday: 9 AM - 5 PM\n\nSaturday, Sunday and Public Holidays: Closed", "contact_website": "https://akistore.co.nz/", "languages_spoken": ["English"], "cultural_identity": "Samoa", "short_description": "Designed to Inspire, Crafted to Glow", "subscription_tier": "featured_plus", "stripe_customer_id": null}', '{"id": "03031b71-e999-40e7-ad4d-efc301d32b2d", "city": "Auckland", "name": "Aki Store", "status": "active", "suburb": "Manukau", "address": "Unit C3 710 Great South Road, Manukau", "claimed": false, "country": "New Zealand", "user_id": null, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771893804500.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banners/Aki%20Store.png", "claimed_at": null, "claimed_by": null, "created_at": "2025-12-12T18:03:21.327378+00:00", "updated_at": "2026-03-03T05:37:35.636743+00:00", "description": "Our name combines two Māori terms: “ā” and “ki.” Together, they symbolise the idea of possessing direction — guiding ownership of your space with purpose and intention. It reflects our belief that the environments we live and work in should empower us, not just surround us. Through meaningful décor, we help you shape spaces that feel aligned, intentional, and uniquely yours.\r\n\r\nAki Store is proudly owned by VAKA, a 3D printing company committed to igniting a new wave of everyday entrepreneurs. Our team of Māori and Pasifika creatives, born and raised in South Auckland, are driven by a shared mission: to inspire you to become the curator of your own home.\r\n\r\nWe understand that home is more than a physical space. It is a sanctuary for creativity, comfort, and connection.\r\n\r\nOur collection blends cultural aesthetics with modern minimalism, allowing each piece to harmonise effortlessly with any interior style. Every design is created to transform your environment into a reflection of who you are — grounded in culture, elevated through simplicity.\r\n\r\nOur goal is simple: to empower you to embrace your individuality and reimagine your living and working spaces.\r\n\r\nJoin us on this journey of self-expression and transformation. Let us help you elevate your space with pieces designed to inspire.", "postal_code": "2104", "proof_links": null, "shop_handle": "aki-store", "contact_name": "Andrea Fua", "created_date": "2025-12-12", "social_links": {"facebook": "https://facebook.com/akistore.co.nz", "instagram": "https://instagram.com/akistore.co.nz"}, "state_region": "Auckland", "contact_email": "support@akistore.co.nz", "contact_phone": null, "owner_user_id": null, "business_hours": "Monday: 9 AM - 5 PM\nTuesday: 9 AM - 5 PM\nWednesday: 9 AM - 5 PM\nThursday: 9 AM - 5 PM\nFriday: 9 AM - 5 PM\n\nSaturday, Sunday and Public Holidays: Closed", "contact_website": "https://akistore.co.nz/", "languages_spoken": ["English"], "cultural_identity": "Samoa", "short_description": "Designed to Inspire, Crafted to Glow", "subscription_tier": "featured_plus", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-03-03 05:37:35.636743+00'),
	('38976e94-2c51-4db7-b886-b93bef573567', 'businesses', '525e84f2-66d3-4a1b-a896-dd64d01ec033', 'UPDATE', '{"id": "525e84f2-66d3-4a1b-a896-dd64d01ec033", "city": "New Zealand", "name": "Tuhono Design", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "New Zealand", "user_id": null, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771899400009.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771899392291.jpg", "claimed_at": null, "claimed_by": null, "created_at": "2025-12-12T18:28:30.64805+00:00", "updated_at": "2026-02-28T02:28:45.479033+00:00", "description": "Tuhono Design was created by Jay and Sarah, a proud Maori whanau dedicated to revitalising te reo Maori in everyday spaces. Inspired by their own journeys of reconnecting with their heritage, they design bilingual planners, calendars, prints, and educational resources that make Maori language and culture accessible, beautiful, and part of daily life. Their kaupapa is built on whanaungatanga, kotahitanga, and uplifting the next generation so they can grow up confident in their identity. Through thoughtfully crafted products rooted in meaning and connection, Tuhono Design invites whanau everywhere to learn, speak, and live te reo Maori with pride.", "postal_code": null, "proof_links": null, "shop_handle": "tuhono-design", "contact_name": "Sarah", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@tuhonodesign", "facebook": "https://facebook.com/Tuhonodesign"}, "state_region": "New Zealand", "contact_email": "kiaora@tuhonodesign.com", "contact_phone": null, "owner_user_id": null, "business_hours": null, "contact_website": "https://tuhonodesign.com", "languages_spoken": ["Te Reo Māori"], "cultural_identity": "Maori", "short_description": "Bilingual Maori Resources to Inspire, Learn & Connect", "s