n", "name": "NEST Interiors", "status": "active", "suburb": null, "address": "593 Te Rapa Road, Level 1, Mayfair Business Centre", "claimed": false, "country": "New Zealand", "user_id": null, "industry": "Consulting & Professional Services", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771897237247.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771897231812.jpg", "claimed_at": null, "claimed_by": null, "created_at": "2025-12-11T22:05:48.010308+00:00", "updated_at": "2026-03-02T19:54:08.169786+00:00", "description": "We are dreamers, doers, and collaborators who bring bold ideas to life through purposeful design.\r\n\r\nOur Pacific roots remind us that creativity is a gift, excellence is a responsibility, and progress is something we achieve together. We design with heart, we act with intention, and we always move forward as one — with our clients, our teams, and the people we serve.", "postal_code": "3200", "proof_links": null, "shop_handle": "nest-interiors", "contact_name": "Tonga Robertson", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/NESTinteriorsanddesign", "linkedin": "https://linkedin.com/company/nest-interiors-design", "instagram": "https://instagram.com/nest_interiors_nz"}, "state_region": "Hamilton", "contact_email": "studio@nestinteriors.co.nz", "contact_phone": "021 167 1027", "owner_user_id": null, "business_hours": null, "contact_website": "https://nestinteriors.co.nz", "languages_spoken": ["English"], "cultural_identity": "Tonga", "short_description": "Full Interior Design Service", "subscription_tier": "featured_plus", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-03-02 19:54:08.169786+00'),
	('62c5f878-ca56-47cc-9fa9-305ec7c7ae42', 'businesses', 'c9fc68e6-da63-4def-9d0b-13991ddc3926', 'UPDATE', '{"id": "c9fc68e6-da63-4def-9d0b-13991ddc3926", "city": "Auckland", "name": "Te Mauri o te Makawe", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "New Zealand", "user_id": null, "industry": "Health & Wellness", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771899866021.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771899858016.jpg", "claimed_at": null, "claimed_by": null, "created_at": "2025-12-01T08:40:49.119488+00:00", "updated_at": "2026-02-28T02:28:45.479033+00:00", "description": "Nuku te manaaki, nuku te manaaki, ka ora ai te iwi.\r\nWith your support and my support, our community will thrive.\r\n\r\nMy name is Iesha Te-Iho. I am a qualified barber, creative, and proud Waiuku local. My journey here was not a straight line — but every challenge sharpened my purpose and showed me that barbering could be more than a trade. It could be a doorway to healing.\r\n\r\nFrom that understanding, Te Mauri o te Makawe: The Koha Manawa was born.\r\n\r\nThis kaupapa delivers professional grooming and braiding through a mobile service, reaching people and places often overlooked — hospices, spinal units, rehabilitation centres, and rural communities where transport and access are barriers. But this work is about far more than hair.\r\n\r\nThrough whakahoki te tapu, hair is treated with care and respectfully returned to Papatūānuku using traditional tikanga — uku (clay), harakeke (flax), and korowai — protecting the mana of our whānau. Alongside this, kōrero is shared and recorded, preserving the voices, stories, and heartbeat of the community.\r\n\r\nThis kaupapa began with one chair and one set of tools, but the vision is a Waka Wānanga — a collective of skilled creatives travelling across Aotearoa and beyond, delivering workshops, teaching tikanga, uplifting hauora, and restoring identity through creativity.\r\n\r\nAt its heart, this is about legacy. About building something that lasts — not just 100 years, but for generations — by caring for people, culture, and community, together.", "postal_code": null, "proof_links": null, "shop_handle": "te-mauri-o-te-makawe", "contact_name": "Iesha Rawinia", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/TeKohaManawa", "instagram": "https://instagram.com/tekohamanawa"}, "state_region": "Auckland", "contact_email": "hairwithesha@gmail.com", "contact_phone": "02102965229", "owner_user_id": null, "business_hours": null, "contact_website": "https://msha.ke/beauty_withinyou", "languages_spoken": ["English"], "cultural_identity": "Cook Islands Māori, Māori", "short_description": "Any Style. Any Hair. Any Where.", "subscription_tier": "featured_plus", "stripe_customer_id": null}', '{"id": "c9fc68e6-da63-4def-9d0b-13991ddc3926", "city": "Auckland", "name": "Te Mauri o te Makawe", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "New Zealand", "user_id": null, "industry": "Health & Wellness", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771899866021.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771899858016.jpg", "claimed_at": null, "claimed_by": null, "created_at": "2025-12-01T08:40:49.119488+00:00", "updated_at": "2026-03-02T19:55:13.415791+00:00", "description": "Nuku te manaaki, nuku te manaaki, ka ora ai te iwi.\r\nWith your support and my support, our community will thrive.\r\n\r\nMy name is Iesha Te-Iho. I am a qualified barber, creative, and proud Waiuku local. My journey here was not a straight line — but every challenge sharpened my purpose and showed me that barbering could be more than a trade. It could be a doorway to healing.\r\n\r\nFrom that understanding, Te Mauri o te Makawe: The Koha Manawa was born.\r\n\r\nThis kaupapa delivers professional grooming and braiding through a mobile service, reaching people and places often overlooked — hospices, spinal units, rehabilitation centres, and rural communities where transport and access are barriers. But this work is about far more than hair.\r\n\r\nThrough whakahoki te tapu, hair is treated with care and respectfully returned to Papatūānuku using traditional tikanga — uku (clay), harakeke (flax), and korowai — protecting the mana of our whānau. Alongside this, kōrero is shared and recorded, preserving the voices, stories, and heartbeat of the community.\r\n\r\nThis kaupapa began with one chair and one set of tools, but the vision is a Waka Wānanga — a collective of skilled creatives travelling across Aotearoa and beyond, delivering workshops, teaching tikanga, uplifting hauora, and restoring identity through creativity.\r\n\r\nAt its heart, this is about legacy. About building something that lasts — not just 100 years, but for generations — by caring for people, culture, and community, together.", "postal_code": null, "proof_links": null, "shop_handle": "te-mauri-o-te-makawe", "contact_name": "Iesha Rawinia", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/TeKohaManawa", "instagram": "https://instagram.com/tekohamanawa"}, "state_region": "Auckland", "contact_email": "hairwithesha@gmail.com", "contact_phone": "02102965229", "owner_user_id": null, "business_hours": null, "contact_website": "https://msha.ke/beauty_withinyou", "languages_spoken": ["English"], "cultural_identity": "Cook Islands, New Zealand Māori", "short_description": "Any Style. Any Hair. Any Where.", "subscription_tier": "featured_plus", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-03-02 19:55:13.415791+00'),
	('b99bd1dd-b571-4e33-b7fe-3336ff9ddee7', 'businesses', '09938336-c963-488a-9c0f-a387893bc13a', 'UPDATE', '{"id": "09938336-c963-488a-9c0f-a387893bc13a", "city": "Auckland", "name": "Angela Malakai | The HONESTea", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "New Zealand", "user_id": null, "industry": "Consulting & Professional Services", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771894190853.png", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771894004538.jpg", "claimed_at": null, "claimed_by": null, "created_at": "2025-12-15T02:51:48.311365+00:00", "updated_at": "2026-02-28T02:28:45.479033+00:00", "description": "About The HONESTea\r\n\r\nThe HONESTea is where real conversations finally happen.\r\n\r\nHosted by Angela Malakai — Speaker, Author, and Holistic Trauma Coach — this podcast is built on truth, voice, and lived experience.\r\n\r\nThis is more than a podcast; it''s the foundation of a speaking platform rooted in honesty, healing, and authentic human connection.\r\n\r\nWe pour the tea that matters — the trauma tea, the growth tea, the spiritual tea, the identity tea, and everything in between.\r\n\r\nIt''s a space for cycle-breakers, leaders, deep feelers, and those who know they were made for more.\r\n\r\n🎙 HONESTea Podcast — Available to watch on YouTube.", "postal_code": null, "proof_links": null, "shop_handle": "angela-malakai-the-honestea", "contact_name": "Angela (Ange) Malakai", "created_date": "2026-02-26", "social_links": {"youtube": "https://youtube.com/@angelamalakai", "facebook": "https://facebook.com/TheHONESTea", "linkedin": "https://linkedin.com/in/angela-malakai", "instagram": "https://instagram.com/thehonestea_podcast"}, "state_region": "North Island", "contact_email": "info@malakailife.com", "contact_phone": "021 091 06467", "owner_user_id": null, "business_hours": null