	('54fd2832-b51d-4a84-b272-c163dfaae796', 'businesses', '03031b71-e999-40e7-ad4d-efc301d32b2d', 'UPDATE', '{"id": "03031b71-e999-40e7-ad4d-efc301d32b2d", "city": "Auckland", "name": "Aki Store", "status": "active", "suburb": "Manukau", "address": "Unit C3 710 Great South Road, Manukau", "claimed": false, "country": "New Zealand", "user_id": null, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771893804500.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banners/Aki%20Store.png", "claimed_at": null, "claimed_by": null, "created_at": "2025-12-12T18:03:21.327378+00:00", "updated_at": "2026-03-03T05:37:35.636743+00:00", "description": "Our name combines two Māori terms: “ā” and “ki.” Together, they symbolise the idea of possessing direction — guiding ownership of your space with purpose and intention. It reflects our belief that the environments we live and work in should empower us, not just surround us. Through meaningful décor, we help you shape spaces that feel aligned, intentional, and uniquely yours.\r\n\r\nAki Store is proudly owned by VAKA, a 3D printing company committed to igniting a new wave of everyday entrepreneurs. Our team of Māori and Pasifika creatives, born and raised in South Auckland, are driven by a shared mission: to inspire you to become the curator of your own home.\r\n\r\nWe understand that home is more than a physical space. It is a sanctuary for creativity, comfort, and connection.\r\n\r\nOur collection blends cultural aesthetics with modern minimalism, allowing each piece to harmonise effortlessly with any interior style. Every design is created to transform your environment into a reflection of who you are — grounded in culture, elevated through simplicity.\r\n\r\nOur goal is simple: to empower you to embrace your individuality and reimagine your living and working spaces.\r\n\r\nJoin us o