	('db9c4622-76a5-4823-9b81-49e75874176e', 'businesses', 'c4530355-c5fb-47fb-ac89-07574831f9e7', 'UPDATE', '{"id": "c4530355-c5fb-47fb-ac89-07574831f9e7", "city": "Naples", "name": "Avalon Wellness and Performance", "status": "active", "suburb": "Naples", "address": "10661 Airport Pulling Road N #10, Naples FL 34109", "claimed": false, "country": "United States", "user_id": null, "industry": "Health & Wellness", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771894449390.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771894442071.png", "claimed_at": null, "claimed_by": null, "created_at": "2026-01-08T00:54:56.222151+00:00", "updated_at": "2026-02-28T00:04:58.146465+00:00", "description": "Avalon Wellness & Performance is a holistic health clinic dedicated to helping people move better, feel stronger, and live with greater ease and confidence. Through personalised, hands-on care, Avalon supports recovery, long-term wellness, and peak physical performance.\r\n\r\nThe clinic takes an integrative approach to treatment, combining techniques such as Active Release Technique (ART), Osteopathic Manual Therapy, Cranial Sacral Therapy, and therapeutic massage. Each session is tailored to the individual, addressing not only symptoms but the underlying causes of pain, tension, and movement restrictions.\r\n\r\nAt Avalon, the body is viewed as a connected system. Treatment plans are developed through careful assessment and collaboration, ensuring care aligns with each client''s goals — whether that''s injury recovery, pain management, improved mobility, or enhanced athletic performance.\r\n\r\nAvalon Wellness & Performance provides a calm, professional environment where expertise and compassion come together. From deep tissue and mobility-focused work to gentle therapies that support nervous system balance and stress relief, every session is delivered with intention and care.\r\n\r\nMore than treatment, Avalon empowers clients with the tools, support, and knowledge needed to maintain their wellbeing long after their session ends — helping them move forward feeling stronger, balanced, and supported.", "postal_code": "34109", "proof_links": null, "shop_handle": "avalon-wellness-and-performance", "contact_name": "Avalon Wellness Performance", "created_date": "2026-02-26", "social_links": {"twitter": "https://twitter.com/WellnessAvalon", "facebook": "https://facebook.com/avalonwellnessandperformance", "instagram": "https://instagram.com/avalonwellnessandperformance"}, "state_region": "FL", "contact_email": "avalonwellnessperformance@gmail.com", "contact_phone": "+632394274697", "owner_user_id": null, "business_hours": null, "contact_website": "https://www.avalonwellnessandperformance.com/", "languages_spoken": ["English"], "cultural_identity": null, "short_description": "Move Better. Feel Better. Live Better.", "subscription_tier": "featured_plus", "stripe_customer_id": null}', '{"id": "c4530355-c5fb-47fb-ac89-07574831f9e7", "city": "Naples", "name": "Avalon Wellness and Performance", "status": "active", "suburb": "Naples", "address": "10661 Airport Pulling Road N #10, Naples FL 34109", "claimed": false, "country": "United States", "user_id": null, "industry": "Health & Wellness", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771894449390.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771894442071.png", "claimed_at": null, "claimed_by": null, "created_at": "2026-01-08T00:54:56.222151+00:00", "updated_at": "2026-03-02T19:55:13.415791+00:00", "description": "Avalon Wellness & Performance is a holistic health clinic dedicated to helping people move better, feel stronger, and live with greater ease and confidence. Through personalised, hands-on care, Avalon supports recovery, long-t