	('69dedf62-e33d-4b1f-bba1-d71bf7f77098', 'businesses', 'ce4a274e-c94d-475f-988e-23741f9e58c5', 'UPDATE', '{"id": "ce4a274e-c94d-475f-988e-23741f9e58c5", "city": "Auckland", "name": "Rebalance Qi Acupuncture", "status": "active", "suburb": "Papatoetoe", "address": "34 Great South Road", "claimed": false, "country": "New Zealand", "user_id": null, "industry": "Health & Wellness", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771898477407.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771898465847.png", "claimed_at": null, "claimed_by": null, "created_at": "2025-12-01T02:43:36.084993+00:00", "updated_at": "2026-02-28T02:28:45.479033+00:00", "description": "Rebalance Qi Acupuncture is a calming and supportive clinic\r\nbased in Papatoetoe, South Auckland. Our mission is to help\r\nindividuals restore balance and feel their best through the natural\r\nhealing principles of traditional Chinese medicine. We believe\r\nwellness is not one-size-fits-all that''s why each treatment is\r\nthoughtfully tailored to suit your individual needs. We offer\r\npersonalized acupuncture sessions, cupping therapy, and holistic\r\ncare in a space designed to help you feel grounded, relaxed, and\r\nheard. As an ACC-registered provider, we also make acupuncture\r\nmore accessible for those recovering from injuries. At Rebalance\r\nQi, your health and well-being are our top priority. We''re here to\r\nsupport you on your journey toward lasting relief and renewed\r\nenergy.", "postal_code": "2025", "proof_links": null, "shop_handle": "rebalance-qi-acupuncture", "contact_name": "Sandy Suriyachaik", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/rebalanceqi.acupuncture", "instagram": "https://instagram.com/rebalanceqi.acupuncture"}, "state_region": "Auckland", "contact_email": "info@rebalanceqi.co.nz", "contact_phone": "022 388