	('42691a15-e68d-4c0c-aca1-32ec8b820e59', 'businesses', '6bd8fad1-df64-4c3c-8cd8-7cb63be2926a', 'UPDATE', '{"id": "6bd8fad1-df64-4c3c-8cd8-7cb63be2926a", "city": "Auckland", "name": "Anarra Alofa Est.2020", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "New Zealand", "user_id": null, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771893925293.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771893916527.jpg", "claimed_at": null, "claimed_by": null, "created_at": "2026-01-06T22:28:48.12743+00:00", "updated_at": "2026-03-02T19:53:31.037648+00:00", "description": "Talofa lava, my name is Sharon, co-founder and owner of Anarra Alofa.\r\nMy creative journey began in 2020, when I first set my heart on making handcrafted board signs. Shortly after, I welcomed my first child — my son — and, like many mothers, I placed that dream on hold. Even so, the desire to create never left me.\r\n\r\nOver time, my inspiration naturally returned through Sei — the floral ear pieces deeply loved and worn by Samoan women. In our culture, Sei are more than adornment; they are expressions of beauty, identity, and pride. The idea of creating them stayed with me, quietly growing until the time felt right.\r\n\r\nAt the beginning of last year, I finally took the step to bring Anarra Alofa to life. Starting small and working with minimal materials, I began handcrafting Sei with love, care, and intention. What started as a simple creative outlet has grown into a heartfelt small business rooted in culture, creativity, and passion.\r\n\r\nAnarra Alofa is a reflection of my journey — as a mother, a Samoan woman, and a creator — and a celebration of the beauty we carry and share through our culture.", "postal_code": null, "proof_links": null, "shop_handle": "anarra-alofa-est-2020", "contact_name": "Sharon Naseri", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@anarraalofa2020", "facebook": "https://facebook.com/silaumea.ieru", "instagram": "https://instagram.com/anarraalofa2125"}, "state_region": null, "contact_email": "sharonnaseri@gmail.com", "contact_phone": "+64212170344", "owner_user_id": null, "business_hours": "Monday-Friday 9am-5pm", "contact_website": null, "languages_spoken": ["English"], "cultural_identity": "Samoa", "short_description": "Elevate your style with beautifully crafted Sei''s for every occasion at Anarra Alofa.", "subscription_tier": "featured_plus", "stripe_customer_id": null}', '{"id": "6bd8fad1-df64-4c3c-8cd8-7cb63be2926a", "city": "Auckland", "name": "Anarra Alofa Est.2020", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "New Zealand", "user_id": null, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771893925293.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banners/anara.png", "claimed_at": null, "claimed_by": null, "created_at": "2026-01-06T22:28:48.12743+00:00", "updated_at": "2026-03-03T05:10:33.552+00:00", "description": "Talofa lava, my name is Sharon, co-founder and owner of Anarra Alofa.\r\nMy creative journey began in 2020, when I first set my heart on making handcrafted board signs. Shortly after, I welcomed my first child — my son — and, like many mothers, I placed that dream on hold. Even so, the desire to create never left me.\r\n\r\nOver time, my inspiration naturally returned through Sei — the floral ear pieces deeply loved and worn by Samoan women. In our culture, Sei are more than adornment; they are expressions of beauty, identity, and pride. The idea of creating them stayed with me, quietly growing until the time felt right.\r\n\r\nAt the beginning of last year, I finally took the step to bring Anarra Alofa to life. Starting small and working with minimal materials, I began handcrafting Sei with love, care, and intention. What started as a simple creative outlet has grown into a heartfelt small business rooted in culture, creativity, and passion.\r\n\r\nAnarra Alofa is a reflection of my journey — as a mother, a Samoan woman, and a creator — and a celebration of the beauty we carry and share through our culture.", "postal_code": null, "proof_links": null, "shop_handle": "anarra-alofa-est-2020", "contact_name": "Sharon Naseri", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@anarraalofa2020", "facebook": "https://facebook.com/silaumea.ieru", "instagram": "https://instagram.com/anarraalofa2125"}, "state_region": null, "contact_email": "sharonnaseri@gmail.com", "contact_phone": "+64212170344", "owner_user_id": null, "business_hours": "Monday-Friday 9am-5pm", "contact_website": null, "languages_spoken": ["English"], "cultural_identity": "Samoa", "short_description": "Elevate your style with beautifully crafted Sei''s for every occasion at Anarra Alofa.", "subscription_tier": "featured_plus", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-03-03 05:10:33.552+00'),
	('d04028ae-532e-42b6-9ab2-f538925f2f4d', 'businesses', 'ebbc9e74-75cc-4b8f-808a-4798ab5e1afd', 'UPDATE', '{"id": "ebbc9e74-75cc-4b8f-808a-4798ab5e1afd", "city": "Apia", "name": "NAUNA", "status": "active", "suburb": null, "address": "Fugalei  (Vaai Compound)", "claimed": false, "country": "Samoa", "user_id": null, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771885311143.webp", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771885298227.jpg", "claimed_at": null, "claimed_by": null, "created_at": "2026-01-05T03:06:07.035478+00:00", "updated_at": "2026-03-02T19:53:31.037648+00:00", "description": "Nauna is a vibrant creative and cultural brand based in Apia, Samoa, celebrated for its authentic elei fashion and Pacific-inspired designs. Rooted in Samoan artistry and storytelling, Nauna showcases clothing and creative expressions that reflect contemporary Pacific identity while honouring traditional patterns and aesthetics.\r\n\r\nKnown for its bold, beautiful pieces and strong community engagement, Nauna has built a dedicated following by blending island heritage with modern style, making traditional influences accessible and wearable for everyday life. Whether through fashion, creative content, or collaborations with local artists, Nauna is a cultural voice that elevates Pacific design and celebrates Samoan creative excellence.", "postal_code": null, "proof_links": null, "shop_handle": "nauna", "contact_name": "Adriana Kamu", "created_date": "2026-01-05", "social_links": {"facebook": "https://facebook.com/profile.php?id=61564135313244", "instagram": "https://instagram.com/nauna.samoa"}, "state_region": "Samoa", "contact_email": "nauna_@outlook.com", "contact_phone": "+6857539518", "owner_user_id": null, "business_hours": "Mon/Friday: 8am - 5pm\nSaturday: 8am-2pm", "contact_website": "https://linktr.ee/nauna_"