ookies", "contact_name": "Jasmin Benioni", "created_date": "2025-11-27", "social_links": {"tiktok": "", "facebook": "", "linkedin": "https://www.linkedin.com/company/111610220", "instagram": ""}, "state_region": null, "contact_email": "saasycookies@gmail.com", "contact_phone": null, "owner_user_id": null, "business_hours": null, "contact_website": "https://www.saasycookies.com", "languages_spoken": ["English", "French"], "cultural_identity": "Cook Islands, French Polynesia", "short_description": "Digital products for freelancers, creators, and small businesses", "subscription_tier": "featured_plus", "stripe_customer_id": null}', '{"id": "1ceaf4d4-8a5e-4f25-b75f-43a05cd656fb", "city": "Auckland", "name": "SaaSy Cookies", "status": "active", "suburb": null, "address": null, "claimed": true, "country": "New Zealand", "user_id": "d5cf35f3-321d-4fb1-9a68-9e16cab473e4", "industry": "Digital Media & Technology", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/saasycookies_gmail_com_logo_1772177789442.webp", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banners/SaaSy Cookies.png", "claimed_at": "2026-02-26T22:33:27.633401+00:00", "claimed_by": "system", "created_at": "2025-11-27T05:54:58.04014+00:00", "updated_at": "2026-03-03T05:45:36.055941+00:00", "description": "SaaSy Cookies is a digital product studio and infrastructure partner for founders, creators, and growing businesses.\n\nAs the exclusive technology partner behind Pacific Market, we design and manage the systems that power visibility, credibility, and growth for Pacific-owned businesses across the platform.\n\nWe don’t just build websites.\nWe build managed website and funnel infrastructure — combining clean design, automation, AI tools, and scalable systems that help founders operate professionally and grow sustainably.\n\nOur work includes:\n\n• Custom website design and development\n• Funnel stra