	('cbe2efa0-888c-4e6b-8890-aead5a46b16f', 'businesses', '7e83ede6-32fa-4019-b2b5-96f71948a0ae', 'UPDATE', '{"id": "7e83ede6-32fa-4019-b2b5-96f71948a0ae", "city": "Australia", "name": "Island Pepe", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "Australia", "user_id": null, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771895626761.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banners/Island Pepe.jpg", "claimed_at": null, "claimed_by": null, "created_at": "2025-12-15T04:06:38.295736+00:00", "updated_at": "2026-03-03T05:45:36.055941+00:00", "description": "Island Pepe is a family-founded Pasifika brand created with one heartfelt purpose: to preserve and share Pacific language and culture with the next generation.\r\n\r\nRooted in a rich heritage spanning multiple regions of the South Pacific, Island Pepe designs meaningful everyday essentials for babies and children — from clothing and blankets to books and gift sets. Each piece is thoughtfully created to reflect the languages, stories, and traditions passed down by our ancestors, helping parents build lasting cultural connections at home.\r\n\r\nMore than a brand, Island Pepe is a celebration of identity, belonging, and pride. Through respectful collaboration with native speakers and cultural contributors across the Pacific, every design honours authenticity, storytelling, and community.\r\n\r\nIsland Pepe welcomes everyone — Pasifika and non-Pasifika alike — to share in this journey of preserving culture, nurturing identity, and creating memories that children will carry with them for life.", "postal_code": null, "proof_links": null, "shop_handle": "island-pepe", "contact_name": "Jen Masoe", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@island_pepe", "facebook": "https://facebook.com/islandpepe", "instagram": "https://instagram.com/island_pepe"}, "state_region": "Australia", "contact_email": "team.islandpepe@gmail.com", "contact_phone": null, "owner_user_id": null, "business_hours": null, "contact_website": "https://www.islandpepe.com", "languages_spoken": ["English"], "cultural_identity": "Samoa, Tonga", "short_description": "Passing Culture to the Next Generation", "subscription_tier": "featured_plus", "stripe_customer_id": null}', '{"id": "7e83ede6-32fa-4019-b2b5-96f71948a0ae", "city": "Australia", "name": "Island Pepe", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "Australia", "user_id": null, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771895626761.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banners/Island Pepe.jpg", "claimed_at": null, "claimed_by": null, "created_at": "2025-12-15T04:06:38.295736+00:00", "updated_at": "2026-03-03T05:49:24.552612+00:00", "description": "Island Pepe is a family-founded Pasifika brand created with one heartfelt purpose: to preserve and share Pacific language and culture with the next generation.\r\n\r\nRooted in a rich heritage spanning multiple regions of the South Pacific, Island Pepe designs meaningful everyday essentials for babies and children — from clothing and blankets to books and gift sets. Each piece is thoughtfully created to reflect the languages, stories, and traditions passed down by our ancestors, helping parents build lasting cultural connections at home.\r\n\r\nMore than a brand, Island Pepe is a celebration of identity, belonging, and pride. Through respectful collaboration with native speakers and cultural contributors across the Pacific, every design honours authenticity, storytelling, and community.\r\n\r\nIsland Pepe welcomes everyone — Pasifika and non-Pasifika alike — to share in this journey of preserving culture, nurturing identity, and creating memories that children will carry with them for life.", "postal_code": null, "proof_links": null, "shop_handle": "island-pepe", "contact_name": "Jen Masoe", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@island_pepe", "facebook": "https://facebook.com/islandpepe", "instagram": "https://instagram.com/island_pepe"}, "state_region": "Australia", "contact_email": "team.islandpepe@gmail.com", "contact_phone": null, "owner_user_id": null, "business_hours": null, "contact_website": "https://www.islandpepe.com", "languages_spoken": ["English"], "cultural_identity": "Samoa, Tonga", "short_description": "Passing Culture to the Next Generation", "subscription_tier": "featured_plus", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-03-03 05:49:24.552612+00'),
	('ea56bffd-09ed-4e78-b317-0c6216ca106e', 'businesses', '20b54ac1-50ae-4475-89ef-b50569505408', 'UPDATE', '{"id": "20b54ac1-50ae-4475-89ef-b50569505408", "city": "New Zealand", "name": "M.Steven", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "New Zealand", "user_id": null, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771896978917.jpeg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771896973343.png", "claimed_at": null, "claimed_by": null, "created_at": "2025-12-14T08:18:01.195186+00:00", "updated_at": "2026-03-02T19:55:13.415791+00:00", "description": "This artist brings worlds to life through intricate, hand-drawn line work, creating pieces that feel both deeply personal and endlessly expansive. Every artwork is built stroke by stroke — layering symbols, creatures, and flowing forms that invite the viewer to slow down and discover something new each time they look.\r\n\r\nInspired by storytelling, movement, and the complexity of lived experience, their work blends fine detail with raw expression. Using acrylic paint and acrylic pen alongside traditional drawing tools, each piece carries its own rhythm — reflecting patience, discipline, and a deep respect for the creative process.\r\n\r\nBeyond visual art, this same care and creativity extend into handcrafted desserts and custom celebration cakes, including wedding and birthday designs. Whether expressed on paper, canvas, or through edible art, the artist approaches every creation with the same intention: balance, beauty, and meaning.\r\n\r\nThese works are never rushed — they are thoughtfully crafted, allowing ideas to unfold naturally. The result is a body of work that feels alive and grounded, celebrating creativity as a form of meditation, expression, and connection across many mediums.", "postal_code": null, "proof