	('9076ca47-14f3-4ca0-bad7-406e464c6ef9', 'businesses', '464afb2e-e877-458d-a6cb-d0b0e6dd049d', 'UPDATE', '{"id": "464afb2e-e877-458d-a6cb-d0b0e6dd049d", "city": "Christchurch", "name": "The Artwork of Dave Sotogi", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "New Zealand", "user_id": null, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771900051547.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771900040353.jpg", "claimed_at": null, "claimed_by": null, "created_at": "2025-12-12T18:55:24.793631+00:00", "updated_at": "2026-03-02T19:53:44.541214+00:00", "description": "Dave Sotogi is a New Zealand artist whose work brings the heart of the Pacific to life through rich symbolism, cultural depth, and emotive portraiture. His paintings blend modern artistry with ancestral influence, honouring the beauty, strength, and stories of Pacific people.\r\n\r\nFrom striking portraits to symbolic, nature-inspired works, each piece reflects Dave''s deep connection to heritage, identity, and the lands and waters that shape us. His art captures moments of reflection, power, and serenity — inviting viewers to feel, remember, and connect.\r\n\r\nToday, Dave''s work is celebrated in homes across Aotearoa and around the world, available as premium canvas prints and carefully crafted wall art. Every creation carries a story, a spirit, and a sense of belonging — an invitation to experience Pacific art through a contemporary lens.", "postal_code": null, "proof_links": null, "shop_handle": "the-artwork-of-dave-sotogi", "contact_name": "Dave Sotogi", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/desotogi", "instagram": "https://instagram.com/desotogi"}, "state_region": "South Island", "contact_email": "info@desotogi.co.nz", "contact_phone": null, "owner_user_i