	('c3e55c09-a06e-4d28-9bf7-7ab6aeae1e20', 'businesses', 'cc214a50-bbbb-4a98-9c77-feb1899c1cae', 'UPDATE', '{"id": "cc214a50-bbbb-4a98-9c77-feb1899c1cae", "city": "Sydney", "name": "Mana Carvings", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "Australia", "user_id": null, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771897109293.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banner_1771897099046.jpg", "claimed_at": null, "claimed_by": null, "created_at": "2025-12-12T17:30:11.143898+00:00", "updated_at": "2026-03-02T19:52:16.520711+00:00", "description": "Mana Carvings is a celebration of Cook Islands heritage, storytelling, and craftsmanship. Every piece — whether carved on wood, engraved on drinkware, or designed for the home — carries deep cultural meaning, ancestral patterns, and the spirit of mana.\r\n\r\nEach artwork is handcrafted with precision and intention, transforming traditional motifs into modern, functional pieces that honour identity and connection. From symbolic creatures to intricate Polynesian designs, every creation holds a story — one that reflects culture, legacy, and the pride of the Pacific.\r\n\r\nMade with heart and guided by tradition, Mana Carvings exists to keep our stories alive, one handcrafted design at a time.", "postal_code": null, "proof_links": null, "shop_handle": "mana-carvings", "contact_name": "Kai Strickland", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/profile.php?id=61577910021592", "instagram": "https://instagram.com/manacarvings"}, "state_region": "NSW", "contact_email": "manacarvings@gmail.com", "contact_phone": null, "owner_user_id": null, "business_hours": null, "contact_website": null, "languages_spoken": ["English"], "cultural_identity": "Cook Islands", "short_description": "Handcrafted wit