aulomauia", "facebook": "https://facebook.com/profile.php?id=100060918442844", "instagram": "https://instagram.com/paulomauia_tattoo"}, "state_region": null, "contact_email": "paulomauia3@gmail.com", "contact_phone": null, "owner_user_id": null, "business_hours": "24hrs", "contact_website": null, "languages_spoken": ["English"], "cultural_identity": "Samoa", "short_description": "Arts Finest", "subscription_tier": "featured_plus", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-03-03 05:58:53.043436+00'),
