	('8f4ec37e-c23b-46f4-847c-ab9ab2de22ef', 'businesses', '6bd8fad1-df64-4c3c-8cd8-7cb63be2926a', 'UPDATE', '{"id": "6bd8fad1-df64-4c3c-8cd8-7cb63be2926a", "city": "Auckland", "name": "Anarra Alofa Est.2020", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "New Zealand", "user_id": null, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771893925293.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banners/Anarra%20Alofa.png", "claimed_at": null, "claimed_by": null, "created_at": "2026-01-06T22:28:48.12743+00:00", "updated_at": "2026-03-03T05:58:53.043436+00:00", "description": "Talofa lava, my name is Sharon, co-founder and owner of Anarra Alofa.\r\nMy creative journey began in 2020, when I first set my heart on making handcrafted board signs. Shortly after, I welcomed my first child — my son — and, like many mothers, I placed that dream on hold. Even so, the desire to create never left me.\r\n\r\nOver time, my inspiration naturally returned through Sei — the floral ear pieces deeply loved and worn by Samoan women. In our culture, Sei are more than adornment; they are expressions of beauty, identity, and pride. The idea of creating them stayed with me, quietly growing until the time felt right.\r\n\r\nAt the beginning of last year, I finally took the step to bring Anarra Alofa to life. Starting small and working with minimal materials, I began handcrafting Sei with love, care, and intention. What started as a simple creative outlet has grown into a heartfelt small business rooted in culture, creativity, and passion.\r\n\r\nAnarra Alofa is a reflection of my journey — as a mother, a Samoan woman, and a creator — and a celebration of the beauty we carry and share through our culture.", "postal_code": null, "proof_links": null, "shop_handle": "anarra-alofa-est-2020", "contact_name": "Sharon Naseri", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@anarraalofa2020", "facebook": "https://facebook.com/silaumea.ieru", "instagram": "https://instagram.com/anarraalofa2125"}, "state_region": null, "contact_email": "sharonnaseri@gmail.com", "contact_phone": "+64212170344", "owner_user_id": null, "business_hours": "Monday-Friday 9am-5pm", "contact_website": null, "languages_spoken": ["English"], "cultural_identity": "Samoa", "short_description": "Elevate your style with beautifully crafted Sei''s for every occasion at Anarra Alofa.", "subscription_tier": "featured_plus", "stripe_customer_id": null}', '{"id": "6bd8fad1-df64-4c3c-8cd8-7cb63be2926a", "city": "Auckland", "name": "Anarra Alofa Est.2020", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "New Zealand", "user_id": null, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logos/anarraalofa.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banners/Anarra%20Alofa.png", "claimed_at": null, "claimed_by": null, "created_at": "2026-01-06T22:28:48.12743+00:00", "updated_at": "2026-03-03T06:13:06.643013+00:00", "description": "Talofa lava, my name is Sharon, co-founder and owner of Anarra Alofa.\r\nMy creative journey began in 2020, when I first set my heart on making handcrafted board signs. Shortly after, I welcomed my first child — my son — and, like many mothers, I placed that dream on hold. Even so, the desire to create never left me.\r\n\r\nOver time, my inspiration naturally returned through Sei — the floral ear pieces deeply loved and worn by Samoan women. In our culture, Sei are more than adornment; they are expressions of beauty, identity, and pride. The idea of creating them stayed with me, quietly growing until the time felt right.\r\n\r\nAt the beginning of last year, I finally took the step to bring Anarra Alofa to life. Starting small and working with minimal materials, I began handcrafting Sei with love, care, and intention. What started as a simple creative outlet has grown into a heartfelt small business rooted in culture, creativity, and passion.\r\n\r\nAnarra Alofa is a reflection of my journey — as a mother, a Samoan woman, and a creator — and a celebration of the beauty we carry and share through our culture.", "postal_code": null, "proof_links": null, "shop_handle": "anarra-alofa-est-2020", "contact_name": "Sharon Naseri", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@anarraalofa2020", "facebook": "https://facebook.com/silaumea.ieru", "instagram": "https://instagram.com/anarraalofa2125"}, "state_region": null, "contact_email": "sharonnaseri@gmail.com", "contact_phone": "+64212170344", "owner_user_id": null, "business_hours": "Monday-Friday 9am-5pm", "contact_website": null, "languages_spoken": ["English"], "cultural_identity": "Samoa", "short_description": "Elevate your style with beautifully crafted Sei''s for every occasion at Anarra Alofa.", "subscription_tier": "featured_plus", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-03-03 06:13:06.643013+00'),
