	('6aabf4d5-2484-4483-bbee-5884f558e2cb', 'businesses', 'fcb997d1-fb71-4406-b902-cc5ef3208b03', 'UPDATE', '{"id": "fcb997d1-fb71-4406-b902-cc5ef3208b03", "city": "Bundaberg", "name": "Papua New Guinea Bilums and Baskets", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "Australia", "user_id": null, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771898183242.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banners/PNG%20Bilums.png", "claimed_at": null, "claimed_by": null, "created_at": "2025-12-17T06:11:26.868237+00:00", "updated_at": "2026-03-03T05:58:53.043436+00:00", "description": "Papua New Guinea Bilums & Baskets, run by CJ & LJ Mountford and based in Bundaberg, Queensland, is a small family business dedicated to sharing authentic Papua New Guinea arts and crafts with the wider community.\r\n\r\nSpecialising in traditional bilums and handwoven baskets, each piece is created using techniques passed down through generations. Bilums are traditionally crafted by women, woven in a variety of shapes and sizes to serve different purposes — from everyday use to baby carrying. The baskets are traditionally crafted by men, reflecting distinct cultural roles and knowledge systems.\r\n\r\nOnly three provinces in Papua New Guinea continue this specific weaving tradition:\r\n\r\nNorth Solomon (Buka)\r\nSouthern Highlands\r\nEastern Highlands\r\n\r\nThese handcrafted pieces are both functional and meaningful, suitable for home décor, shopping, picnics, and baby carrying — while carrying the stories, skills, and heritage of the communities who make them.\r\n\r\nBy supporting Papua New Guinea Bilums & Baskets, you are helping preserve traditional knowledge and create income opportunities for PNG artisans.", "postal_code": null, "proof_links": null, "shop_handle": "papua-new-guinea-bilums-and-baskets", "contact_name": "Linah Mountford", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/PapuaNewGuineaBilumsAndBasketsCjLjMountford", "instagram": "https://instagram.com/pngbilumsnbaskets"}, "state_region": "Queensland", "contact_email": "Cmford@southernphone.com.au", "contact_phone": "0423 819 378", "owner_user_id": null, "business_hours": "10am to 2pm", "contact_website": null, "languages_spoken": ["Pidgin"], "cultural_identity": "Papua New Guinea", "short_description": "CJ & LJ Mountford", "subscription_tier": "featured_plus", "stripe_customer_id": null}', '{"id": "fcb997d1-fb71-4406-b902-cc5ef3208b03", "city": "Bundaberg", "name": "Papua New Guinea Bilums and Baskets", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "Australia", "user_id": null, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logos/pngbilum.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banners/PNG%20Bilums.png", "claimed_at": null, "claimed_by": null, "created_at": "2025-12-17T06:11:26.868237+00:00", "updated_at": "2026-03-03T06:13:06.643013+00:00", "description": "Papua New Guinea Bilums & Baskets, run by CJ & LJ Mountford and based in Bundaberg, Queensland, is a small family business dedicated to sharing authentic Papua New Guinea arts and crafts with the wider community.\r\n\r\nSpecialising in traditional bilums and handwoven baskets, each piece is created using techniques passed down through generations. Bilums are traditionally crafted by women, woven in a variety of shapes and sizes to serve different purposes — from everyday use to baby carrying. The baskets are traditionally crafted by men, reflecting distinct cultural roles and knowledge systems.\r\n\r\nOnly three provinces in Papua New Guinea continue this specific weaving tradition:\r\n\r\nNorth Solomon (Buka)\r\nSouthern Highlands\r\nEastern Highlands\r\n\r\nThese handcrafted pieces are both functional and meaningful, suitable for home décor, shopping, picnics, and baby carrying — while carrying the stories, skills, and heritage of the communities who make them.\r\n\r\nBy supporting Papua New Guinea Bilums & Baskets, you are helping preserve traditional knowledge and create income opportunities for PNG artisans.", "postal_code": null, "proof_links": null, "shop_handle": "papua-new-guinea-bilums-and-baskets", "contact_name": "Linah Mountford", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/PapuaNewGuineaBilumsAndBasketsCjLjMountford", "instagram": "https://instagram.com/pngbilumsnbaskets"}, "state_region": "Queensland", "contact_email": "Cmford@southernphone.com.au", "contact_phone": "0423 819 378", "owner_user_id": null, "business_hours": "10am to 2pm", "contact_website": null, "languages_spoken": ["Pidgin"], "cultural_identity": "Papua New Guinea", "short_description": "CJ & LJ Mountford", "subscription_tier": "featured_plus", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-03-03 06:13:06.643013+00'),
	('dc6efe27-3292-448d-8d8c-6f038105d396', 'businesses', '3966d793-4307-49e0-891e-5fc34c3a0cd8', 'UPDATE', '{"id": "3966d793-4307-49e0-891e-5fc34c3a0cd8", "city": "Avignon", "name": "SILILO TATTOO", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "France", "user_id": null, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771899176037.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banners/Sililo.png", "claimed_at": null, "claimed_by": null, "created_at": "2025-12-23T08:13:31.132338+00:00", "updated_at": "2026-03-03T05:58:53.043436+00:00", "description": "SILLO TATTOO is a Polynesian tattoo artist whose work is deeply influenced by traditional patterns, structure, and the cultural meaning carried within every line.\r\n\r\nEach tattoo is approached with intention and respect, not simply as a design, but as a personal story expressed through Polynesian-inspired motifs, balance, and flow. From large-scale body pieces to detailed custom work, SILLO TATTOO focuses on clean execution, strong composition, and designs that honour both the wearer and the cultural origins of the art.\r\n\r\nBased in Avignon, France, SILLO TATTOO works by appointment, creating custom tattoos for clients who value authenticity, symbolism, and craftsmanship. Every piece is thoughtfully designed to fit the body naturally, ensuring the tattoo remains timeless, powerful, and meaningful.\r\n\r\nAt SILLO TATTOO, tattooing is more than decoration, it is identity, respect, and storytelling through ink.", "postal_code": null, "proof_links": null, "shop_handle": "sililo-tattoo", "contact_name": "Brice SILILO", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@sililo.tattoo", "facebook": "https://facebook.com/profile.php?id=100077690003413", "linkedin": "https://linkedin.com/brice-sililo-6154b91