	('1d811c28-6b4d-4e51-8d16-2cb7fd5f0b08', 'businesses', '847bde54-f369-40c3-a22b-a4d045850982', 'UPDATE', '{"id": "847bde54-f369-40c3-a22b-a4d045850982", "city": "Auckland", "name": "Paulo Mauia", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "New Zealand", "user_id": null, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logo_1771898295405.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banners/Paulo.png", "claimed_at": null, "claimed_by": null, "created_at": "2025-12-17T05:28:29.873448+00:00", "updated_at": "2026-03-03T05:58:53.043436+00:00", "description": "Arts Finest Tattoo Shop, owned and led by Paulo Mauia, is a respected Samoan tattoo studio known for delivering finely detailed, culturally grounded tattoo work with skill, care, and integrity.\r\n\r\nSpecialising in Samoan and Polynesian tattoo designs, Paulo brings years of experience and a deep understanding of traditional patterns, symbolism, and placement. Each piece is carefully crafted to reflect identity, story, and cultural pride — whether through bold traditional work, custom designs, or finely executed modern pieces.\r\n\r\nArts Finest Tattoo Shop is more than a place to get tattooed; it is a space where art, heritage, and craftsmanship come together. With a strong reputation across Samoa and New Zealand — and expanding to Australia from January 2026 — the studio continues to serve clients who value authenticity, cultural respect, and high-quality tattooing.", "postal_code": null, "proof_links": null, "shop_handle": "paulo-mauia", "contact_name": "Paulo Mauia", "created_date": "2025-12-17", "social_links": {"tiktok": "https://tiktok.com/@paulomauia", "facebook": "https://facebook.com/profile.php?id=100060918442844", "instagram": "https://instagram.com/paulomauia_tattoo"}, "state_region": null, "contact_email": "paulomauia3@gmail.com", "contact_phone": null, "owner_user_id": null, "business_hours": "24hrs", "contact_website": null, "languages_spoken": ["English"], "cultural_identity": "Samoa", "short_description": "Arts Finest", "subscription_tier": "featured_plus", "stripe_customer_id": null}', '{"id": "847bde54-f369-40c3-a22b-a4d045850982", "city": "Auckland", "name": "Paulo Mauia", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "New Zealand", "user_id": null, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logos/paulo.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banners/Paulo.png", "claimed_at": null, "claimed_by": null, "created_at": "2025-12-17T05:28:29.873448+00:00", "updated_at": "2026-03-03T06:13:06.643013+00:00", "description": "Arts Finest Tattoo Shop, owned and led by Paulo Mauia, is a respected Samoan tattoo studio known for delivering finely detailed, culturally grounded tattoo work with skill, care, and integrity.\r\n\r\nSpecialising in Samoan and Polynesian tattoo designs, Paulo brings years of experience and a deep understanding of traditional patterns, symbolism, and placement. Each piece is carefully crafted to reflect identity, story, and cultural pride — whether through bold traditional work, custom designs, or finely executed modern pieces.\r\n\r\nArts Finest Tattoo Shop is more than a place to get tattooed; it is a space where art, heritage, and craftsmanship come together. With a strong reputation across Samoa and New Zealand — and expanding to Australia from January 2026 — the studio continues to serve clients who value authenticity, cultural respect, and high-quality tattooing.", "postal_code": null, "proof_links": null, "shop_handle": "paulo-mauia", "contact_name": "Paulo Mauia", "created_date": "2025-12-17", "social_links": {"tiktok": "https://tiktok.com/@paulomauia", "f