	('f2f57309-0b78-4bda-9ac1-147c9e1389d4', 'businesses', '8e3c51fd-f7f9-4873-a91e-5edafb7b10f0', 'UPDATE', '{"id": "8e3c51fd-f7f9-4873-a91e-5edafb7b10f0", "city": "Auckland", "name": "Inailau", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "New Zealand", "user_id": null, "industry": "Consulting & Professional Services", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logos/inailau.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banners/Inailau.png", "claimed_at": null, "claimed_by": null, "created_at": "2025-12-14T20:05:18.903507+00:00", "updated_at": "2026-03-03T06:09:11.046545+00:00", "description": "Inailau Business Women''s Network is a community-driven platform dedicated to uplifting, connecting, and empowering Pacific women in business.\r\n\r\nRooted in collaboration and collective growth, Inailau creates safe, supportive spaces where women can share knowledge, build confidence, and grow both personally and professionally. Through networking events, workshops, mentoring sessions, and global connections, Inailau supports Pacific women entrepreneurs at every stage of their journey — from early ideas to established businesses.\r\n\r\nThe network champions visibility, leadership, and economic empowerment, recognising that when Pacific women rise, families, communities, and future generations rise with them.\r\n\r\nMore than a business network, Inailau is a movement grounded in culture, connection, and purpose — bringing Pacific women together to reflect, realign, and rise together.", "postal_code": null, "proof_links": null, "shop_handle": "inailau", "contact_name": "Jackie Curry", "created_date": "2025-12-14", "social_links": {"facebook": "https://facebook.com/www.facebook.com/profile.php?id=61552017680960", "instagram": "https://instagram.com/inailaubusinessnetwork"}, "state_region": "North Island", "contact_em