	('ee3cabf5-9694-4e0d-8191-f97f255c1bd5', 'businesses', '20b54ac1-50ae-4475-89ef-b50569505408', 'UPDATE', '{"id": "20b54ac1-50ae-4475-89ef-b50569505408", "city": "New Zealand", "name": "M.Steven", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "New Zealand", "user_id": null, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logos/msteven.jpeg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banners/M%20Steven.png", "claimed_at": null, "claimed_by": null, "created_at": "2025-12-14T08:18:01.195186+00:00", "updated_at": "2026-03-03T06:13:06.643013+00:00", "description": "This artist brings worlds to life through intricate, hand-drawn line work, creating pieces that feel both deeply personal and endlessly expansive. Every artwork is built stroke by stroke — layering symbols, creatures, and flowing forms that invite the viewer to slow down and discover something new each time they look.\r\n\r\nInspired by storytelling, movement, and the complexity of lived experience, their work blends fine detail with raw expression. Using acrylic paint and acrylic pen alongside traditional drawing tools, each piece carries its own rhythm — reflecting patience, discipline, and a deep respect for the creative process.\r\n\r\nBeyond visual art, this same care and creativity extend into handcrafted desserts and custom celebration cakes, including wedding and birthday designs. Whether expressed on paper, canvas, or through edible art, the artist approaches every creation with the same intention: balance, beauty, and meaning.\r\n\r\nThese works are never rushed — they are thoughtfully crafted, allowing ideas to unfold naturally. The result is a body of work that feels alive and grounded, celebrating creativity as a form of meditation, expression, and connection across many mediums.", "postal_code": null, "proof_links"