	('2fcdd988-6850-4731-90be-5a89986a3147', 'businesses', '74845da6-e0b1-421c-8181-7e6753c152f9', 'UPDATE', '{"id": "74845da6-e0b1-421c-8181-7e6753c152f9", "city": "Auckland", "name": "Zeena Khan Coaching", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "New Zealand", "user_id": null, "industry": "Consulting & Professional Services", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logos/zeena.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banners/Zeena.png", "claimed_at": null, "claimed_by": null, "created_at": "2026-01-17T23:14:01.458139+00:00", "updated_at": "2026-03-03T06:20:44.136798+00:00", "description": "Zeena Khan Coaching stands at the intersection of modern leadership and cultural wisdom, offering a nuanced approach to professional development.\r\n\r\nWith a focus on empowering leaders to build agile and confident teams, Zeena''s coaching practice is particularly attuned to the complexities of the AI era. Her methodology is grounded in a strengths-based framework that encourages individuals to harness their unique capabilities while remaining culturally aware.\r\n\r\nZeena Khan brings a wealth of experience to her coaching engagements, drawing from her own heritage and understanding of diverse cultural perspectives. This blend of insight ensures that her clients are not only prepared to meet the challenges of today''s fast-paced business environment but are also equipped to lead with empathy and respect for the diverse backgrounds within their teams.\r\n\r\nAt the core of Zeena''s practice is the belief that true leadership is about fostering an environment where all team members can thrive. By emphasizing cultural awareness and personal strengths, she helps leaders create workplaces that are both innovative and inclusive. Zeena Khan Coaching is dedicated to nurturing leadership that is as dynamic as the world around us, with a commitment to guiding professionals towards their highest potential.", "postal_code": null, "proof_links": null, "shop_handle": "zeena-khan-coaching", "contact_name": "Zeena Khan", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@ZeenaKhanCoaching", "youtube": "https://youtube.com/@Adaptability Advantage", "instagram": "https://instagram.com/ZeenaKhanCoaching"}, "state_region": "North Island", "contact_email": "hello@zeenakhan.com", "contact_phone": "021364881", "owner_user_id": null, "business_hours": null, "contact_website": "https://www.zeenakhan.com", "languages_spoken": ["Hindi", "English"], "cultural_identity": "Fiji, China, India", "homepage_featured": false, "short_description": "Empowering leaders to foster agile, confident teams in the AI era.", "subscription_tier": "featured_plus", "stripe_customer_id": null}', '{"id": "74845da6-e0b1-421c-8181-7e6753c152f9", "city": "Auckland", "name": "Zeena Khan Coaching", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "New Zealand", "user_id": null, "industry": "Consulting & Professional Services", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logos/zeena.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banners/Zeena.png", "claimed_at": null, "claimed_by": null, "created_at": "2026-01-17T23:14:01.458139+00:00", "updated_at": "2026-03-05T02:32:21.595222+00:00", "description": "Zeena Khan Coaching stands at the intersection of modern leadership and cultural wisdom, offering a nuanced approach to professional development.\r\n\r\nWith a focus on empowering leaders to build agile and confident teams, Zeena''s coaching practice is particularly attuned to the complexities of the AI era. Her methodology is grounded in a strengths-based framework that encourages individuals to harness their unique capabilities while remaining culturally aware.\r\n\r\nZeena Khan brings a wealth of experience to her coaching engagements, drawing from her own heritage and understanding of diverse cultural perspectives. This blend of insight ensures that her clients are not only prepared to meet the challenges of today''s fast-paced business environment but are also equipped to lead with empathy and respect for the diverse backgrounds within their teams.\r\n\r\nAt the core of Zeena''s practice is the belief that true leadership is about fostering an environment where all team members can thrive. By emphasizing cultural awareness and personal strengths, she helps leaders create workplaces that are both innovative and inclusive. Zeena Khan Coaching is dedicated to nurturing leadership that is as dynamic as the world around us, with a commitment to guiding professionals towards their highest potential.", "postal_code": null, "proof_links": null, "shop_handle": "zeena-khan-coaching", "contact_name": "Zeena Khan", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@ZeenaKhanCoaching", "youtube": "https://youtube.com/@Adaptability Advantage", "instagram": "https://instagram.com/ZeenaKhanCoaching"}, "state_region": "North Island", "contact_email": "hello@zeenakhan.com", "contact_phone": "021364881", "owner_user_id": null, "business_hours": null, "contact_website": "https://www.zeenakhan.com", "languages_spoken": ["Hindi", "English"], "cultural_identity": "Fiji, China, India", "homepage_featured": true, "short_description": "Empowering leaders to foster agile, confident teams in the AI era.", "subscription_tier": "verified", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-03-05 02:32:21.595222+00'),
	('fb66b54f-fef9-4812-8ddc-f83870b59cb2', 'businesses', 'c9fc68e6-da63-4def-9d0b-13991ddc3926', 'UPDATE', '{"id": "c9fc68e6-da63-4def-9d0b-13991ddc3926", "city": "Auckland", "name": "Te Mauri o te Makawe", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "New Zealand", "user_id": null, "industry": "Health & Wellness", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logos/temauri.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banners/Te%20Mauri.png", "claimed_at": null, "claimed_by": null, "created_at": "2025-12-01T08:40:49.119488+00:00", "updated_at": "2026-03-03T06:13:06.643013+00:00", "description": "Nuku te manaaki, nuku te manaaki, ka ora ai te iwi.\r\nWith your support and my support, our community will thrive.\r\n\r\nMy name is Iesha Te-Iho. I am a qualified barber, creative, and proud Waiuku local. My journey here was not a straight line — but every challenge sharpened my purpose and showed me that barbering could be more than a trade. It could be a doorway to healing.\r\n\r\nFrom that understanding, Te Mauri o te Makawe: The Koha Manawa was born.\r\n\r\nThis kaupapa delivers professional grooming and braiding through a mobile service, reaching people and places often overlooked — hospices, spinal units, rehabilitation centres, and rural communities where transport and access are barriers. But this work is about far more than hair.\r\n\r\nThrough whakahoki te tapu, hair is treated with care and respectfully returned to Papatūānuku using traditional tikanga — uku (clay), harakeke (flax), and korowai — protecting the mana of our whānau. Alongside this, kōrero is shared and recorded, preserving the voices, stories, and heartbeat of the community.\r\n\r\nThis kaupapa began with one chair and one set of tools, but the vision is a Waka Wānanga — a collective of skilled creatives travelling across Aotearoa and beyond, delivering workshops, teaching tikanga, uplifting hauora, and restoring identity through creativity.\r\n\r\nAt its heart, this is about legacy. About building something that lasts — not just 100 years, but for generations — by caring for people, culture, and community, together.", "postal_code": null, "proof_links": null, "shop_handle": "te-mauri-o-te-makawe", "contact_name": "Iesha Rawinia", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/TeKohaManawa", "instagram": "https://instagram.com/tekohamanawa"}, "state_region": "Auckland", "contact_email": "hairwithesha@gmail.com", "contact_phone": "02102965229", "owner_user_id": null, "business_hours": null, "contact_website": "https://msha.ke/beauty_withinyou", "languages_spoken": ["English"], "cultural_identity": "Cook Islands, New Zealand Māori", "homepage_featured": false, "short_description": "Any Style. Any Hair. Any Where.", "subscription_tier": "featured_plus", "stripe_customer_id": null}', '{"id": "c9fc68e6-da63-4def-9d0b-13991ddc3926", "city": "Auckland", "name": "Te Mauri o te Makawe", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "New Zealand", "user_id": null, "industry": "Health & Wellness", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logos/temauri.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banners/Te%20Mauri.png", "claimed_at": null, "claimed_by": null, "created_at": "2025-12-01T08:40:49.119488+00:00", "updated_at": "2026-03-05T02:32:21.595222+00:00", "description": "Nuku te manaaki, nuku te manaaki, ka ora ai te iwi.\r\nWith your support and my support, our community will thrive.\r\n\r\nMy name is Iesha Te-Iho. I am a qualified barber, creative, and proud Waiuku local. My journey here was not a straight line — but every challenge sharpened my purpose and showed me that barbering could be more than a trade. It could be a doorway to healing.\r\n\r\nFrom that understanding, Te Mauri o te Makawe: The Koha Manawa was born.\r\n\r\nThis kaupapa delivers professional grooming and braiding through a mobile service, reaching people and places often overlooked — hospices, spinal units, rehabilitation centres, and rural communities where transport and access are barriers. But this work is about far more than hair.\r\n\r\nThrough whakahoki te tapu, hair is treated with care and respectfully returned to Papatūānuku using traditional tikanga — uku (clay), harakeke (flax), and korowai — protecting the mana of our whānau. Alongside this, kōrero is shared and recorded, preserving the voices, stories, and heartbeat of the community.\r\n\r\nThis kaupapa began with one chair and one set of tools, but the vision is a Waka Wānanga — a collective of skilled creatives travelling across Aotearoa and beyond, delivering workshops, teaching tikanga, uplifting hauora, and restoring identity through creativity.\r\n\r\nAt its heart, this is about legacy. About building something that lasts — not just 100 years, but for generations — by caring for people, culture, and community, together.", "postal_code": null, "proof_links": null, "shop_handle": "te-mauri-o-te-makawe", "contact_name": "Iesha Rawinia", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/TeKohaManawa", "instagram": "https://instagram.com/tekohamanawa"}, "state_region": "Auckland", "contact_email": "hairwithesha@gmail.com", "contact_phone": "02102965229", "owner_user_id": null, "business_hours": null, "contact_website": "https://msha.ke/beauty_withinyou", "languages_spoken": ["English"], "cultural_identity": "Cook Islands, New Zealand Māori", "homepage_featured": true, "short_description": "Any Style. Any Hair. Any Where.", "subscription_tier": "verified", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-03-05 02:32:21.595222+00'),
	('bd34d221-1434-438f-8f06-bd187b9765da', 'businesses', '525e84f2-66d3-4a1b-a896-dd64d01ec033', 'UPDATE', '{"id": "525e84f2-66d3-4a1b-a896-dd64d01ec033", "city": "New Zealand", "name": "Tuhono Design", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "New Zealand", "user_id": null, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logos/tuhono.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banners/Tuhono.png", "claimed_at": null, "claimed_by": null, "created_at": "2025-12-12T18:28:30.64805+00:00", "updated_at": "2026-03-03T06:20:44.136798+00:00", "description": "Tuhono Design was created by Jay and Sarah, a proud Maori whanau dedicated to revitalising te reo Maori in everyday spaces. Inspired by their own journeys of reconnecting with their heritage, they design bilingual planners, calendars, prints, and educational resources that make Maori language and culture accessible, beautiful, and part of daily life. Their kaupapa is built on whanaungatanga, kotahitanga, and uplifting the next generation so they can grow up confident in their identity. Through thoughtfully crafted products rooted in meaning and connection, Tuhono Design invites whanau everywhere to learn, speak, and live te reo Maori with pride.", "postal_code": null, "proof_links": null, "shop_handle": "tuhono-design", "contact_name": "Sarah", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@tuhonodesign", "facebook": "https://facebook.com/Tuhonodesign"}, "state_region": "New Zealand", "contact_email": "kiaora@tuhonodesign.com", "contact_phone": null, "owner_user_id": null, "business_hours": null, "contact_website": "https://tuhonodesign.com", "languages_spoken": ["Te Reo Māori", "English"], "cultural_identity": "New Zealand Māori", "homepage_featured": false, "short_description": "Bilingual Maori Resources to Inspire, Learn & Connect", "subscription_tier": "featured_plus", "stripe_customer_id": null}', '{"id": "525e84f2-66d3-4a1b-a896-dd64d01ec033", "city": "New Zealand", "name": "Tuhono Design", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "New Zealand", "user_id": null, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logos/tuhono.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banners/Tuhono.png", "claimed_at": null, "claimed_by": null, "created_at": "2025-12-12T18:28:30.64805+00:00", "updated_at": "2026-03-05T02:32:21.595222+00:00", "description": "Tuhono Design was created by Jay and Sarah, a proud Maori whanau dedicated to revitalising te reo Maori in everyday spaces. Inspired by their own journeys of reconnecting with their heritage, they design bilingual planners, calendars, prints, and educational resources that make Maori language and culture accessible, beautiful, and part of daily life. Their kaupapa is built on whanaungatanga, kotahitanga, and uplifting the next generation so they can grow up confident in their identity. Through thoughtfully crafted products rooted in meaning and connection, Tuhono Design invites whanau everywhere to learn, speak, and live te reo Maori with pride.", "postal_code": null, "proof_links": null, "shop_handle": "tuhono-design", "contact_name": "Sarah", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@tuhonodesign", "facebook": "https://facebook.com/Tuhonodesign"}, "state_region": "New Zealand", "contact_email": "kiaora@tuhonodesign.com", "contact_phone": null, "owner_user_id": null, "business_hours": null, "contact_website": "https://tuhonodesign.com", "languages_spoken": ["Te Reo Māori", "English"], "cultural_identity": "New Zealand Māori", "homepage_featured": true, "short_description": "Bilingual Maori Resou