	('85ffdec8-7df9-4ad2-99f1-150aba0b8f35', 'businesses', 'fcb997d1-fb71-4406-b902-cc5ef3208b03', 'UPDATE', '{"id": "fcb997d1-fb71-4406-b902-cc5ef3208b03", "city": "Bundaberg", "name": "Papua New Guinea Bilums and Baskets", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "Australia", "user_id": null, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logos/pngbilum.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banners/PNG%20Bilums.png", "claimed_at": null, "claimed_by": null, "created_at": "2025-12-17T06:11:26.868237+00:00", "updated_at": "2026-03-05T02:32:21.595222+00:00", "description": "Papua New Guinea Bilums & Baskets, run by CJ & LJ Mountford and based in Bundaberg, Queensland, is a small family business dedicated to sharing authentic Papua New Guinea arts and crafts with the wider community.\r\n\r\nSpecialising in traditional bilums and handwoven baskets, each piece is created using techniques passed down through generations. Bilums are traditionally crafted by women, woven in a variety of shapes and sizes to serve different purposes — from everyday use to baby carrying. The baskets are traditionally crafted by men, reflecting distinct cultural roles and knowledge systems.\r\n\r\nOnly three provinces in Papua New Guinea continue this specific weaving tradition:\r\n\r\nNorth Solomon (Buka)\r\nSouthern Highlands\r\nEastern Highlands\r\n\r\nThese handcrafted pieces are both functional and meaningful, suitable for home décor, shopping, picnics, and baby carrying — while carrying the stories, skills, and heritage of the communities who make them.\r\n\r\nBy supporting Papua New Guinea Bilums & Baskets, you are helping preserve traditional knowledge and create income opportunities for PNG artisans.", "postal_code": null, "proof_links": null, "shop_handle": "papua-new-guinea-bilums-and-baskets", "contact_name": "Linah Mountford", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/PapuaNewGuineaBilumsAndBasketsCjLjMountford", "instagram": "https://instagram.com/pngbilumsnbaskets"}, "state_region": "Queensland", "contact_email": "Cmford@southernphone.com.au", "contact_phone": "0423 819 378", "owner_user_id": null, "business_hours": "10am to 2pm", "contact_website": null, "visibility_tier": "none", "languages_spoken": ["Pidgin", "English"], "cultural_identity": "Papua New Guinea", "homepage_featured": true, "short_description": "CJ & LJ Mountford", "subscription_tier": "verified", "stripe_customer_id": null}', '{"id": "fcb997d1-fb71-4406-b902-cc5ef3208b03", "city": "Bundaberg", "name": "Papua New Guinea Bilums and Baskets", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "Australia", "user_id": null, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logos/pngbilum.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banners/PNG%20Bilums.png", "claimed_at": null, "claimed_by": null, "created_at": "2025-12-17T06:11:26.868237+00:00", "updated_at": "2026-03-05T02:35:18.829614+00:00", "description": "Papua New Guinea Bilums & Baskets, run by CJ & LJ Mountford and based in Bundaberg, Queensland, is a small family business dedicated to sharing authentic Papua New Guinea arts and crafts with the wider community.\r\n\r\nSpecialising in traditional bilums and handwoven baskets, each piece is created using techniques passed down through generations. Bilums are traditionally crafted by women, woven in a variety of shapes and sizes to serve different purposes — from everyday use to baby carrying. The baskets are traditionally crafted by men, reflecting distinct cultural roles and knowledge systems.\r\n\r\nOnly three provinces in Papua New Guinea continue this specific weaving tradition:\r\n\r\nNorth Solomon (Buka)\r\nSouthern Highlands\r\nEastern Highlands\r\n\r\nThese handcrafted pieces are both functional and meaningful, suitable for home décor, shopping, picnics, and baby carrying — while carrying the stories, skills, and heritage of the communities who make them.\r\n\r\nBy supporting Papua New Guinea Bilums & Baskets, you are helping preserve traditional knowledge and create income opportunities for PNG artisans.", "postal_code": null, "proof_links": null, "shop_handle": "papua-new-guinea-bilums-and-baskets", "contact_name": "Linah Mountford", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/PapuaNewGuineaBilumsAndBasketsCjLjMountford", "instagram": "https://instagram.com/pngbilumsnbaskets"}, "state_region": "Queensland", "contact_email": "Cmford@southernphone.com.au", "contact_phone": "0423 819 378", "owner_user_id": null, "business_hours": "10am to 2pm", "contact_website": null, "visibility_tier": "homepage", "languages_spoken": ["Pidgin", "English"], "cultural_identity": "Papua New Guinea", "homepage_featured": true, "short_description": "CJ & LJ Mountford", "subscription_tier": "verified", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-03-05 02:35:18.829614+00'),
	('baccb92c-0566-4c34-9583-b1fa4f802ede', 'businesses', 'a1fb7177-900d-41f8-b635-c155a16c2e43', 'UPDATE', '{"id": "a1fb7177-900d-41f8-b635-c155a16c2e43", "city": "Raiatea", "name": "L''ame Du Pareu by Vai''ohani", "status": "active", "suburb": "Tumaraa", "address": "PK30.9 C/mer - Motu Nuutere", "claimed": false, "country": "French Polynesia", "user_id": null, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logos/lamedupareu.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banners/Lame%20Du%20Pareu.png", "claimed_at": null, "claimed_by": null, "created_at": "2025-11-27T07:23:16.513022+00:00", "updated_at": "2026-03-05T02:32:21.595222+00:00", "description": "Discover the magic of pareo art with Vaihere in beautiful Raiatea. In this hands-on workshop, you''ll learn the traditional craft of painting your own pareo, using colours and patterns that reflect your personal story.\r\n\r\nChoose from three experience levels:\r\n🎨 Child''s Pareo (3 hrs) — A fun, creative session perfect for young artists.\r\n🎨 Guided Design (3 hrs) — Vaihere sketches your chosen idea, and you bring it to life with paint.\r\n🎨 Create Your Own (4 hrs) — Design and paint your own pareo from scratch.\r\n\r\nAll materials are included — just bring yourself and your creativity, and leave with a beautiful handmade pareo to take home. A meaningful and memorable activity for both locals and visitors.\r\n\r\nDécouvrez la magie de l''art du pareo avec Vaihere sur la magnifique île de Raiatea. Lors de cet atelier créatif et immersif, vous apprendrez à peindre votre propre pareo en utilisant des couleurs et des motifs qui racontent votre histoire personnelle.\r\n\r\nChoisissez parmi trois niveaux d''expérience :\r\n🎨 Pareo Enfant (3h) — Une activité amusante et créative, idéale pour les jeunes artistes.\r\n🎨 Design Guidé (3h) — Vaihere dessine le motif de votre choix, et vous lui donnez vie avec la peinture.\r\n🎨 Créez Votre Propre Motif (4h) — Concevez et peignez votre pareo de A à Z.\r\n\r\nTout le matériel est fourni — il vous suffit d''apporter votre créativité et vous repartirez avec un pareo unique, réalisé de vos propres mains. Une expérience", "postal_code": null, "proof_links": null, "shop_handle": "l-ame-du-pareu-by-vai-ohani", "contact_name": "Vaihere Pito", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@vaiohani", "facebook": "https://facebook.com/100046471642888", "instagram": "https://instagram.com/pareubyvaiohani.00"}, "state_region": "Ils Sous Le Vent", "contact_email": "lornapitovai@gmail.com", "contact_phone": "+689 87376668", "owner_user_id": null, "business_hours": null, "contact_website": null, "visibility_tier": "none", "languages_spoken": ["English", "French", "Tahitian"], "cultural_identity": "French Polynesia", "homepage_featured": true, "short_description": "A hands-on pareu painting experience in Raiatea", "subscription_tier": "verified", "stripe_customer_id": null}', '{"id": "a1fb7177-900d-41f8-b635-c155a16c2e43", "city": "Raiatea", "name": "L''ame Du Pareu by Vai''ohani", "status": "active", "suburb": "Tumaraa", "address": "PK30.9 C/mer - Motu Nuutere", "claimed": false, "country": "French Polynesia", "user_id": null, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logos/lamedupareu.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banners/Lame%20Du%20Pareu.png", "claimed_at": null, "claimed_by": null, "created_at": "2025-11-27T07:23:16.513022+00:00", "updated_at": "2026-03-05T02:35:18.829614+00:00", "description": "Discover the magic of pareo art with Vaihere in beautiful Raiatea. In this hands-on workshop, you''ll learn the traditional craft of painting your own pareo, using colours and patterns that reflect your per