	('0d9da520-801c-457a-9641-891e40d257cf', 'businesses', '70ea5ff4-fe63-4d3e-b526-cfa3ec0dc95a', 'UPDATE', '{"id": "70ea5ff4-fe63-4d3e-b526-cfa3ec0dc95a", "city": "Draper", "name": "Warrior Lines Tattoo", "status": "active", "suburb": null, "address": "12233 900 E", "claimed": false, "country": "United States", "user_id": null, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logos/warriorlines.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banners/Warrior%20Lines.png", "claimed_at": null, "claimed_by": null, "created_at": "2025-12-17T04:52:57.713415+00:00", "updated_at": "2026-03-05T02:32:21.595222+00:00", "description": "Warrior Lines Tattoo is a veteran-owned tattoo studio built on discipline, respect, and the belief that great art comes from a strong, healthy environment.\r\n\r\nWe specialise in bold black and grey work, custom designs, and Polynesian-inspired tattoos that carry meaning, structure, and story.\r\n\r\nThis is a no-nonsense shop for artists and clients who value integrity, craftsmanship, and authenticity. We reject ego, drama, and gatekeeping, and instead foster a space where artists are encouraged to grow, sharpen their skills, and take pride in their work — without judgment or pressure.\r\n\r\nAt Warrior Lines Tattoo, tattooing is more than ink. It''s commitment. It''s brotherhood. It''s honouring the past while building something stronger for the future — one line at a time.", "postal_code": null, "proof_links": null, "shop_handle": "warrior-lines-tattoo", "contact_name": "Hans Bennion", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@tribal_touch", "instagram": "https://instagram.com/tribaltouchdesigns"}, "state_region": null, "contact_email": "hans@warriorlines.com", "contact_phone": "4843797885", "owner_user_id": null, "business_hours": "By Appointment Only", "contact