	('0c1ffddb-4c91-47c2-a432-ae8dd511d300', 'businesses', '669c26b2-ceec-498e-9e38-17329d6b05ec', 'UPDATE', '{"id": "669c26b2-ceec-498e-9e38-17329d6b05ec", "city": "Auckland", "name": "Oceanique Solutions", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "New Zealand", "user_id": null, "industry": "Travel & Tourism", "logo_url": null, "verified": false, "banner_url": null, "claimed_at": null, "claimed_by": null, "created_at": "2025-11-24T09:10:17.344881+00:00", "updated_at": "2026-03-05T02:32:21.595222+00:00", "description": "Oceanique DMC & Consulting:\r\nYour Premier Destination Management (DMC) and tailored business consultancy. We offer unmatched expertise, seamless event planning and execution. With a deep insight into local culture and attention to detail, we guarantee a spectacular experience. Let us handle the details so you can immerse yourself in the adventure.\r\n\r\nChoose Oceanique Solutions for an experience as smooth as the sound of waves lapping the shore, the touch of gentle breeze, the sight of vibrant sunset, the scent of fresh rain, and the taste of a perfectly crafted meal.\r\n\r\nOceanique Travel:\r\nAs seasoned travel professionals, Oceanique - is your one stop travel shop. From island retreats to cultural experiences, we ensure your travels are unforgettable, allowing you to relish every sun-kissed moment.\r\n\r\nOceanique Education:\r\nOur education services forge strong partnerships with top educational institutions, immigration agent, and schools in New Zealand. We are a partnered Tahitian International Education Agency and engage as a Learning & Development Contractor. Our mission is to offer enriching educational experiences that connect cultures and unlock global opportunities.\r\n\r\nJoin us, and let''s embark on a new learning adventure together.", "postal_code": null, "proof_links": null, "shop_handle": "oceanique-solutions", "contact_name": "Daniel Maine", "created_date": "2026-02-26", "social_links":