ain", "facebook": "https://facebook.com/pacific.stain", "instagram": "https://instagram.com/pacificstain_official"}, "state_region": "Florida", "contact_email": "pacificstain@aol.com", "contact_phone": null, "owner_user_id": null, "business_hours": null, "contact_website": null, "visibility_tier": "homepage", "languages_spoken": ["English"], "cultural_identity": "Samoa", "homepage_featured": true, "short_description": "Carving the Spirit of Samoa", "subscription_tier": "verified", "stripe_customer_id": null}', NULL, NULL, NULL, '2026-03-05 02:35:18.829614+00'),
	('66c670bd-9b20-424a-bad8-6f9efd4ca54d', 'businesses', '1bebde9a-bd2f-4c22-a522-228fbef28880', 'UPDATE', '{"id": "1bebde9a-bd2f-4c22-a522-228fbef28880", "city": "Port Moresby", "name": "Pacificana", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "Papua New Guinea", "user_id": null, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logos/pacificana.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banners/Pacificana.jpg", "claimed_at": null, "claimed_by": null, "created_at": "2025-12-13T02:00:27.00608+00:00", "updated_at": "2026-03-05T02:32:21.595222+00:00", "description": "Pacificana is a proudly Papua New Guinea–owned creative studio bringing the vibrant spirit of the Pacific to life through handcrafted floral art. Every piece is inspired by the colours of our islands, the strength of our women, and the traditions passed down through generations.\r\n\r\nEach handmade bloom is carefully shaped, painted, and detailed with love — transforming iconic Pacific flowers into stunning wearable art for everyday joy, cultural events, weddings, and island celebrations.\r\n\r\nPacificana is more than an accessories brand — it is a celebration of identity. A way for our people to express who we are, wherever we are in the world. Bold, colourful, authentic, and proudly PNG.\r\n\r\nFrom bright hibiscus and frangipani to custom colourways, every design reflects the warmth, resilience, and creativity of our Pacific community.\r\n\r\nWear your culture. Celebrate your roots. Bloom boldly with Pacificana.", "postal_code": null, "proof_links": null, "shop_handle": "pacificana", "contact_name": "Pacificana", "created_date": "2026-02-26", "social_links": {"facebook": "https://facebook.com/pacificana.pg"}, "state_region": null, "contact_email": "pacificmarketltd@gmail.com", "contact_phone": "+675 7344 5243", "ow