	('a8a820d0-d82f-4839-b51c-d5e7f7ec0eb9', 'businesses', '525e84f2-66d3-4a1b-a896-dd64d01ec033', 'UPDATE', '{"id": "525e84f2-66d3-4a1b-a896-dd64d01ec033", "city": "New Zealand", "name": "Tuhono Design", "status": "active", "suburb": null, "address": null, "claimed": false, "country": "New Zealand", "user_id": null, "industry": "Arts & Culture", "logo_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/logos/tuhono.jpg", "verified": false, "banner_url": "https://mnmisjprswpuvcojnbip.supabase.co/storage/v1/object/public/admin-listings/banners/Tuhono.png", "claimed_at": null, "claimed_by": null, "created_at": "2025-12-12T18:28:30.64805+00:00", "updated_at": "2026-03-05T02:32:21.595222+00:00", "description": "Tuhono Design was created by Jay and Sarah, a proud Maori whanau dedicated to revitalising te reo Maori in everyday spaces. Inspired by their own journeys of reconnecting with their heritage, they design bilingual planners, calendars, prints, and educational resources that make Maori language and culture accessible, beautiful, and part of daily life. Their kaupapa is built on whanaungatanga, kotahitanga, and uplifting the next generation so they can grow up confident in their identity. Through thoughtfully crafted products rooted in meaning and connection, Tuhono Design invites whanau everywhere to learn, speak, and live te reo Maori with pride.", "postal_code": null, "proof_links": null, "shop_handle": "tuhono-design", "contact_name": "Sarah", "created_date": "2026-02-26", "social_links": {"tiktok": "https://tiktok.com/@tuhonodesign", "facebook": "https://facebook.com/Tuhonodesign"}, "state_region": "New Zealand", "contact_email": "kiaora@tuhonodesign.com", "contact_phone": null, "owner_user_id": null, "business_hours": null, "contact_website": "https://tuhonodesign.com", "visibility_tier": "none", "languages_spoken": ["Te Reo Māori", "English"], "cultural_identity": "New Zealand Māori", "homepage_featured": true, "short_descript